def _check_dependencies():
    """Check for required packages and offer to install missing ones."""
    required = {
        'numpy': 'numpy',
        'torch': 'torch',
        'transformers': 'transformers',
        'sentence_transformers': 'sentence-transformers',
        'huggingface_hub': 'huggingface-hub',
        'reportlab': 'reportlab',
        'pygments': 'pygments',
        'rerun': 'rerun-sdk',
        'mcp': 'mcp[cli]',
    }
    
    # Only check packages we might actually use
    optional = {'reportlab', 'pygments', 'rerun', 'mcp'}  # These have fallbacks
    
    missing = []
    missing_optional = []
    
    for module, package in required.items():
        try:
            __import__(module)
        except ImportError:
            if module in optional:
                missing_optional.append(package)
            else:
                missing.append(package)
    
    if not missing and not missing_optional:
        return True
    
    # Show what's missing
    print("\n" + "=" * 60)
    print("🔮 GLASS BOX AI - Dependency Check")
    print("=" * 60)
    
    if missing:
        print(f"\n❌ Required packages missing: {', '.join(missing)}")
    if missing_optional:
        print(f"\n⚠️  Optional packages missing: {', '.join(missing_optional)}")
        print("   (PDF export, visualization features may be limited)")
    
    all_missing = missing + missing_optional
    
    print(f"\n📦 Install {len(all_missing)} package(s)?")
    print(f"   pip install {' '.join(all_missing)}")
    
    try:
        response = input("\n   Install now? [Y/n]: ").strip().lower()
    except (EOFError, KeyboardInterrupt):
        response = 'n'
    
    if response in ('', 'y', 'yes'):
        import subprocess
        print("\n🔧 Installing...")
        for pkg in all_missing:
            print(f"   → {pkg}")
            result = subprocess.run(
                [sys.executable, '-m', 'pip', 'install', '-q', pkg],
                capture_output=True, text=True
            )
            if result.returncode != 0:
                print(f"   ⚠️  Failed: {pkg}")
        print("\n✅ Done! Restarting capsule...\n")
        # Re-exec to pick up new packages
        import os
        os.execv(sys.executable, [sys.executable] + sys.argv)
    else:
        if missing:
            print("\n⚠️  Missing required packages - some features may fail.")
        return len(missing) == 0  # Return True if only optionals missing

# Run check at import time (only in __main__)
if __name__ == "__main__":
    _check_dependencies()


