_DREAMERV3_BUNDLE = """"""

# Extract dreamerv3 to temp directory on module load
import tempfile
import time
import atexit
import shutil
import collections
from dataclasses import dataclass
_DREAMERV3_PATH = None
_DREAMERV3_EXTRACTED = False

def _extract_dreamerv3():
    global _DREAMERV3_PATH, _DREAMERV3_EXTRACTED
    if _DREAMERV3_EXTRACTED or not _DREAMERV3_BUNDLE:
        return _DREAMERV3_PATH
    try:
        import pickle
        bundle_data = gzip.decompress(base64.b64decode(_DREAMERV3_BUNDLE))
        files = pickle.loads(bundle_data)
        _DREAMERV3_PATH = Path(tempfile.mkdtemp(prefix='dreamerv3_'))
        for rel_path, content in files.items():
            full_path = _DREAMERV3_PATH / rel_path
            full_path.parent.mkdir(parents=True, exist_ok=True)
            full_path.write_bytes(content)
        # Add to sys.path
        if str(_DREAMERV3_PATH) not in sys.path:
            sys.path.insert(0, str(_DREAMERV3_PATH))
        _DREAMERV3_EXTRACTED = True
        print(f"[🐍 Ouroboros] ✓ DreamerV3 extracted: {len(files)} files")
    except Exception as e:
        print(f"[🐍 Ouroboros] DreamerV3 extraction failed: {e}")
    return _DREAMERV3_PATH

def _cleanup_dreamerv3():
    global _DREAMERV3_PATH
    if _DREAMERV3_PATH and _DREAMERV3_PATH.exists():
        try:
            shutil.rmtree(_DREAMERV3_PATH)
        except Exception:
            pass

atexit.register(_cleanup_dreamerv3)

# Extract immediately on module load
_extract_dreamerv3()

