# REMOTE GPU EXECUTOR - SSH-based Remote Inference
# ═══════════════════════════════════════════════════════════════
# Execute Python code on rented GPUs via SSH tunnel.
# Zero-password authentication using auto-generated SSH keys.
# Enables "limitless pill" mode - use heavy models on potato PCs.

class RemoteGPUExecutor:
    """Execute Python code on remote GPU via SSH."""
    
    def __init__(self, host: str, port: int, username: str = 'root', key_path: Optional[str] = None):
        self.host = host
        self.port = port
        self.username = username
        self.key_path = key_path or str(Path.home() / '.ssh' / 'id_rsa')
        self.client = None
        self.channel = None
        self._connected = False
    
    def connect(self, timeout: int = 30) -> bool:
        """Establish SSH connection and start Python REPL."""
        try:
            # Verify SSH key exists BEFORE attempting connection
            key_file = Path(self.key_path)
            if not key_file.exists():
                print(f"SSH key not found at {self.key_path}")
                return False
            
            import paramiko
            self.client = paramiko.SSHClient()
            self.client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
            
            # CRITICAL: Disable password auth entirely - key-only authentication
            self.client.connect(
                hostname=self.host,
                port=self.port,
                username=self.username,
                key_filename=self.key_path,
                timeout=timeout,
                look_for_keys=True,
                allow_agent=True,
                password=None,  # Explicitly no password
                passphrase=None,  # Explicitly no passphrase
                disabled_algorithms={'pubkeys': []}  # Don't disable any key algorithms
            )
            
            # Start interactive shell
            self.channel = self.client.invoke_shell()
            import time
            time.sleep(1)  # Wait for shell to initialize
            
            # Clear any welcome messages
            if self.channel.recv_ready():
                self.channel.recv(4096)
            
            # Start Python REPL
            self.channel.send('python3\n')
            time.sleep(1)
            
            # Wait for Python prompt
            output = self._read_until_prompt(timeout=10)
            if '>>>' in output:
                self._connected = True
                
                # Auto-import common dependencies for GPU work
                self.channel.send('import torch\n')
                time.sleep(0.5)
                self._read_until_prompt(timeout=5)
                
                self.channel.send('import numpy as np\n')
                time.sleep(0.5)
                self._read_until_prompt(timeout=5)
                
                return True
            
            return False
            
        except Exception as e:
            print(f"Connection failed: {e}")
            return False
    
    def _read_until_prompt(self, timeout: int = 30) -> str:
        """Read output until Python prompt appears."""
        import time
        output = ''
        start_time = time.time()
        
        while time.time() - start_time < timeout:
            if self.channel.recv_ready():
                chunk = self.channel.recv(4096).decode('utf-8', errors='ignore')
                output += chunk
                
                # Check for Python prompt
                if '>>>' in output or '...' in output:
                    return output
            
            time.sleep(0.1)
        
        return output
    
    def execute(self, code: str, timeout: int = 60) -> Dict[str, Any]:
        """Execute Python code and return output."""
        if not self._connected:
            return {'error': 'Not connected', 'output': None}
        
        try:
            import time
            # Send code
            self.channel.send(code + '\n')
            time.sleep(0.5)
            
            # Read output
            output = self._read_until_prompt(timeout=timeout)
            
            # Parse output (remove prompt and echoed code)
            lines = output.split('\n')
            result_lines = [l for l in lines if not l.startswith('>>>') and not l.startswith('...') and l.strip()]
            result = '\n'.join(result_lines).strip()
            
            return {'output': result, 'error': None}
            
        except Exception as e:
            return {'error': str(e), 'output': None}
    
    def load_model(self, model_id: str) -> Dict[str, Any]:
        """Load a model on the remote GPU."""
        code = f"""
import torch
from transformers import AutoModel, AutoTokenizer
try:
    model = AutoModel.from_pretrained('{model_id}').cuda()
    tokenizer = AutoTokenizer.from_pretrained('{model_id}')
    print('MODEL_LOADED:{model_id}')
except Exception as e:
    print(f'MODEL_ERROR:{{e}}')
"""
        result = self.execute(code, timeout=120)
        
        if result['error']:
            return {'status': 'error', 'message': result['error']}
        
        if 'MODEL_LOADED' in result.get('output', ''):
            return {'status': 'loaded', 'model_id': model_id}
        elif 'MODEL_ERROR' in result.get('output', ''):
            return {'status': 'error', 'message': result['output']}
        else:
            return {'status': 'unknown', 'output': result['output']}
    
    def embed(self, text: str, model_var: str = 'model') -> Dict[str, Any]:
        """Generate embeddings using loaded model."""
        # Escape quotes in text
        text_escaped = text.replace("'", "\\'").replace('"', '\\"')
        
        code = f"""
import torch
import numpy as np
try:
    inputs = tokenizer("{text_escaped}", return_tensors="pt", truncation=True, max_length=512).to('cuda')
    with torch.no_grad():
        outputs = {model_var}(**inputs)
    embedding = outputs.last_hidden_state.mean(dim=1).cpu().numpy()
    print('EMBEDDING_SHAPE:', embedding.shape)
    print('EMBEDDING_MEAN:', embedding.mean())
except Exception as e:
    print(f'EMBED_ERROR:{{e}}')
"""
        result = self.execute(code, timeout=30)
        
        if 'EMBEDDING_SHAPE' in result.get('output', ''):
            return {'status': 'success', 'output': result['output']}
        else:
            return {'status': 'error', 'message': result.get('output', 'Unknown error')}
    
    def generate(self, prompt: str, model_var: str = 'model', max_tokens: int = 256) -> Dict[str, Any]:
        """Generate text using loaded model."""
        prompt_escaped = prompt.replace("'", "\\'").replace('"', '\\"')
        
        code = f"""
import torch
try:
    inputs = tokenizer("{prompt_escaped}", return_tensors="pt").to('cuda')
    _in_len = inputs['input_ids'].shape[-1]
    with torch.no_grad():
        outputs = {model_var}.generate(**inputs, max_new_tokens={max_tokens})
    generated = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
    print('GENERATED:', generated)
except Exception as e:
    print(f'GENERATE_ERROR:{{e}}')
"""
        result = self.execute(code, timeout=60)
        
        if 'GENERATED:' in result.get('output', ''):
            return {'status': 'success', 'output': result['output']}
        else:
            return {'status': 'error', 'message': result.get('output', 'Unknown error')}
    
    def close(self):
        """Close SSH connection."""
        if self.channel:
            self.channel.close()
        if self.client:
            self.client.close()
        self._connected = False
    
    def __enter__(self):
        self.connect()
        return self
    
    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()


# ═══════════════════════════════════════════════════════════════
# CAPSULE AGENT
# ═══════════════════════════════════════════════════════════════

class CapsuleAgent:
    """
    🔮 GLASS BOX AI - Self-contained evolved agent with full provenance.
    
    Every inference call is observed and recorded in the CASCADE lattice.
    Cryptographic receipts link back to genesis.
    
    Usage:
        agent = CapsuleAgent()
        output = agent.forward({"traits": [0.5, 0.3, 0.8]})
        agent.learn(task_data)
        agent.export_pt("model.pt")
        
        # View provenance
        agent.show_readme()
        agent.get_cascade_identity()
        
        # Dataset bridging (data_unity)
        bridge_result = agent.get_bridge().bridge(old_form, new_form)
        
        # Observation modes:
        # - observe=True: CASCADE receipts (cryptographic)
        # - observe_visual=True: Rerun viewer (visual)
    """
    
    def __init__(self, observe: bool = True, observe_visual: bool = False):
        """
        Initialize capsule agent.
        
        Args:
            observe: If True, initialize CASCADE for cryptographic receipts
            observe_visual: If True, initialize Rerun for visual observation
        """
        self.brain = CapsuleBrain()
        self.traits = _TRAITS.copy()
        self.fitness = _FITNESS
        self.generation = _GENERATION
        self.bridge = None  # Lazy init
        self._inference_count = 0
        self._cascade_identity = None
        self._observe_visual = observe_visual
        # Agent identity for provenance tracking
        self._id = _NODE_DOCS[0]["node_id"] if _NODE_DOCS else f"capsule_gen{self.generation}"
        self._parent_ids = []  # Will be populated by quine replication
        
        # Initialize CASCADE lattice (THE RECEIPTS)
        if observe:
            _init_cascade()
            self._cascade_identity = _create_capsule_identity()
        
        # Initialize Rerun viewer (THE EYES)
        if observe_visual:
            _init_rerun()
    
    def get_bridge(self):
        """Get or create bridge faculty."""
        if self.bridge is None:
            self.bridge = BridgeFaculty(self)
        return self.bridge
    
    def forward(self, inputs: Dict[str, Any] = None, observe: bool = True,
                observe_visual: bool = None) -> Dict[str, Any]:
        """
        Run inference with dual observation:
        - CASCADE: Cryptographic receipts (the PROOF)
        - Rerun: Visual observation (the EYES)
        
        Args:
            inputs: Input dict
            observe: If True, emit CASCADE cryptographic receipt
            observe_visual: If True, log to Rerun (defaults to self._observe_visual)
            
        Returns:
            Output dict with optional merkle_root
        """
        inputs = inputs or {"traits": self.traits}
        
        # Use instance default if not specified
        if observe_visual is None:
            observe_visual = getattr(self, '_observe_visual', False)
        
        self._inference_count += 1
        
        # Forward pass with FULL INTERNAL CAPTURE
        output, internals = self._forward_with_internals(inputs)
        
        # CASCADE observation with COMPLETE COMPUTATIONAL RECORD
        observation = None
        if observe:
            node_id = _NODE_DOCS[0]["node_id"] if _NODE_DOCS else "capsule"
            observation = _observe_inference(
                model_id=f"key-evolved/{node_id}",
                input_data=inputs,
                output_data=output,
                internals=internals,  # THE GLASS BOX - full computation
                metrics={
                    "generation": self.generation,
                    "fitness": self.fitness,
                    "inference_num": self._inference_count,
                }
            )
            if observation and observation.get("merkle_root"):
                output["_merkle_root"] = observation["merkle_root"]
                output["_genesis_linked"] = observation.get("genesis_linked", False)
        
        # Rerun VISUALIZES the CASCADE event (single source of truth)
        if observe_visual and observation:
            _visualize_cascade_event(observation, self._inference_count)
        
        return output
    
    def _forward_with_internals(self, inputs: Dict[str, Any]):
        """
        Forward pass capturing COMPLETE computational internals.
        
        This is what makes Glass Box real - every computation step
        is captured and will be merkle-hashed by CASCADE.
        """
        # Get input vector
        if "traits" in inputs:
            x = np.array(list(inputs["traits"].values()) if isinstance(inputs["traits"], dict) 
                        else inputs["traits"])
        else:
            x = np.array(list(_TRAITS.values()))
        
        internals = {
            "brain_type": self.brain.brain_type,
            "input_vector": x.tolist(),
            "computation_path": [],
        }
        
        if self.brain.brain_type == "mlp":
            # === LAYER 1: Linear ===
            pre_h = x @ self.brain.w1 + self.brain.b1
            internals["computation_path"].append("linear_1")
            internals["hidden_pre"] = pre_h.tolist()
            
            # === LAYER 1: Activation ===
            h = np.tanh(pre_h)
            internals["computation_path"].append("tanh")
            internals["hidden_post"] = h.tolist()
            
            # === LAYER 2: Linear (output) ===
            out = h @ self.brain.w2 + self.brain.b2
            internals["computation_path"].append("linear_2")
            internals["output_pre_format"] = out.tolist()
            
            # === Weight snapshot (hashed for efficiency) ===
            import hashlib
            w1_hash = hashlib.sha256(self.brain.w1.tobytes()).hexdigest()[:16]
            w2_hash = hashlib.sha256(self.brain.w2.tobytes()).hexdigest()[:16]
            internals["weights_snapshot"] = {
                "w1_hash": w1_hash,
                "w2_hash": w2_hash,
                "w1_shape": list(self.brain.w1.shape),
                "w2_shape": list(self.brain.w2.shape),
                "w1_norm": float(np.linalg.norm(self.brain.w1)),
                "w2_norm": float(np.linalg.norm(self.brain.w2)),
            }
            
            output = {key: float(out[i]) for i, key in enumerate(self.brain.output_keys)}
            return output, internals
        
        elif self.brain.brain_type == "scarecrow":
            # Scarecrow adapter - convert traits to input if needed
            scarecrow_inputs = inputs.copy()
            if 'embedding' not in scarecrow_inputs and 'input' not in scarecrow_inputs:
                # Convert traits to input vector for scarecrow
                scarecrow_inputs['input'] = x
            
            raw_output = self.brain.forward(scarecrow_inputs)
            internals["computation_path"].append("scarecrow_adapter")
            
            # Capture adapter internals
            if hasattr(self.brain._brain, 'adapter_in'):
                import hashlib
                adapter_in_hash = hashlib.sha256(self.brain._brain.adapter_in.tobytes()).hexdigest()[:16]
                adapter_out_hash = hashlib.sha256(self.brain._brain.adapter_out.tobytes()).hexdigest()[:16]
                internals["adapter_snapshot"] = {
                    "adapter_in_hash": adapter_in_hash,
                    "adapter_out_hash": adapter_out_hash,
                    "adapter_dim": self.brain._brain.adapter_dim,
                    "model_plugged": self.brain._brain.model is not None,
                }
            
            # Convert raw numpy output to dict format with action
            if isinstance(raw_output, np.ndarray):
                action = int(np.argmax(raw_output[:32])) if len(raw_output) >= 32 else int(np.argmax(raw_output))
                output = {
                    'action': action,
                    'value': float(raw_output.mean()),
                    'embedding': raw_output.tolist(),
                }
            elif isinstance(raw_output, dict):
                # Handle dict output from QuineScarecrowBrain
                emb = raw_output.get('output', raw_output.get('embedding', np.zeros(32)))
                if isinstance(emb, np.ndarray):
                    action = int(np.argmax(emb[:32])) if len(emb) >= 32 else int(np.argmax(emb))
                    value = float(emb.mean())
                    emb_list = emb.tolist()
                else:
                    action = 0
                    value = 0.0
                    emb_list = emb if isinstance(emb, list) else [0.0]
                output = {
                    'action': action,
                    'value': value,
                    'embedding': emb_list,
                }
            else:
                output = {'action': 0, 'value': 0.0}
            
            return output, internals
        
        elif self.brain.brain_type == "dreamer":
            # Dreamer with full RSSM
            output = self.brain.forward(inputs)
            internals["computation_path"].append("dreamer_rssm")
            return output, internals

        elif self.brain.brain_type == "ouroboros":
            # Ouroboros composite brain - full 5-stage pipeline
            try:
                output = self.brain.forward(inputs)
                internals["computation_path"].append("ouroboros_pipeline")
                # Capture pipeline stage details if available
                if isinstance(output, dict):
                    if 'councilor_votes' in output.get('final_output', {}) if isinstance(output.get('final_output'), dict) else False:
                        internals["council_votes"] = output.get('final_output', {}).get('councilor_votes', 0)
                    internals["pipeline_stages"] = ["embed", "dreamer", "scarecrow", "council", "hold"]
            except Exception as e:
                # Graceful fallback on pipeline failure
                internals["computation_path"].append("ouroboros_fallback")
                internals["pipeline_error"] = str(e)
                output = {"action": 0, "value": 0.0, "error": str(e)}
            return output, internals

        else:
            # Other brain types - basic capture
            output = self.brain.forward(inputs)
            internals["computation_path"].append("unknown_forward")
            return output, internals
    
    def get_cascade_identity(self) -> Optional[Dict]:
        """Get the CASCADE ModelIdentity for this capsule."""
        if self._cascade_identity:
            return {
                "model_id": self._cascade_identity.model_id,
                "parent_root": _GENESIS_ROOT,
                "genesis_linked": True,
            }
        return None
    
    def verify_genesis_lineage(self) -> bool:
        """Verify this capsule's provenance chain links to genesis."""
        if not _HAS_CASCADE:
            return False
        try:
            # Simple check - verify genesis root matches
            actual_genesis = get_genesis_root()
            return actual_genesis == _GENESIS_ROOT
        except Exception:
            return False
    
    def pin_provenance(self) -> Optional[str]:
        """
        Pin full provenance record to IPFS.
        
        Returns the CID (content ID) which can be used to retrieve
        this exact provenance record from any IPFS gateway forever.
        
        Usage:
            agent = CapsuleAgent()
            for _ in range(100):
                agent.forward({"traits": [0.5, 0.3]})
            cid = agent.pin_provenance()
            print(f"Provenance pinned: ipfs.io/ipfs/{cid}")
        """
        provenance = self.get_full_provenance()
        cid = _pin_to_ipfs(provenance, name=f"capsule_gen{self.generation}_provenance")
        if cid:
            print(f"📌 Provenance pinned to IPFS: {cid}")
            print(f"   View: https://ipfs.io/ipfs/{cid}")
        return cid
    
    # ═══════════════════════════════════════════════════════════
    # HOLD - Inference-Level Halt (requires cascade-lattice)
    # ═══════════════════════════════════════════════════════════
    
    def forward_hold(self, inputs: Dict[str, Any] = None, blocking: bool = True) -> Dict[str, Any]:
        """
        Run inference with HOLD - yields at decision point.
        
        HOLD halts inference at the decision point, exposing the action
        probabilities for potential human override. Resolution is
        recorded to CASCADE with full provenance.
        
        Requires: cascade-lattice (pip install cascade-lattice)
        
        Args:
            inputs: Input dict
            blocking: If True, blocks until resolved (or timeout)
            
        Returns:
            Output dict including hold resolution data
            
        Usage:
            agent = CapsuleAgent()
            
            # In another thread or async:
            hold = get_hold()
            hold.override(3)  # Override AI choice with action 3
            # or: hold.accept()  # Accept AI's choice
            
            output = agent.forward_hold({"obs": observation})
            # output['was_override'] tells you if human overrode
        """
        if not _HOLD_AVAILABLE:
            print("⚠️ HOLD requires cascade-lattice: pip install cascade-lattice")
            return self.forward(inputs, observe=True)
        
        inputs = inputs or {"traits": self.traits}
        self._inference_count += 1
        
        # Get decision matrix from brain
        output = self.brain.forward(inputs)
        
        action_probs = output.get('action_probs')
        if action_probs is None:
            # Non-dreamer brain - no HOLD support
            return self.forward(inputs, observe=True)
        
        # YIELD to HOLD system
        node_id = _NODE_DOCS[0]["node_id"] if _NODE_DOCS else "capsule"
        # Safely extract value - may be dict in nested brain outputs
        raw_value = output.get('value', 0.0)
        # Unwrap nested dicts recursively (handles {'value': {'value': 0.5}})
        while isinstance(raw_value, dict):
            raw_value = raw_value.get('value', raw_value.get('output', 0.0))
        if isinstance(raw_value, (int, float)) and not isinstance(raw_value, bool):
            hold_value = float(raw_value)
        else:
            hold_value = 0.0
        resolution = _HOLD_SYSTEM.yield_point(
            action_probs=np.array(action_probs),
            value=hold_value,
            observation=inputs,
            brain_id=f"key-evolved/{node_id}",
            blocking=blocking,
        )
        
        # Update output with resolution
        output['action'] = resolution['action']
        output['was_override'] = resolution['was_override']
        output['hold_id'] = resolution['hold_id']
        output['hold_duration'] = resolution.get('duration', 0.0)
        
        return output
    
    @property
    def hold(self):
        """Access HOLD system for this capsule."""
        return _HOLD_SYSTEM
    
    @property
    def hold_stats(self) -> Dict[str, Any]:
        """Get HOLD statistics."""
        if not _HOLD_AVAILABLE:
            return {'available': False}
        return {
            'available': True,
            'enabled': _HOLD_SYSTEM.enabled,
            'total_holds': _HOLD_SYSTEM.hold_count,
            'overrides': _HOLD_SYSTEM.override_count,
            'override_rate': _HOLD_SYSTEM.override_count / max(_HOLD_SYSTEM.hold_count, 1),
            'timeout': _HOLD_SYSTEM.timeout,
        }
    
