    def export_pdf(self, path: str = None, mode: str = 'full') -> str:
        """
        Export capsule as PDF with syntax highlighting and provenance.
        
        Modes:
            'full'       - Complete source file as PDF (syntax highlighted)
            'report'     - Diagnostic report (metadata, architecture, fitness)
            'provenance' - Cascade-lattice verified lineage chain
            'artifacts'  - All embedded artifacts as separate pages
            'summary'    - One-page executive summary
        
        Uses cascade-lattice pip package for cryptographic provenance.
        
        Args:
            path: Output path (default: <capsule_name>_<mode>.pdf)
            mode: One of 'full', 'report', 'provenance', 'artifacts', 'summary'
            
        Returns:
            Path to generated PDF
        """
        try:
            from reportlab.lib.pagesizes import letter, A4
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            from reportlab.lib.units import inch
            from reportlab.lib.colors import HexColor, black, white, gray
            from reportlab.platypus import (
                SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle,
                PageBreak, Preformatted, Image, Flowable
            )
            from reportlab.lib.enums import TA_LEFT, TA_CENTER, TA_RIGHT
            from pygments import highlight
            from pygments.lexers import PythonLexer
            from pygments.formatters import HtmlFormatter
            import html
        except ImportError as e:
            print(f"PDF export requires: pip install reportlab pygments")
            print(f"Missing: {e}")
            return None
        
        # Default path
        stem = Path(__file__).stem
        path = path or f"{stem}_{mode}.pdf"
        
        # Build PDF based on mode
        if mode == 'full':
            return self._export_pdf_full_source(path)
        elif mode == 'report':
            return self._export_pdf_diagnostic_report(path)
        elif mode == 'provenance':
            return self._export_pdf_provenance(path)
        elif mode == 'artifacts':
            return self._export_pdf_artifacts(path)
        elif mode == 'summary':
            return self._export_pdf_summary(path)
        else:
            print(f"Unknown PDF mode '{mode}'. Use: full, report, provenance, artifacts, summary")
            return None
    
    def _export_pdf_full_source(self, path: str) -> str:
        """Export entire Python source as syntax-highlighted PDF."""
        from reportlab.lib.pagesizes import letter
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.units import inch
        from reportlab.lib.colors import HexColor, black
        from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Preformatted, PageBreak
        from reportlab.lib.enums import TA_LEFT
        from pygments import highlight
        from pygments.lexers import PythonLexer
        from pygments.formatters import RawTokenFormatter
        from pygments.token import Token
        from datetime import datetime
        import html
        
        # Read source
        source = Path(__file__).read_text(encoding='utf-8')
        
        # Create PDF
        doc = SimpleDocTemplate(path, pagesize=letter,
                               leftMargin=0.5*inch, rightMargin=0.5*inch,
                               topMargin=0.5*inch, bottomMargin=0.5*inch)
        
        styles = getSampleStyleSheet()
        
        # Code style - monospace, small
        code_style = ParagraphStyle(
            'Code',
            parent=styles['Normal'],
            fontName='Courier',
            fontSize=6,
            leading=7,
            leftIndent=0,
            textColor=black,
        )
        
        # Title style
        title_style = ParagraphStyle(
            'Title',
            parent=styles['Heading1'],
            fontSize=18,
            textColor=HexColor('#1a1a2e'),
            spaceAfter=12,
        )
        
        # Header style
        header_style = ParagraphStyle(
            'Header',
            parent=styles['Normal'],
            fontSize=10,
            textColor=HexColor('#666666'),
        )
        
        story = []
        
        # Title page
        story.append(Paragraph(f"📦 {Path(__file__).stem}", title_style))
        story.append(Paragraph(f"Champion Capsule - Full Source", styles['Heading2']))
        story.append(Spacer(1, 12))
        
        # Metadata header
        meta_lines = [
            f"Generation: {self.generation} | Fitness: {self.fitness:.4f}",
            f"Brain Type: {_BRAIN_CONFIG.get('brain_type', 'unknown')}",
            f"Exported: {datetime.now().isoformat()}",
            f"Lines: {len(source.splitlines())} | Size: {len(source):,} bytes",
        ]
        for line in meta_lines:
            story.append(Paragraph(line, header_style))
        
        story.append(Spacer(1, 24))
        story.append(PageBreak())
        
        # Source code - split into chunks to avoid memory issues
        lines = source.splitlines()
        chunk_size = 100  # Lines per page approximately
        
        for i in range(0, len(lines), chunk_size):
            chunk = lines[i:i+chunk_size]
            # Add line numbers
            numbered = []
            for j, line in enumerate(chunk, start=i+1):
                # Escape HTML entities
                escaped = html.escape(line)
                numbered.append(f"{j:5d} │ {escaped}")
            
            code_text = "\n".join(numbered)
            # Use Preformatted for exact spacing
            story.append(Preformatted(code_text, code_style))
            story.append(PageBreak())
        
        doc.build(story)
        print(f"📄 Exported full source PDF: {path}")
        print(f"   {len(lines)} lines, {len(source):,} bytes")
        return path
    
