            ["Node Docs", "✓" if _NODE_DOCS else "✗", f"{len(_NODE_DOCS)} nodes" if _NODE_DOCS else "Empty"],
            ["Population Doc", "✓" if _POPULATION_DOC else "✗", f"{len(str(_POPULATION_DOC))} chars"],
            ["Config Doc", "✓" if _CONFIG_DOC else "✗", f"{len(str(_CONFIG_DOC))} chars"],
