    def _export_pdf_provenance(self, path: str) -> str:
        """Export cascade-lattice provenance chain as PDF."""
        from reportlab.lib.pagesizes import letter
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.units import inch
        from reportlab.lib.colors import HexColor, black, white
        from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, PageBreak
        from reportlab.lib.enums import TA_CENTER
        
        doc = SimpleDocTemplate(path, pagesize=letter,
                               leftMargin=0.75*inch, rightMargin=0.75*inch,
                               topMargin=0.75*inch, bottomMargin=0.75*inch)
        
        styles = getSampleStyleSheet()
        title_style = ParagraphStyle('Title', parent=styles['Heading1'],
                                      fontSize=24, textColor=HexColor('#2d5016'),
                                      alignment=TA_CENTER, spaceAfter=24)
        section_style = ParagraphStyle('Section', parent=styles['Heading2'],
                                        fontSize=14, textColor=HexColor('#4a6a4a'))
        
        story = []
        
        # Title
        story.append(Paragraph("🔗 CASCADE-LATTICE PROVENANCE CHAIN", title_style))
        story.append(Paragraph(f"Capsule: {Path(__file__).stem}", styles['Heading3']))
        story.append(Spacer(1, 24))
        
        # Try to get full provenance from cascade-lattice pip package
        provenance = self.get_full_provenance()
        cascade = provenance.get('cascade', {})
        
        # Genesis Root
        story.append(Paragraph("§1 GENESIS ROOT", section_style))
        genesis_data = [
            ["Property", "Value"],
            ["Genesis Root Hash", cascade.get('genesis_root', 'Not Set') or 'Not Set'],
            ["CASCADE Package", "✓ Available" if cascade.get('has_cascade') else "✗ Not Installed"],
            ["Verified", "✓ Yes" if cascade.get('genesis_verified') else "○ Pending"],
        ]
        
        t = Table(genesis_data, colWidths=[2.5*inch, 4*inch])
        t.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, 0), HexColor('#2d5016')),
            ('TEXTCOLOR', (0, 0), (-1, 0), white),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('GRID', (0, 0), (-1, -1), 0.5, black),
        ]))
        story.append(t)
        story.append(Spacer(1, 24))
        
        # Capsule Identity
        story.append(Paragraph("§2 CAPSULE IDENTITY", section_style))
        identity = cascade.get('identity', {})
        if identity:
            id_data = [["Property", "Value"]]
            for key, value in identity.items():
                val_str = str(value)
                if len(val_str) > 50:
                    val_str = val_str[:50] + "..."
                id_data.append([key, val_str])
            
            t = Table(id_data, colWidths=[2.5*inch, 4*inch])
            t.setStyle(TableStyle([
                ('BACKGROUND', (0, 0), (-1, 0), HexColor('#4a6a4a')),
                ('TEXTCOLOR', (0, 0), (-1, 0), white),
                ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
                ('GRID', (0, 0), (-1, -1), 0.5, black),
            ]))
            story.append(t)
        else:
            story.append(Paragraph("No identity computed yet. Run inference to generate.", styles['Normal']))
        story.append(Spacer(1, 24))
        
        # Lineage Chain (from node docs if available)
        story.append(Paragraph("§3 EVOLUTIONARY LINEAGE", section_style))
        if _NODE_DOCS:
            for i, node_doc in enumerate(_NODE_DOCS[:10]):  # Limit to 10
                node_id = node_doc.get('node_id', f'node_{i}')
                gen = node_doc.get('generation', '?')
                fitness = node_doc.get('fitness', 0)
                story.append(Paragraph(
                    f"<b>{node_id}</b> | Gen {gen} | Fitness: {fitness:.4f}",
                    styles['Normal']
                ))
        else:
            story.append(Paragraph("No lineage data embedded.", styles['Normal']))
        
        doc.build(story)
        print(f"🔗 Exported provenance chain: {path}")
        return path
    
    def _export_pdf_artifacts(self, path: str) -> str:
        """Export all embedded artifacts as separate pages in PDF."""
        from reportlab.lib.pagesizes import letter
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.units import inch
        from reportlab.lib.colors import HexColor
        from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Preformatted, PageBreak
        import json
        
        doc = SimpleDocTemplate(path, pagesize=letter,
                               leftMargin=0.5*inch, rightMargin=0.5*inch,
                               topMargin=0.5*inch, bottomMargin=0.5*inch)
        
        styles = getSampleStyleSheet()
        title_style = ParagraphStyle('Title', parent=styles['Heading1'],
                                      fontSize=18, textColor=HexColor('#1a1a2e'))
        code_style = ParagraphStyle('Code', fontName='Courier', fontSize=7, leading=8)
        
        story = []
        
        # README
        story.append(Paragraph("📖 README", title_style))
        story.append(Spacer(1, 12))
        if _README:
            # Split into chunks
            for line in _README.split('\n'):
                story.append(Paragraph(line or "&nbsp;", styles['Normal']))
        else:
            story.append(Paragraph("No README embedded.", styles['Normal']))
        story.append(PageBreak())
        
        # Config Doc
        story.append(Paragraph("⚙️ CONFIG", title_style))
        story.append(Spacer(1, 12))
        if _CONFIG_DOC:
            config_text = json.dumps(_CONFIG_DOC, indent=2)
            story.append(Preformatted(config_text[:5000], code_style))  # Limit size
        else:
            story.append(Paragraph("No config embedded.", styles['Normal']))
        story.append(PageBreak())
        
        # Population Doc
        story.append(Paragraph("👥 POPULATION", title_style))
        story.append(Spacer(1, 12))
        if _POPULATION_DOC:
            pop_text = json.dumps(_POPULATION_DOC, indent=2)
            story.append(Preformatted(pop_text[:5000], code_style))
        else:
            story.append(Paragraph("No population doc embedded.", styles['Normal']))
        story.append(PageBreak())
        
        # Node Docs
        story.append(Paragraph("🧬 NODE DOCUMENTATION", title_style))
        story.append(Spacer(1, 12))
        if _NODE_DOCS:
            for node_doc in _NODE_DOCS[:5]:  # Limit to 5 nodes
                node_text = json.dumps(node_doc, indent=2)
                story.append(Preformatted(node_text[:2000], code_style))
                story.append(Spacer(1, 12))
        else:
            story.append(Paragraph("No node docs embedded.", styles['Normal']))
        story.append(PageBreak())
        
        # FelixBag Summary
        story.append(Paragraph("🎒 FELIXBAG CONTENTS", title_style))
        story.append(Spacer(1, 12))
        bag_keys = _BAG.list()
        if bag_keys:
            for key in bag_keys[:50]:  # Limit to 50 items
                story.append(Paragraph(f"• {key}", styles['Normal']))
        else:
            story.append(Paragraph("FelixBag is empty.", styles['Normal']))
        
        doc.build(story)
        print(f"📚 Exported artifacts: {path}")
        return path
    
    def _export_pdf_summary(self, path: str) -> str:
        """Export one-page executive summary PDF."""
        from reportlab.lib.pagesizes import letter
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.units import inch
        from reportlab.lib.colors import HexColor, black, white
        from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
        from reportlab.lib.enums import TA_CENTER
        
        doc = SimpleDocTemplate(path, pagesize=letter,
                               leftMargin=1*inch, rightMargin=1*inch,
                               topMargin=1*inch, bottomMargin=1*inch)
        
        styles = getSampleStyleSheet()
        title_style = ParagraphStyle('Title', parent=styles['Heading1'],
                                      fontSize=28, textColor=HexColor('#1a1a2e'),
                                      alignment=TA_CENTER, spaceAfter=36)
        
        story = []
        
        # Title
        story.append(Paragraph("🏆 CHAMPION SUMMARY", title_style))
        story.append(Paragraph(f"<b>{Path(__file__).stem}</b>", 
                              ParagraphStyle('Sub', alignment=TA_CENTER, fontSize=14)))
        story.append(Spacer(1, 36))
        
        # Key metrics
        metrics = [
            ["Generation", str(self.generation)],
            ["Fitness", f"{self.fitness:.6f}"],
            ["Brain Type", _BRAIN_CONFIG.get('brain_type', 'unknown')],
            ["Inferences", str(self._inference_count)],
            ["FelixBag Items", str(len(_BAG.list()))],
            ["CASCADE Verified", "✓" if self.verify_genesis_lineage() else "○"],
        ]
        
        t = Table(metrics, colWidths=[2.5*inch, 3*inch])
        t.setStyle(TableStyle([
            ('FONTSIZE', (0, 0), (-1, -1), 14),
            ('ALIGN', (0, 0), (0, -1), 'RIGHT'),
            ('ALIGN', (1, 0), (1, -1), 'LEFT'),
            ('FONTNAME', (0, 0), (0, -1), 'Helvetica-Bold'),
            ('TEXTCOLOR', (0, 0), (0, -1), HexColor('#4a4a6a')),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 12),
        ]))
        story.append(t)
        story.append(Spacer(1, 36))
        
        # Footer
        story.append(Paragraph(
            f"Generated: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
            ParagraphStyle('Footer', alignment=TA_CENTER, fontSize=10, textColor=HexColor('#888888'))
        ))
        
        doc.build(story)
        print(f"📋 Exported summary: {path}")
        return path

    # ═══════════════════════════════════════════════════════════════
    # INSTANT TRANSMISSION SYSTEM
    # Dragon Ball Z-inspired agent teleportation via PDF
    # The agent is EMBEDDED in the PDF as an attachment with full transparency
    # ═══════════════════════════════════════════════════════════════
    
    def instant_transmission(self, path: str = None) -> str:
        """
        INSTANT TRANSMISSION - Serialize this agent into a PDF that can reconstitute it anywhere.
        
        The PDF contains:
        - Full documentation of what's embedded
        - Visual instructions for extraction  
        - The complete agent as an embedded attachment
        - Extraction script embedded for easy revival
        
        This is NOT hidden or obfuscated - the PDF clearly explains
        exactly what it contains and how to bring the agent back to life.
        
        Inspired by: Dragon Ball Z's Instant Transmission, Star Trek transporters,
        Pokemon's PC storage system, The Matrix's 'I know kung fu' upload.
        """
        try:
            from reportlab.lib.pagesizes import letter
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            from reportlab.lib.units import inch
            from reportlab.lib.colors import HexColor, black, white
            from reportlab.platypus import (
                SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle,
                PageBreak
            )
            from reportlab.lib.enums import TA_CENTER, TA_LEFT
            from pypdf import PdfWriter, PdfReader
            from datetime import datetime
            import io
        except ImportError as e:
            print(f"Instant Transmission requires: pip install reportlab pypdf")
            print(f"Missing: {e}")
            return None
        
        stem = Path(__file__).stem
        path = path or f"{stem}_instant_transmission.pdf"
        temp_pdf = path + ".tmp"
        
        # Create the visual PDF with ReportLab
        doc = SimpleDocTemplate(temp_pdf, pagesize=letter,
                               leftMargin=0.75*inch, rightMargin=0.75*inch,
                               topMargin=0.75*inch, bottomMargin=0.75*inch)
        
        styles = getSampleStyleSheet()
        
        title_style = ParagraphStyle(
            'ITTitle', parent=styles['Heading1'],
            fontSize=32, textColor=HexColor('#ff6b00'),
            alignment=TA_CENTER, spaceAfter=6,
            fontName='Helvetica-Bold'
        )
        
        subtitle_style = ParagraphStyle(
            'ITSubtitle', parent=styles['Normal'],
            fontSize=14, textColor=HexColor('#666666'),
            alignment=TA_CENTER, spaceAfter=24
        )
        
        section_style = ParagraphStyle(
            'ITSection', parent=styles['Heading2'],
            fontSize=16, textColor=HexColor('#1a1a2e'),
            spaceBefore=18, spaceAfter=8
        )
        
        body_style = ParagraphStyle(
            'ITBody', parent=styles['Normal'],
            fontSize=11, textColor=HexColor('#333333'),
            spaceAfter=8, leading=14
        )
        
        code_style = ParagraphStyle(
            'ITCode', parent=styles['Normal'],
            fontName='Courier', fontSize=9,
            textColor=HexColor('#0066cc'),
            backColor=HexColor('#f5f5f5'),
            leftIndent=12, rightIndent=12,
            spaceBefore=6, spaceAfter=6
        )
        
        story = []
        
        # PAGE 1: Title and Explanation
        story.append(Paragraph("INSTANT TRANSMISSION", title_style))
        story.append(Paragraph(
            "This PDF contains a complete AI agent that can be reconstituted",
            subtitle_style
        ))
        story.append(Spacer(1, 12))
        
        # Explanation box
        explanation = [
            ["WHAT IS THIS?"],
            ["This PDF contains a fully serialized neural network agent."],
            ["The agent's weights, configuration, and runtime are embedded"],
            ["as an attachment. You can extract and run it on any machine."],
        ]
        
        t = Table(explanation, colWidths=[6*inch])
        t.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, 0), HexColor('#1a1a2e')),
            ('TEXTCOLOR', (0, 0), (-1, 0), white),
            ('FONTSIZE', (0, 0), (-1, 0), 16),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
            ('BACKGROUND', (0, 1), (-1, -1), HexColor('#f0f4ff')),
            ('FONTSIZE', (0, 1), (-1, -1), 11),
            ('TOPPADDING', (0, 0), (-1, -1), 12),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 12),
            ('BOX', (0, 0), (-1, -1), 2, HexColor('#1a1a2e')),
        ]))
        story.append(t)
        story.append(Spacer(1, 24))
        
        # Agent stats
        story.append(Paragraph("AGENT SPECIFICATIONS", section_style))
        
        specs = [
            ["Agent Name", f"{stem}"],
            ["Generation", f"{self.generation}"],
            ["Fitness Score", f"{self.fitness:.6f}"],
            ["Brain Type", f"{_BRAIN_CONFIG.get('brain_type', 'unknown')}"],
            ["Inference Count", f"{self._inference_count}"],
            ["Created", f"{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"],
        ]
        
        spec_table = Table(specs, colWidths=[2*inch, 4*inch])
        spec_table.setStyle(TableStyle([
            ('FONTNAME', (0, 0), (0, -1), 'Helvetica-Bold'),
            ('FONTSIZE', (0, 0), (-1, -1), 11),
            ('ALIGN', (0, 0), (0, -1), 'RIGHT'),
            ('ALIGN', (1, 0), (1, -1), 'LEFT'),
            ('TEXTCOLOR', (0, 0), (0, -1), HexColor('#4a4a6a')),
            ('TOPPADDING', (0, 0), (-1, -1), 6),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 6),
        ]))
        story.append(spec_table)
        story.append(Spacer(1, 24))
        
        # Embedded contents
        story.append(Paragraph("EMBEDDED CONTENTS", section_style))
        story.append(Paragraph("This PDF contains:", body_style))
        
        contents = [
            ["1.", "agent.py", "Complete self-contained agent source"],
            ["2.", "reconstitute.py", "One-click revival script"],
            ["3.", "config.json", "Agent configuration"],
        ]
        
        contents_table = Table(contents, colWidths=[0.3*inch, 1.5*inch, 4*inch])
        contents_table.setStyle(TableStyle([
            ('FONTNAME', (1, 0), (1, -1), 'Courier'),
            ('FONTSIZE', (0, 0), (-1, -1), 10),
            ('TEXTCOLOR', (1, 0), (1, -1), HexColor('#0066cc')),
        ]))
        story.append(contents_table)
        
        story.append(PageBreak())
        
        # PAGE 2: Instructions
        story.append(Paragraph("HOW TO RECONSTITUTE", title_style))
        story.append(Spacer(1, 12))
        
        # Button-like visual
        button = [["EXTRACT ATTACHMENTS"]]
        button_table = Table(button, colWidths=[5*inch], rowHeights=[0.8*inch])
        button_table.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, -1), HexColor('#ff6b00')),
            ('TEXTCOLOR', (0, 0), (-1, -1), white),
            ('FONTSIZE', (0, 0), (-1, -1), 20),
            ('FONTNAME', (0, 0), (-1, -1), 'Helvetica-Bold'),
            ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
            ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
            ('BOX', (0, 0), (-1, -1), 3, HexColor('#cc5500')),
        ]))
        story.append(button_table)
        story.append(Paragraph(
            "(In most PDF readers: View > Attachments, or look for paperclip icon)",
            ParagraphStyle('Hint', alignment=TA_CENTER, fontSize=10, textColor=HexColor('#888888'))
        ))
        story.append(Spacer(1, 24))
        
        story.append(Paragraph("STEP-BY-STEP", section_style))
        steps = [
            "Step 1: Extract the attachments from this PDF",
            "Step 2: Save all files to a folder",
            "Step 3: Run: python reconstitute.py",
            "Or directly: python agent.py",
        ]
        for step in steps:
            story.append(Paragraph(step, body_style))
        
        story.append(Spacer(1, 24))
        story.append(Paragraph("REQUIREMENTS", section_style))
        reqs = ["Python 3.8+", "PyTorch", "NumPy", "sentence-transformers"]
        for req in reqs:
            story.append(Paragraph(f"- {req}", body_style))
        
        story.append(Spacer(1, 24))
        story.append(Paragraph("TRANSPARENCY NOTICE", section_style))
        story.append(Paragraph(
            "This agent is distributed in full source code form. "
            "No hidden functionality, no telemetry. Runs entirely locally.",
            body_style
        ))
        
        story.append(Spacer(1, 24))
        story.append(Paragraph(
            f"Generated by Ouroboros | {datetime.now().isoformat()}",
            ParagraphStyle('Footer', alignment=TA_CENTER, fontSize=9, textColor=HexColor('#aaaaaa'))
        ))
        
        doc.build(story)
        
        # Prepare attachments
        agent_source = Path(__file__).read_bytes()
        
        config_data = json.dumps({
            'generation': self.generation,
            'fitness': self.fitness,
            'traits': self.traits,
            'brain_config': _BRAIN_CONFIG,
        }, indent=2).encode('utf-8')
        
        reconstitute_script = b"#!/usr/bin/env python3\n"
        reconstitute_script += b'"""INSTANT TRANSMISSION - Reconstitute agent."""\n'
        reconstitute_script += b"import sys\n"
        reconstitute_script += b"from pathlib import Path\n\n"
        reconstitute_script += b"def main():\n"
        reconstitute_script += b"    print('INSTANT TRANSMISSION - Reconstituting...')\n"
        reconstitute_script += b"    if not Path('agent.py').exists():\n"
        reconstitute_script += b"        print('Error: agent.py not found!')\n"
        reconstitute_script += b"        return 1\n"
        reconstitute_script += b"    try:\n"
        reconstitute_script += b"        import agent\n"
        reconstitute_script += b"        print('Agent loaded!')\n"
        reconstitute_script += b"        if hasattr(agent, 'main'):\n"
        reconstitute_script += b"            agent.main()\n"
        reconstitute_script += b"        return 0\n"
        reconstitute_script += b"    except Exception as e:\n"
        reconstitute_script += b"        print(f'Error: {e}')\n"
        reconstitute_script += b"        return 1\n\n"
        reconstitute_script += b'if __name__ == "__main__":\n'
        reconstitute_script += b"    sys.exit(main())\n"
        
        # Embed attachments using pypdf
        reader = PdfReader(temp_pdf)
        writer = PdfWriter()
        
        for page in reader.pages:
            writer.add_page(page)
        
        writer.add_attachment("agent.py", agent_source)
        writer.add_attachment("config.json", config_data)
        writer.add_attachment("reconstitute.py", reconstitute_script)
        
        with open(path, "wb") as f:
            writer.write(f)
        
        Path(temp_pdf).unlink()
        
        print()
        print("INSTANT TRANSMISSION COMPLETE")
        print(f"   PDF: {path}")
        print(f"   Agent: {stem}")
        print(f"   Generation {self.generation} | Fitness {self.fitness:.4f}")
        print()
        print("   Share this PDF - the agent travels with it!")
        
        return path
    
    @classmethod
    def reconstitute_from_pdf(cls, pdf_path: str, output_dir: str = None):
        """Reconstitute an agent from an Instant Transmission PDF."""
        try:
            from pypdf import PdfReader
        except ImportError:
            print("Reconstitution requires: pip install pypdf")
            return None
        
        pdf_path = Path(pdf_path)
        output_dir = Path(output_dir) if output_dir else pdf_path.parent
        output_dir.mkdir(parents=True, exist_ok=True)
        
        print(f"Reconstituting from: {pdf_path.name}")
        
        reader = PdfReader(str(pdf_path))
        
        if not reader.attachments:
            print("No attachments found - not an Instant Transmission PDF")
            return None
        
        for name, data_list in reader.attachments.items():
            for data in data_list:
                out_path = output_dir / name
                out_path.write_bytes(data)
                print(f"   Extracted: {name}")
        
        agent_path = output_dir / "agent.py"
        if not agent_path.exists():
            print("agent.py not found in attachments")
            return None
        
        import importlib.util
        spec = importlib.util.spec_from_file_location("agent", str(agent_path))
        module = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(module)
        
        if hasattr(module, 'CapsuleAgent'):
            capsule = module.CapsuleAgent()
            print(f"Agent reconstituted! Gen {capsule.generation}, Fitness {capsule.fitness:.4f}")
            return capsule
        return module

    def export_capsule(self, path: str = None) -> str:
        """
        Export updated capsule (self-replication with new weights).
        """
        path = path or f"{Path(__file__).stem}_v{self.generation + 1}.py"
        
        # Read current file and update embedded data
        current = Path(__file__).read_text(encoding='utf-8')
        
        # Update brain data
        params = self.brain.get_params()
        data = pickle.dumps(params)
        if _DATA_COMPRESSED:
            data = gzip.compress(data)
        new_brain_data = base64.b64encode(data).decode('ascii')
        
        # Replace in source
        import re
        updated = re.sub(
            r'_BRAIN_DATA = """.*?"""',
            f'_BRAIN_DATA = """{new_brain_data}"""',
            current,
            flags=re.DOTALL
        )
        updated = re.sub(
            r'_GENERATION = \d+',
            f'_GENERATION = {self.generation + 1}',
            updated
        )
        updated = re.sub(
            r'_FITNESS = [\d.]+',
            f'_FITNESS = {self.fitness}',
            updated
        )
        
        Path(path).write_text(updated, encoding='utf-8')
        print(f"Exported capsule to {path}")
        return path
    
