    def export_all_docs(self, directory: str = None) -> Dict[str, str]:
        """
        Export all documentation artifacts to Bag of Tricks folder.
        
        Creates <capsule_name>_bag_of_tricks/ folder with all embedded artifacts.
        Dynamically discovers and exports whatever artifacts exist.
        
        Returns dict of {artifact_name: path}
        """
        base_name = Path(__file__).stem
        
        # Default to Bag of Tricks folder (Felix the Cat's magic bag)
        if directory is None:
            directory = f"{base_name}_bag_of_tricks"
        
        dir_path = Path(__file__).parent / directory
        dir_path.mkdir(parents=True, exist_ok=True)
        
        exports = {}
        
        # Dynamic artifact discovery - export whatever exists
        artifact_sources = [
            ('_README', 'README.md', lambda v: v, 'text'),
            ('_NODE_DOCS', 'node_docs.json', lambda v: json.dumps(v, indent=2), 'json'),
            ('_POPULATION_DOC', 'population.json', lambda v: json.dumps(v, indent=2), 'json'),
            ('_CONFIG_DOC', 'config.json', lambda v: json.dumps(v, indent=2), 'json'),
            ('_BRAIN_CONFIG', 'brain_config.json', lambda v: json.dumps(v, indent=2), 'json'),
            ('_TRAITS', 'traits.json', lambda v: json.dumps(v, indent=2), 'json'),
            ('_FELIX_BAG', 'felixbag.json', lambda v: json.dumps({k: str(x)[:1000] if not isinstance(x, (dict, list, str, int, float, bool, type(None))) else x for k, x in v.items()}, indent=2), 'json'),
        ]
        
        for var_name, filename, formatter, ftype in artifact_sources:
            try:
                val = globals().get(var_name)
                if val:
                    artifact_path = dir_path / f"{base_name}_{filename}"
                    content = formatter(val)
                    artifact_path.write_text(content, encoding='utf-8')
                    exports[var_name.strip('_').lower()] = str(artifact_path)
            except Exception as e:
                pass  # Skip failed artifacts silently
        
        # Source code
        source_path = dir_path / f"{base_name}_source.py"
        source_path.write_text(Path(__file__).read_text(encoding='utf-8'), encoding='utf-8')
        exports["source"] = str(source_path)
        
        # Brain data (only if reasonable size)
        if _BRAIN_DATA and len(_BRAIN_DATA) < 100000:
            brain_path = dir_path / f"{base_name}_brain.b64"
            brain_path.write_text(_BRAIN_DATA, encoding='utf-8')
            exports["brain_data"] = str(brain_path)
        
        # Generate PDFs if available
        try:
            for mode in ['summary', 'report']:
                pdf_path = dir_path / f"{base_name}_{mode}.pdf"
                result = self.export_pdf(str(pdf_path), mode)
                if result:
                    exports[f"pdf_{mode}"] = result
        except Exception:
            pass  # PDF generation optional
        
        print(f"🎒 Exported {len(exports)} artifacts to {dir_path.name}/")
        for name, path in exports.items():
            print(f"   ✓ {name}: {Path(path).name}")
        return exports
    
