def get_capabilities() -> dict:
    """Return the capability manifest - what this agent can do."""
    return _CAPABILITIES


def get_action_manifest() -> list:
    """Return list of clickable actions for UI generation."""
    return [
        {
            "id": cap["id"],
            "label": cap["name"],
            "icon": cap["icon"],
            "description": cap["description"],
        }
        for cap in _CAPABILITIES.values()
    ]


def get_param_count() -> int:
    """Get parameter count for this model (works for all brain types)."""
    try:
        brain_type = _BRAIN_CONFIG.get("brain_type", "mlp")
        if brain_type == "dreamer":
            # For Dreamer brains, count LoRA params from config
            # Don't instantiate the brain (expensive!)
            lora_rank = _BRAIN_CONFIG.get("lora_rank", 16)
            latent_dim = _BRAIN_CONFIG.get("latent_dim", 5120)
            action_dim = _BRAIN_CONFIG.get("action_dim", 8)
            # LoRA params: A (latent x rank) + B (rank x action) + bias (action)
            return latent_dim * lora_rank + lora_rank * action_dim + action_dim
        else:
            # For MLP brains, count params array length
            if QuineBrain:
                brain = QuineBrain()
                return len(brain._params) if hasattr(brain, '_params') else 0
            return 0
    except Exception:
        return 0


