        def add_inference(self, fitness: float, time_ms: float):
            self.fitness_history.append(fitness)
            if len(self.fitness_history) > 20:
                self.fitness_history.pop(0)
            self.inference_times.append(time_ms)
            if len(self.inference_times) > 20:
                self.inference_times.pop(0)
            self.inference_count += 1
            self.refresh()
        
        def render(self):
            fit = self.fitness_history[-1] if self.fitness_history else 0
            avg_time = sum(self.inference_times) / len(self.inference_times) if self.inference_times else 0
            spark_chars = "▁▂▃▄▅▆▇█"
            if self.fitness_history:
                mn, mx = min(self.fitness_history), max(self.fitness_history)
                rng = mx - mn if mx > mn else 1
                spark = "".join(spark_chars[min(7, int((v-mn)/rng * 7))] for v in self.fitness_history[-15:])
            else:
                spark = "▁" * 15
            lines = [
                f"[bold cyan]📊 METRICS[/]",
                f"Inferences: [yellow]{self.inference_count}[/]",
                f"Fitness: [green]{fit:.4f}[/]",
                f"Avg Time: [magenta]{avg_time:.1f}ms[/]",
                f"[dim]{spark}[/]",
            ]
            return Panel("\n".join(lines), border_style="cyan", height=7)
    
