    # ═══════════════════════════════════════════════════════════════
    # WORKFLOW ENGINE - Embedded Automation System (v1)
    # Defined here so both TUI relay and MCP can access it
    # ═══════════════════════════════════════════════════════════════
    
    class WorkflowExecutor:
        """Python-native workflow execution engine v2.2.0.

        Executes DAG-based workflows with 10 node types:
        - tool       : Universal node - calls ANY MCP tool by name
        - agent      : Agentic node - plugged model operates granted MCP tools in a loop
        - input      : Workflow entry point (passes $input through)
        - output     : Workflow exit point (collects upstream results)
        - fan_out    : Parallel dispatch via ThreadPoolExecutor
        - http       : HTTP requests (GET, POST, etc.)
        - if         : Conditional branching
        - set        : Data transformation
        - merge      : Branch merging
        - web_search : Web search (Brave, SearXNG, Serper providers)
        """

        def __init__(self, cascade_monitor=None):
            self.cascade = cascade_monitor
            self.node_handlers = {
                "http": self._execute_http,
                "if": self._execute_if,
                "set": self._execute_set,
                "merge": self._execute_merge,
                "tool": self._execute_tool,
                "input": self._execute_input,
                "output": self._execute_output,
                "fan_out": self._execute_fan_out,
                "web_search": self._execute_web_search,
                "agent": self._execute_agent,
            }
            self._execution_state = {}
            self._node_outputs = {}
            self._tool_registry = {}

        def _build_dag(self, workflow: dict) -> tuple:
            """Build DAG from workflow and return execution order.
            
            Returns:
                Tuple of (execution_order, node_map, reverse_connections)
            """
            nodes = workflow.get("nodes", [])
            connections = workflow.get("connections", [])
            
            # Build node map for quick lookup
            node_map = {n["id"]: n for n in nodes}
            
            # Build adjacency list and in-degree count for topological sort
            in_degree = {n["id"]: 0 for n in nodes}
            adjacency = {n["id"]: [] for n in nodes}
            
            # Track connections by target (for merge nodes)
            reverse_connections = {}  # target_id -> [(source_id, branch)]
            
            for conn in connections:
                # Validate required connection fields
                from_id = conn.get("from")
                to_id = conn.get("to")
                if not from_id or not to_id:
                    raise ValueError(f"Invalid connection - missing 'from' or 'to': {conn}")
                branch = conn.get("branch")
                adjacency[from_id].append(to_id)
                in_degree[to_id] += 1
                
                if to_id not in reverse_connections:
                    reverse_connections[to_id] = []
                reverse_connections[to_id].append((from_id, branch))
            
            # Kahn's algorithm for topological sort
            queue = [n for n in in_degree if in_degree[n] == 0]
            execution_order = []
            
            while queue:
                node = queue.pop(0)
                execution_order.append(node)
                for neighbor in adjacency[node]:
                    in_degree[neighbor] -= 1
                    if in_degree[neighbor] == 0:
                        queue.append(neighbor)
            
            # Check for cycles
            if len(execution_order) != len(nodes):
                raise ValueError("Workflow contains cycles - must be a DAG")
            
            return execution_order, node_map, reverse_connections

        def _resolve_ref(self, ref, context):
            """Resolve a single $-expression reference.
            
            Returns resolved value or None if unresolvable.
            """
            import uuid as uuid_mod
            from datetime import datetime
            ref = ref.strip()
            if ref == "$now":
                return datetime.utcnow().isoformat() + "Z"
            elif ref == "$uuid":
                return str(uuid_mod.uuid4())
            elif ref == "$random":
                import random
                return str(random.random())
            try:
                if ref.startswith("$input"):
                    path = ref[6:]
                    if path.startswith("."):
                        path = path[1:]
                    obj = context.get("$input", {})
                    for part in path.split(".") if path else []:
                        _arr = None
                        if '[' in part and part.endswith(']'):
                            _bkt = part.index('[')
                            _istr = part[_bkt+1:-1]
                            if _istr.isdigit():
                                _arr = (part[:_bkt], int(_istr))
                        if _arr and isinstance(obj, dict):
                            obj = obj.get(_arr[0])
                            if isinstance(obj, (list, tuple)):
                                obj = obj[_arr[1]] if _arr[1] < len(obj) else None
                        elif not _arr and isinstance(obj, dict):
                            obj = obj.get(part)
                        else:
                            return None
                        if obj is None:
                            return None
                    return obj
                elif ref.startswith("$node."):
                    parts = ref[6:].split(".")
                    node_id = parts[0]
                    obj = context.get("$node", {}).get(node_id, {})
                    for part in parts[1:]:
                        _arr = None
                        if '[' in part and part.endswith(']'):
                            _bkt = part.index('[')
                            _istr = part[_bkt+1:-1]
                            if _istr.isdigit():
                                _arr = (part[:_bkt], int(_istr))
                        if _arr and isinstance(obj, dict):
                            obj = obj.get(_arr[0])
                            if isinstance(obj, (list, tuple)):
                                obj = obj[_arr[1]] if _arr[1] < len(obj) else None
                        elif not _arr and isinstance(obj, dict):
                            obj = obj.get(part)
                        else:
                            return None
                        if obj is None:
                            return None
                    return obj
                elif ref.startswith("$env."):
                    import os
                    return os.environ.get(ref[5:], "")
            except Exception:
                pass
            return None

        def _resolve_expression(self, expr, context: dict):
            """Resolve $-expressions in a value.
            
            Pass 1: Bare $-expression as entire value (preserves type).
            Pass 2: Inline {{$expr}} wrapped expressions in larger strings.
            """
            import re
            
            if not isinstance(expr, str):
                return expr
            
            # Pass 1: Entire string is a bare $-expression — resolve directly
            stripped = expr.strip()
            if stripped.startswith("$") and " " not in stripped:
                # Handle ${expr} syntax — strip braces
                if stripped.startswith("${") and stripped.endswith("}"):
                    stripped = "$" + stripped[2:-1]
                result = self._resolve_ref(stripped, context)
                if result is not None:
                    return result
            
            # Pass 2: Inline {{...}} wrapped expressions
            pattern = r"\{\{(.+?)\}\}"
            def replace_expr(match):
                inner = match.group(1).strip()
                result = self._resolve_ref(inner, context)
                return str(result) if result is not None else match.group(0)
            
            resolved = re.sub(pattern, replace_expr, expr)
            
            # Pass 3: Inline ${expr} syntax in larger strings
            pattern2 = r"\$\{(.+?)\}"
            def replace_dollar_brace(match):
                inner = "$" + match.group(1).strip()
                result = self._resolve_ref(inner, context)
                return str(result) if result is not None else match.group(0)
            
            resolved = re.sub(pattern2, replace_dollar_brace, resolved)
            return resolved

        def _resolve_dict(self, d: dict, context: dict) -> dict:
            """Recursively resolve expressions in a dict."""
            result = {}
            for k, v in d.items():
                if isinstance(v, dict):
                    result[k] = self._resolve_dict(v, context)
                elif isinstance(v, list):
                    result[k] = [self._resolve_expression(item, context) if isinstance(item, str) else item for item in v]
                else:
                    result[k] = self._resolve_expression(v, context)
            return result
        
        def _validate_params(self, params: dict, context: dict = None) -> tuple[bool, list]:
            """Validate parameters for missing or invalid values.

            Args:
                params: Parameters to validate
                context: Workflow execution context (for diagnostic info)

            Returns:
                Tuple of (is_valid, errors)
            """
            import re as _re
            errors = []
            for key, value in params.items():
                if value is None:
                    errors.append("Parameter '" + str(key) + "' is null")
                elif isinstance(value, str) and value.strip() == "":
                    errors.append("Parameter '" + str(key) + "' is empty")
                elif isinstance(value, str) and "{{" in value:
                    # Extract unresolved {{...}} patterns for diagnostic detail
                    unresolved = _re.findall(r'\{\{(.+?)\}\}', value)
                    if unresolved and context:
                        details = []
                        for expr in unresolved:
                            expr = expr.strip()
                            if expr.startswith("$node."):
                                parts = expr[6:].split(".")
                                node_id = parts[0]
                                requested_key = parts[1] if len(parts) > 1 else "?"
                                node_data = context.get("$node", {}).get(node_id, {})
                                if node_data:
                                    available = sorted(node_data.keys())
                                    details.append("{{$node." + node_id + "." + requested_key + "}} - node '" + node_id + "' has keys: " + str(available))
                                else:
                                    details.append("{{$node." + node_id + "." + requested_key + "}} - node '" + node_id + "' has no outputs (failed or not yet executed)")
                            elif expr.startswith("$input."):
                                field = expr[7:]
                                available_inputs = sorted(context.get("$input", {}).keys())
                                details.append("{{" + expr + "}} - available input fields: " + str(available_inputs))
                            else:
                                details.append("{{" + expr + "}}")
                        errors.append("Parameter '" + str(key) + "' has unresolved: " + "; ".join(details))
                    elif unresolved:
                        errors.append("Parameter '" + str(key) + "' has unresolved expressions: " + ", ".join("{{" + e.strip() + "}}" for e in unresolved))
                    else:
                        errors.append("Parameter '" + str(key) + "' has unresolved expression")
            return len(errors) == 0, errors

        def execute(self, workflow: dict, input_data: dict = None) -> dict:
            """Execute a workflow with input data.

            Args:
                workflow: Workflow definition dict
                input_data: Input data for the workflow

            Returns:
                Execution result dict
            """
            import time
            import uuid
            import os
            from datetime import datetime

            exec_id = f"exec_{uuid.uuid4().hex[:12]}"
            start_time = time.time()
            started_at = datetime.now().isoformat()
            input_data = input_data or {}

            try:
                # Validate workflow structure
                if "nodes" not in workflow or "connections" not in workflow:
                    return {
                        "execution_id": exec_id,
                        "status": "failed",
                        "error": "Invalid workflow: missing nodes or connections",
                        "started_at": started_at
                    }

                # Build DAG and get execution order
                execution_order, node_map, reverse_connections = self._build_dag(workflow)

                # Pre-flight: validate that agent nodes reference populated slots
                try:
                    _si_func = self._tool_registry.get("slot_info")
                    if _si_func:
                        for _nid, _nd in node_map.items():
                            if _nd.get("type") == "agent":
                                _np = _nd.get("parameters", _nd.get("params", {}))
                                _slot = _np.get("slot")
                                if _slot is not None:
                                    try:
                                        _slot = int(_slot)
                                    except (ValueError, TypeError):
                                        continue
                                    _si_raw = _si_func(slot=_slot)
                                    _si = json.loads(_si_raw) if isinstance(_si_raw, str) else _si_raw
                                    if not _si.get("plugged", False):
                                        return {
                                            "execution_id": exec_id,
                                            "status": "failed",
                                            "error": f"Slot {_slot} ({_si.get('name', 'unnamed')}) is empty - plug a model before running this workflow",
                                            "started_at": started_at
                                        }
                except Exception:
                    pass  # Pre-flight is best-effort

                # Initialize context
                context = {
                    "$input": input_data,
                    "$node": {},
                    "$env": dict(os.environ),
                }
                
                # Track node states
                node_states = {}
                final_output = None
                
                # Execute nodes in topological order
                for node_id in execution_order:
                    node = node_map[node_id]
                    node_type = node.get("type")
                    node_start = time.time()
                    
                    # Get handler
                    handler = self.node_handlers.get(node_type)
                    if not handler:
                        return {
                            "execution_id": exec_id,
                            "status": "failed",
                            "error": f"Unknown node type: {node_type}"
                        }
                    
                    # Get inputs from connected nodes
                    inputs = {}
                    incoming = reverse_connections.get(node_id, [])
                    skip_node = False
                    for source_id, branch in incoming:
                        if source_id in context["$node"]:
                            inputs[source_id] = context["$node"][source_id]
                            # Branch gating: if source is an if-node, check branch
                            source_output = context["$node"].get(source_id, {})
                            if isinstance(source_output, dict) and "_branch" in source_output:
                                taken = source_output["_branch"]  # "true" or "false"
                                source_node = node_map.get(source_id, {})
                                src_params = source_node.get("parameters", {})
                                then_target = src_params.get("then")
                                else_target = src_params.get("else")
                                if then_target or else_target:
                                    if taken == "true" and else_target == node_id:
                                        skip_node = True
                                    elif taken == "false" and then_target == node_id:
                                        skip_node = True
                    
                    if skip_node:
                        node_states[node_id] = {"status": "skipped", "elapsed_ms": 0}
                        continue
                    
                    # Execute node with retry logic
                    retry_count = 0
                    max_retries = 3
                    on_error = node.get("on_error", "fail")
                    output = None
                    
                    node_timeout = node.get("timeout", node.get("parameters", {}).get("timeout", 300))
                    try:
                        node_timeout = int(node_timeout)
                    except (ValueError, TypeError):
                        node_timeout = 300

                    while retry_count <= max_retries:
                        try:
                            from concurrent.futures import ThreadPoolExecutor, TimeoutError as FuturesTimeoutError
                            with ThreadPoolExecutor(max_workers=1) as _tex:
                                _future = _tex.submit(handler, node, inputs, context)
                                output = _future.result(timeout=node_timeout)
                            
                            # Handle IF node branching
                            if node_type == "if":
                                branch_result = output.get("branch", "true")
                                output["_branch"] = branch_result
                            
                            # Store output
                            context["$node"][node_id] = output
                            final_output = output
                            
                            # Check if output contains error
                            has_error = False
                            if isinstance(output, dict):
                                has_error = bool(output.get("error"))
                            
                            if has_error:
                                node_states[node_id] = {
                                    "status": "failed",
                                    "elapsed_ms": int((time.time() - node_start) * 1000),
                                    "error": output.get("error", "Unknown error"),
                                    "output_keys": list(output.keys()) if isinstance(output, dict) else None
                                }
                            else:
                                node_states[node_id] = {
                                    "status": "completed",
                                    "elapsed_ms": int((time.time() - node_start) * 1000),
                                    "output_keys": list(output.keys()) if isinstance(output, dict) else None
                                }
                            break
                            
                        except FuturesTimeoutError:
                            _timeout_msg = f"Node {node_id} timed out after {node_timeout}s"
                            if on_error == "skip":
                                output = {"error": _timeout_msg, "skipped": True, "timeout": True}
                                context["$node"][node_id] = output
                                node_states[node_id] = {"status": "timeout", "elapsed_ms": node_timeout * 1000}
                                break
                            else:
                                return {
                                    "execution_id": exec_id,
                                    "status": "failed",
                                    "error": _timeout_msg,
                                    "failed_node": node_id,
                                    "node_states": node_states,
                                    "started_at": started_at,
                                    "elapsed_ms": int((time.time() - start_time) * 1000)
                                }
                        except Exception as e:
                            retry_count += 1
                            if on_error == "retry" and retry_count <= max_retries:
                                import time
                                time.sleep(0.5 * retry_count)  # Exponential backoff
                                continue
                            elif on_error == "skip":
                                output = {"error": str(e), "skipped": True}
                                context["$node"][node_id] = output
                                node_states[node_id] = {"status": "skipped", "error": str(e)}
                                break
                            else:
                                return {
                                    "execution_id": exec_id,
                                    "status": "failed",
                                    "error": f"Node {node_id} failed: {str(e)}",
                                    "failed_node": node_id,
                                    "started_at": started_at,
                                    "elapsed_ms": int((time.time() - start_time) * 1000)
                                }
                
                _any_failed = any(
                    ns.get("status") == "failed"
                    for ns in node_states.values()
                    if isinstance(ns, dict)
                )
                result = {
                    "execution_id": exec_id,
                    "status": "partial_failure" if _any_failed else "completed",
                    "workflow_id": workflow.get("id", "unknown"),
                    "nodes_executed": len(execution_order),
                    "output": final_output,
                    "node_states": node_states,
                    "started_at": started_at,
                    "elapsed_ms": int((time.time() - start_time) * 1000)
                }
                # Save execution history to FelixBag
                try:
                    bag = get_bag()
                    import json as _json
                    bag.induct(
                        name=f"workflow_exec:{workflow.get('id', 'unknown')}:{exec_id}",
                        content=_json.dumps(result, default=str),
                        item_type="workflow_execution",
                        preview=f"Exec {exec_id}: {result.get('status', 'unknown')} ({result.get('elapsed_ms', 0)}ms)"
                    )
                except Exception:
                    pass  # Don't fail execution if history save fails
                # Reward capture for successful workflow execution
                try:
                    _ragent = get_agent()
                    _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
                    _rbrain = getattr(_router, '_brain', _router)
                    if _rbrain and hasattr(_rbrain, '_capture_reward'):
                        _rbrain._capture_reward(source_key='workflow_success', event_id=exec_id, metadata={'workflow_id': workflow.get('id', 'unknown')})
                except Exception:
                    pass
                return result

            except ValueError as e:
                result = {
                    "execution_id": exec_id,
                    "status": "failed",
                    "workflow_id": workflow.get("id", "unknown"),
                    "error": str(e),
                    "started_at": started_at,
                    "elapsed_ms": int((time.time() - start_time) * 1000)
                }
                # Save failed execution history
                try:
                    bag = get_bag()
                    import json as _json
                    bag.induct(
                        name=f"workflow_exec:{workflow.get('id', 'unknown')}:{exec_id}",
                        content=_json.dumps(result, default=str),
                        item_type="workflow_execution",
                        preview=f"Exec {exec_id}: failed - {str(e)[:60]}"
                    )
                except Exception:
                    pass
                try:
                    _ragent = get_agent()
                    _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
                    _rbrain = getattr(_router, '_brain', _router)
                    if _rbrain and hasattr(_rbrain, '_capture_reward'):
                        _rbrain._capture_reward(source_key='workflow_failure', event_id=exec_id, metadata={'workflow_id': workflow.get('id', 'unknown'), 'error': str(e)[:200]})
                except Exception:
                    pass
                return result
            except Exception as e:
                result = {
                    "execution_id": exec_id,
                    "status": "failed",
                    "workflow_id": workflow.get("id", "unknown"),
                    "error": str(e),
                    "started_at": started_at,
                    "elapsed_ms": int((time.time() - start_time) * 1000)
                }
                # Save failed execution history
                try:
                    bag = get_bag()
                    import json as _json
                    bag.induct(
                        name=f"workflow_exec:{workflow.get('id', 'unknown')}:{exec_id}",
                        content=_json.dumps(result, default=str),
                        item_type="workflow_execution",
                        preview=f"Exec {exec_id}: failed - {str(e)[:60]}"
                    )
                except Exception:
                    pass
                try:
                    _ragent = get_agent()
                    _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
                    _rbrain = getattr(_router, '_brain', _router)
                    if _rbrain and hasattr(_rbrain, '_capture_reward'):
                        _rbrain._capture_reward(source_key='workflow_failure', event_id=exec_id, metadata={'workflow_id': workflow.get('id', 'unknown'), 'error': str(e)[:200]})
                except Exception:
                    pass
                return result

        def _execute_http(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute HTTP request node."""
            import requests
            import time
            
            params = node.get("parameters", {})
            method = params.get("method", "GET").upper()
            url = self._resolve_expression(params.get("url", ""), context)
            headers = self._resolve_dict(params.get("headers", {}), context)
            timeout = params.get("timeout", 10)
            response_format = params.get("response_format", "json")
            
            # Resolve body
            body = params.get("body")
            if body:
                if isinstance(body, dict):
                    body = self._resolve_dict(body, context)
                else:
                    body = self._resolve_expression(body, context)
            
            start = time.time()
            
            try:
                if method == "GET":
                    resp = requests.get(url, headers=headers, timeout=timeout)
                elif method == "POST":
                    resp = requests.post(url, json=body, headers=headers, timeout=timeout)
                elif method == "PUT":
                    resp = requests.put(url, json=body, headers=headers, timeout=timeout)
                elif method == "DELETE":
                    resp = requests.delete(url, headers=headers, timeout=timeout)
                elif method == "PATCH":
                    resp = requests.patch(url, json=body, headers=headers, timeout=timeout)
                else:
                    return {"error": f"Unsupported method: {method}"}
                
                result = {
                    "status_code": resp.status_code,
                    "headers": dict(resp.headers),
                    "elapsed_ms": int((time.time() - start) * 1000)
                }
                
                if response_format == "json":
                    try:
                        result["json"] = resp.json()
                    except:
                        result["text"] = resp.text
                elif response_format == "text":
                    result["text"] = resp.text
                else:
                    import base64
                    result["binary"] = base64.b64encode(resp.content).decode()
                
                return result
                
            except requests.exceptions.Timeout:
                return {"error": "Request timeout", "elapsed_ms": int((time.time() - start) * 1000)}
            except Exception as e:
                return {"error": str(e), "elapsed_ms": int((time.time() - start) * 1000)}

        def _execute_if(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute conditional branching node."""
            params = node.get("parameters", {})
            conditions = params.get("conditions", [])
            combine = params.get("combine", "and")
            
            evaluated = []
            results = []
            
            for cond in conditions:
                left = self._resolve_expression(cond.get("left"), context)
                right = self._resolve_expression(cond.get("right"), context)
                operator = cond.get("operator", "==")
                
                # Type coercion
                try:
                    if isinstance(right, (int, float)) and isinstance(left, str):
                        left = float(left) if "." in left else int(left)
                    elif isinstance(left, (int, float)) and isinstance(right, str):
                        right = float(right) if "." in right else int(right)
                except:
                    pass
                
                # Evaluate condition
                result = False
                if operator == "==":
                    result = left == right
                elif operator == "!=":
                    result = left != right
                elif operator == ">":
                    result = left > right
                elif operator == ">=":
                    result = left >= right
                elif operator == "<":
                    result = left < right
                elif operator == "<=":
                    result = left <= right
                elif operator == "contains":
                    result = str(right) in str(left)
                elif operator == "not_contains":
                    result = str(right) not in str(left)
                elif operator == "starts_with":
                    result = str(left).startswith(str(right))
                elif operator == "ends_with":
                    result = str(left).endswith(str(right))
                elif operator == "is_empty":
                    result = left is None or left == "" or left == []
                elif operator == "is_not_empty":
                    result = left is not None and left != "" and left != []
                elif operator == "regex":
                    import re
                    result = bool(re.search(str(right), str(left)))
                
                results.append(result)
                evaluated.append({"left": left, "operator": operator, "right": right, "result": result})
            
            # Combine results
            if combine == "and":
                final_result = all(results) if results else True
            else:  # or
                final_result = any(results) if results else False
            
            return {
                "result": final_result,
                "branch": "true" if final_result else "false",
                "evaluated_conditions": evaluated
            }

        def _execute_set(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute data transformation node."""
            params = node.get("parameters", {})
            values = params.get("values", {})
            mode = params.get("mode", "set")

            # Support key/value shorthand alongside values dict
            if not values and "key" in params and "value" in params:
                values = {params["key"]: params["value"]}

            # Resolve all expressions in values
            resolved = self._resolve_dict(values, context)

            if mode == "set":
                return resolved
            elif mode == "append":
                # Merge with first input
                result = {}
                for source_id, source_data in inputs.items():
                    if isinstance(source_data, dict):
                        result.update(source_data)
                    break
                result.update(resolved)
                return result
            elif mode == "merge":
                # Deep merge
                import copy
                result = {}
                for source_id, source_data in inputs.items():
                    if isinstance(source_data, dict):
                        result = copy.deepcopy(source_data)
                    break
                for k, v in resolved.items():
                    if k in result and isinstance(result[k], dict) and isinstance(v, dict):
                        result[k].update(v)
                    else:
                        result[k] = v
                return result
            
            return resolved

        def _execute_merge(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute branch merge node."""
            params = node.get("parameters", {})
            mode = params.get("mode", "wait_all")
            
            branches = []
            for source_id, source_data in inputs.items():
                branches.append({"branch": source_id, "data": source_data})
            
            if mode == "first":
                # Return first non-error branch
                for b in branches:
                    if not (isinstance(b["data"], dict) and b["data"].get("skipped")):
                        return {
                            "mode": "first",
                            "selected": b["branch"],
                            "data": b["data"]
                        }
                return {"mode": "first", "data": branches[0]["data"] if branches else None}
            
            elif mode == "wait_all":
                return {
                    "mode": "wait_all",
                    "branches": branches,
                    "completed_count": len(branches)
                }
            
            elif mode == "append":
                all_data = []
                for b in branches:
                    if isinstance(b["data"], list):
                        all_data.extend(b["data"])
                    else:
                        all_data.append(b["data"])
                return {"mode": "append", "data": all_data}
            
            elif mode == "combine":
                combined = {}
                for b in branches:
                    if isinstance(b["data"], dict):
                        for k, v in b["data"].items():
                            if k in combined:
                                existing = combined[k]
                                if isinstance(existing, list):
                                    existing.append(v)
                                else:
                                    combined[k] = [existing, v]
                            else:
                                combined[k] = v
                return {"mode": "combine", "data": combined}
            
            return {"branches": branches}

        def _execute_web_search(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute web search node - first-class search across multiple providers.

            Supported providers: brave, searxng, serper
            Parameters:
                provider: Search provider (default: brave)
                query: Search query (supports expression interpolation)
                api_key: API key (or use $env.BRAVE_API_KEY / $env.SERPER_API_KEY)
                count: Number of results (default: 10)
                freshness: Time filter - day, week, month, year (brave/serper only)
                language: Language code e.g. en, es, de (default: en)
            """
            import requests
            import time
            import os

            params = node.get("parameters", {})
            provider = params.get("provider", "brave").lower()
            query = self._resolve_expression(params.get("query", ""), context)
            count = int(params.get("count", 10))
            freshness = params.get("freshness", "")
            language = params.get("language", "en")

            if not query:
                # Auto-wire from upstream if no explicit query
                for source_id, source_data in inputs.items():
                    if isinstance(source_data, dict):
                        query = source_data.get("query", source_data.get("text", source_data.get("output", "")))
                        if query:
                            break
                    elif isinstance(source_data, str):
                        query = source_data
                        break
            if not query:
                return {"error": "No search query provided", "provider": provider}

            # Resolve API key: explicit param > env var
            api_key = self._resolve_expression(params.get("api_key", ""), context)
            if not api_key:
                env_keys = {
                    "brave": "BRAVE_API_KEY",
                    "serper": "SERPER_API_KEY",
                    "searxng": "",
                }
                env_var = env_keys.get(provider, "")
                if env_var:
                    api_key = os.environ.get(env_var, "")

            start = time.time()

            try:
                if provider == "brave":
                    if not api_key:
                        return {"error": "Brave API key required. Set BRAVE_API_KEY env var or pass api_key parameter."}
                    url = "https://api.search.brave.com/res/v1/web/search"
                    req_params = {"q": query, "count": min(count, 20)}
                    if freshness:
                        req_params["freshness"] = freshness
                    if language:
                        req_params["search_lang"] = language
                    resp = requests.get(url, params=req_params,
                                        headers={"Accept": "application/json", "X-Subscription-Token": api_key},
                                        timeout=15)
                    resp.raise_for_status()
                    data = resp.json()
                    web_results = data.get("web", {}).get("results", [])
                    results = [{
                        "title": r.get("title", ""),
                        "url": r.get("url", ""),
                        "snippet": r.get("description", ""),
                        "age": r.get("age", ""),
                    } for r in web_results[:count]]

                elif provider == "searxng":
                    base_url = self._resolve_expression(
                        params.get("base_url", "http://localhost:8888"), context)
                    resp = requests.get(f"{base_url}/search",
                                        params={"q": query, "format": "json", "language": language,
                                                "pageno": 1, "categories": "general"},
                                        timeout=15)
                    resp.raise_for_status()
                    data = resp.json()
                    results = [{
                        "title": r.get("title", ""),
                        "url": r.get("url", ""),
                        "snippet": r.get("content", ""),
                        "engine": r.get("engine", ""),
                    } for r in data.get("results", [])[:count]]

                elif provider == "serper":
                    if not api_key:
                        return {"error": "Serper API key required. Set SERPER_API_KEY env var or pass api_key parameter."}
                    resp = requests.post("https://google.serper.dev/search",
                                         json={"q": query, "num": min(count, 100), "hl": language},
                                         headers={"X-API-KEY": api_key, "Content-Type": "application/json"},
                                         timeout=15)
                    resp.raise_for_status()
                    data = resp.json()
                    results = [{
                        "title": r.get("title", ""),
                        "url": r.get("link", ""),
                        "snippet": r.get("snippet", ""),
                        "position": r.get("position", 0),
                    } for r in data.get("organic", [])[:count]]

                else:
                    return {"error": f"Unknown provider: {provider}. Use brave, searxng, or serper."}

                elapsed = int((time.time() - start) * 1000)
                return {
                    "provider": provider,
                    "query": query,
                    "count": len(results),
                    "results": results,
                    "elapsed_ms": elapsed,
                }

            except requests.exceptions.Timeout:
                return {"error": "Search request timeout", "provider": provider, "elapsed_ms": int((time.time() - start) * 1000)}
            except requests.exceptions.HTTPError as e:
                return {"error": f"HTTP {e.response.status_code}: {e.response.text[:200]}", "provider": provider}
            except Exception as e:
                return {"error": str(e), "provider": provider, "elapsed_ms": int((time.time() - start) * 1000)}

        def _execute_tool(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute universal tool node - calls any MCP tool by name.

            This is the key primitive: any of the capsule's 140+ MCP tools
            becomes a usable workflow node through this single handler.

            Node definition:
                {"type": "tool", "tool_name": "embed_text", "parameters": {"text": "..."}}
            """
            import json
            tool_name = node.get("tool_name", "")
            if not tool_name:
                raise ValueError(f"Tool node '{node['id']}' missing 'tool_name'")

            # Resolve parameters from node definition
            params = node.get("parameters", node.get("params", {}))
            resolved_params = self._resolve_dict(params, context) if params else {}

            # Validate resolved parameters
            if resolved_params:
                _valid, _errs = self._validate_params(resolved_params, context)
                if not _valid:
                    return {"error": "Invalid parameters: " + ", ".join(_errs)}

            # Auto-wire: if no explicit params, merge upstream outputs as parameters
            if inputs and not params:
                for source_id, source_data in inputs.items():
                    if isinstance(source_data, dict):
                        for k, v in source_data.items():
                            if k not in resolved_params:
                                resolved_params[k] = v

            # Look up tool function: registry first, then globals fallback
            tool_func = self._tool_registry.get(tool_name) or globals().get(tool_name)
            if tool_func is None:
                raise ValueError(f"Tool not found: {tool_name}")

            # Bypass logged_tool decorator to avoid caching interference
            # Workflow execution itself is the observable unit
            while hasattr(tool_func, '__wrapped__'):
                tool_func = tool_func.__wrapped__

            # Filter params to match tool signature (prevents auto-wired
            # upstream data from crashing zero-arg or few-arg tools)
            import inspect
            try:
                sig = inspect.signature(tool_func)
                has_var_keyword = any(
                    p.kind == inspect.Parameter.VAR_KEYWORD
                    for p in sig.parameters.values()
                )
                if not has_var_keyword and resolved_params:
                    accepted = set(sig.parameters.keys())
                    resolved_params = {k: v for k, v in resolved_params.items() if k in accepted}
            except (ValueError, TypeError):
                pass  # Can't inspect — pass params as-is

            # Call tool with filtered parameters
            try:
                result_str = tool_func(**resolved_params)
            except TypeError:
                if resolved_params:
                    result_str = tool_func(*resolved_params.values())
                else:
                    raise

            # Parse JSON result - handle LLM responses with markdown + JSON
            if isinstance(result_str, dict):
                return result_str
            if isinstance(result_str, str):
                try:
                    return json.loads(result_str)
                except (json.JSONDecodeError, ValueError):
                    pass
                # Find first valid JSON object in response
                _decoder = json.JSONDecoder()
                _idx = 0
                while _idx < len(result_str):
                    _idx = result_str.find(chr(123), _idx)
                    if _idx == -1:
                        break
                    try:
                        obj, _ = _decoder.raw_decode(result_str, _idx)
                        if isinstance(obj, dict):
                            return obj
                    except (json.JSONDecodeError, ValueError):
                        pass
                    _idx += 1
                return {"result": result_str}
            return {"result": result_str}

        def _execute_agent(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute agent node - plugged model operates granted MCP tools in a loop.

            A plugged model is given a task and a whitelist of MCP tools it can call.
            The model reasons, calls tools, receives results, and loops until it
            produces a final answer or hits max_iterations.

            Node definition:
                {"type": "agent", "parameters": {
                    "slot": 1,
                    "task": "Search memory for X and summarize",
                    "granted_tools": ["bag_search", "embed_text", "get_status"],
                    "max_iterations": 5,
                    "max_tokens": 512
                }}

            Output keys: .final_answer, .iterations, .tool_calls, .slot, .name
            """
            import json

            params = node.get("parameters", node.get("params", {}))
            resolved_params = self._resolve_dict(params, context) if params else {}

            slot_idx = resolved_params.get("slot", 0)
            if isinstance(slot_idx, str):
                try:
                    slot_idx = int(slot_idx)
                except ValueError:
                    slot_idx = 0
            task = resolved_params.get("task", "")
            if not task:
                return {"error": "Agent node requires 'task' parameter"}
            granted_tools = resolved_params.get("granted_tools", [])
            if isinstance(granted_tools, str):
                try:
                    granted_tools = json.loads(granted_tools)
                except (json.JSONDecodeError, ValueError):
                    granted_tools = [t.strip() for t in granted_tools.split(",") if t.strip()]
            if not granted_tools:
                granted_tools = [
                    "get_status", "list_slots", "slot_info", "get_capabilities", "embed_text",
                    "bag_get", "bag_put", "bag_search", "bag_catalog", "bag_induct",
                    "bag_read_doc", "bag_list_docs", "bag_search_docs", "bag_tree",
                    "bag_versions", "bag_diff", "bag_checkpoint", "bag_restore",
                    "workflow_list", "workflow_get", "workflow_status",
                    "cascade_graph", "cascade_chain", "cascade_data", "cascade_system",
                    "cascade_record", "cascade_instrument", "cascade_proxy",
                    "diagnose_file", "diagnose_directory", "symbiotic_interpret",
                    "trace_root_causes", "forensics_analyze", "metrics_analyze",
                ]
            max_iterations = int(resolved_params.get("max_iterations", 5))
            agent_max_tokens = int(resolved_params.get("max_tokens", 0))

            # Validate granted tools (ignore unknown entries instead of hard-failing).
            available_tools = {}
            _unknown_granted_tools = []
            for tool_name in granted_tools:
                tool_func = self._tool_registry.get(tool_name) or globals().get(tool_name)
                if tool_func is None:
                    _unknown_granted_tools.append(tool_name)
                    continue
                while hasattr(tool_func, '__wrapped__'):
                    tool_func = tool_func.__wrapped__
                available_tools[tool_name] = tool_func

            granted_tools = list(available_tools.keys())
            if not granted_tools:
                return {
                    "error": "No valid granted tools available",
                    "unknown_tools": _unknown_granted_tools,
                }

            # Get invoke_slot for model communication
            invoke_func = self._tool_registry.get("invoke_slot") or globals().get("invoke_slot")
            if invoke_func is None:
                return {"error": "invoke_slot not found in tool registry"}
            while hasattr(invoke_func, '__wrapped__'):
                invoke_func = invoke_func.__wrapped__

            # Build tool descriptions for the model prompt
            import inspect
            tool_descriptions = []
            for tname, tfunc in available_tools.items():
                try:
                    sig = inspect.signature(tfunc)
                    sig_parts = []
                    for p in sig.parameters.values():
                        ann = p.annotation.__name__ if p.annotation != inspect.Parameter.empty else "any"
                        part = f"{p.name}: {ann}"
                        if p.default != inspect.Parameter.empty:
                            part += f" = {p.default}"
                        sig_parts.append(part)
                    params_str = ", ".join(sig_parts)
                    doc = (tfunc.__doc__ or "").strip().split("\n")[0]
                    tool_descriptions.append(f"- {tname}({params_str}): {doc}")
                except Exception:
                    tool_descriptions.append(f"- {tname}(): (no signature available)")
            tools_block = "\n".join(tool_descriptions)

            # ── Dynamic context blocks scoped to granted_tools (B13) ──
            context_blocks = []
            _granted_set = set(granted_tools)
            _has_prefix = lambda pfx: any(t.startswith(pfx) for t in _granted_set)
            _has_any = lambda *names: bool(_granted_set & set(names))

            # Identity — always included
            try:
                _id_name = f"slot_{slot_idx}"
                _id_total = 0
                _id_consensus = "bayesian"
                _get_agent_fn = self._tool_registry.get("get_status")
                if _get_agent_fn:
                    import json as _j
                    _st = _j.loads(_get_agent_fn())
                    _id_total = _st.get("slots_filled", 0)
                    _id_consensus = "bayesian"
                try:
                    _brain_ref = None
                    _ga = self._tool_registry.get("get_agent") or globals().get("get_agent")
                    if callable(_ga):
                        _a = _ga()
                        _ob = getattr(_a, '_brain', getattr(_a, 'brain', None))
                        _brain_ref = getattr(_ob, '_brain', _ob)
                    if _brain_ref and hasattr(_brain_ref, 'councilors'):
                        _c = _brain_ref.councilors[slot_idx]
                        _id_name = getattr(_c, 'name', _id_name)
                        _id_total = sum(1 for c in _brain_ref.councilors if getattr(c, 'model', None))
                        _id_consensus = getattr(_brain_ref, 'consensus_method', _id_consensus)
                except Exception:
                    pass
                context_blocks.append(
                    f"IDENTITY: You are {_id_name}, council slot {slot_idx} "
                    f"in an Ouroboros capsule. {_id_total} models active, "
                    f"consensus: {_id_consensus}. Your outputs are provenance-tracked."
                )
            except Exception:
                context_blocks.append(f"IDENTITY: You are an agent in council slot {slot_idx}.")

            # FelixBag
            if _has_prefix("bag_"):
                context_blocks.append(
                    "FELIXBAG: Persistent semantic memory. "
                    "bag_search(query) uses BGE embeddings for semantic search (not keyword). "
                    "bag_put(key, value) stores, bag_get(key) retrieves. "
                    "bag_catalog() lists all items (filterable by type). "
                    "bag_induct(key, content, item_type) adds typed items (text, json, code, workflow). "
                    "bag_read_doc(key) returns full document content and metadata. "
                    "bag_list_docs(prefix/filter_type) lists workspace documents. "
                    "bag_tree(prefix) gives a drillable workspace tree. "
                    "bag_checkpoint(key)/bag_versions(key)/bag_diff(key)/bag_restore(key, checkpoint_key) "
                    "provide document history, differential tracking, and recovery. "
                    "Items persist across sessions."
                )

            # CASCADE
            if _has_prefix("cascade_"):
                context_blocks.append(
                    "CASCADE: Provenance and observability lattice. "
                    "cascade_graph: causal reasoning (add_event, add_link, get_causes, get_effects). "
                    "cascade_chain: merkle-linked provenance (create_chain, add_record, verify). "
                    "cascade_data: PII scanning (pii_scan), schema inference, license analysis. "
                    "cascade_system: log ingestion and format classification. "
                    "cascade_record: tape recording (tape_write, tape_read) and structured logging."
                )

            # Inference
            if _has_any("embed_text", "classify", "rerank", "forward", "infer", "generate"):
                context_blocks.append(
                    "INFERENCE: embed_text(text) returns 384-dim BGE embeddings. "
                    "classify(text) returns labels with confidence (output key: 'output'). "
                    "rerank(query, documents) re-orders by relevance. "
                    "generate(prompt) produces text from a plugged LLM. "
                    "forward(text) runs through the quine brain. "
                    "infer(text) runs full council consensus across all slots."
                )

            # Council
            if _has_any("invoke_slot", "list_slots", "council_status", "slot_info",
                        "broadcast", "compare", "debate", "chain", "all_slots"):
                context_blocks.append(
                    "COUNCIL: Multi-model system, 32 slots. "
                    "invoke_slot(slot, text, mode) calls a model (modes: generate, embed, classify). "
                    "list_slots() shows all slots. compare(input_text) runs through all slots. "
                    "debate(text, rounds) runs multi-round deliberation. "
                    "chain(slot_sequence, text) pipes output sequentially through slots."
                )

            # Workflows
            if _has_prefix("workflow_"):
                context_blocks.append(
                    "WORKFLOWS: DAG automation engine. "
                    "workflow_create(definition) from JSON. "
                    "workflow_execute(workflow_id, input_data) may be restricted by operator policy. "
                    "10 node types: tool (top-level tool_name), agent, input, output, "
                    "fan_out (targets array), http, if (conditions array + then/else), "
                    "set, merge, web_search. "
                    "Data wiring: $input.field, $node.nodeId.key, $env.VAR."
                )

            # HuggingFace
            if _has_prefix("hub_"):
                context_blocks.append(
                    "HUGGINGFACE: hub_search(query) finds models, hub_search_datasets(query) datasets. "
                    "hub_info(model_id) gets details. hub_top(task) gets trending. "
                    "hub_download(model_id) downloads locally. "
                    "hub_plug(model_id) downloads AND plugs into a council slot. "
                    "Use short keywords (1-2 words) for best search results."
                )

            # Diagnostics
            if _has_prefix("diagnose_") or _has_any("symbiotic_interpret", "trace_root_causes",
                                                     "forensics_analyze", "metrics_analyze"):
                context_blocks.append(
                    "DIAGNOSTICS: diagnose_file(path) runs full analysis on Python files. "
                    "symbiotic_interpret(signal) interprets errors and stack traces. "
                    "trace_root_causes(description) traces backwards to root causes. "
                    "forensics_analyze(data) detects patterns and fingerprints. "
                    "metrics_analyze(name, values) detects anomalies and trends."
                )

            # Status
            if _has_any("get_status", "verify_integrity", "verify_hash", "get_capabilities",
                        "get_identity", "get_genesis", "heartbeat"):
                context_blocks.append(
                    "STATUS: get_status() returns generation, fitness, brain type, slot count. "
                    "verify_integrity() checks merkle hash. heartbeat() lightweight alive check. "
                    "get_capabilities() lists all capsule capabilities."
                )

            context_section = "\n\n".join(context_blocks) + "\n\n" if context_blocks else ""

            # ── Ecosystem awareness: other agents + recent activity ──
            try:
                _eco_lines = []
                if _brain_ref and hasattr(_brain_ref, 'councilors'):
                    for _ei, _ec in enumerate(_brain_ref.councilors):
                        if _ei == slot_idx:
                            continue
                        _em = getattr(_ec, 'model', None)
                        if _em is not None:
                            _ename = getattr(_ec, 'name', f'slot_{_ei}')
                            _esrc = getattr(_ec, '_model_source', 'unknown')
                            _etype = getattr(_ec, '_model_type', 'generic')
                            _eco_lines.append(f"  Slot {_ei}: {_ename} ({_etype}, {_esrc})")
                if _eco_lines:
                    context_blocks.append(
                        "ECOSYSTEM: Other active agents in the council:\n"
                        + "\n".join(_eco_lines)
                        + "\nUse bag_search to find their recent work. "
                        "Use invoke_slot(slot, text) to delegate to them."
                    )
            except Exception:
                pass

            # ── Operational envelope: denied tools + constraints ──
            try:
                _all_registered = set(self._tool_registry.keys())
                _denied = sorted(_all_registered - _granted_set - {"get_agent"})
                if len(_denied) > 0 and len(_denied) <= 30:
                    context_blocks.append(
                        f"BOUNDARIES: You have {len(granted_tools)} granted tools. "
                        f"You do NOT have access to: {', '.join(_denied[:15])}."
                        + (" (and more)" if len(_denied) > 15 else "")
                        + f" Max iterations: {max_iterations}."
                    )
                elif len(_denied) > 30:
                    context_blocks.append(
                        f"BOUNDARIES: You have {len(granted_tools)} granted tools out of {len(_all_registered)} total. "
                        f"Only use tools listed in AVAILABLE TOOLS above. "
                        f"Max iterations: {max_iterations}."
                    )
            except Exception:
                pass

            # ── Recent FelixBag activity for cross-agent coordination ──
            try:
                _bag_fn = self._tool_registry.get("bag_catalog")
                if _bag_fn and _has_prefix("bag_"):
                    _cat_raw = _bag_fn()
                    _cat = json.loads(_cat_raw) if isinstance(_cat_raw, str) else _cat_raw
                    _items = _cat.get("items", [])
                    _recent_sessions = [
                        it for it in _items
                        if isinstance(it, (list, tuple)) and len(it) >= 2
                        and (str(it[1]).startswith("agent_session:") or str(it[1]).startswith("workflow_exec:"))
                    ][-5:]
                    if _recent_sessions:
                        _sess_lines = [f"  {it[1]}" for it in _recent_sessions]
                        context_blocks.append(
                            "RECENT ACTIVITY:\n" + "\n".join(_sess_lines)
                            + "\nUse bag_get(key) to inspect any of these."
                        )
            except Exception:
                pass

            context_section = "\n\n".join(context_blocks) + "\n\n" if context_blocks else ""
            upstream_context = ""
            for source_id, source_data in inputs.items():
                if isinstance(source_data, dict):
                    for k, v in source_data.items():
                        if k not in ("error", "skipped", "_branch"):
                            val_str = str(v)[:500] if not isinstance(v, str) else v[:500]
                            upstream_context += f"\n{k}: {val_str}"

            system_prompt = (
                f"{context_section}"
                "You are an AI agent operating inside an Ouroboros workflow node. "
                "You have access to ONLY the tools listed below. "
                "Respond with EXACTLY ONE JSON object per turn.\n\n"
                f"AVAILABLE TOOLS:\n{tools_block}\n\n"
                "To call a tool, respond with:\n"
                '{"tool": "tool_name", "args": {"param": "value"}}\n\n'
                "When you have completed the task, respond with:\n"
                '{"final_answer": "your complete answer here"}\n\n'
                "Rules:\n"
                "- Call ONE tool at a time\n"
                "- Wait for the result before calling another\n"
                "- Use ONLY the tools listed above\n"
                "- Always end with a final_answer"
            )

            full_task = f"TASK: {task}"
            if upstream_context:
                full_task += f"\n\nCONTEXT FROM PREVIOUS NODES:{upstream_context}"

            # Agent loop - structured message list
            chat_messages = [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": full_task},
            ]
            tool_calls_log = []
            final_answer = None
            slot_name = f"slot_{slot_idx}"
            iterations_used = 0
            _last_iteration_nudge = "This is your LAST iteration. You MUST respond with {\"final_answer\": \"your answer\"} now."

            for iteration in range(max_iterations):
                iterations_used = iteration + 1
                # Nudge on penultimate iteration
                if iteration == max_iterations - 1:
                    if chat_messages and chat_messages[-1].get("role") == "user":
                        chat_messages[-1]["content"] = str(chat_messages[-1].get("content", "")) + "\n\n" + _last_iteration_nudge
                    else:
                        chat_messages.append({
                            "role": "user",
                            "content": _last_iteration_nudge
                        })

                try:
                    _invoke_kwargs = {"slot": slot_idx, "text": full_task, "mode": "generate", "messages": chat_messages}
                    if agent_max_tokens > 0:
                        _invoke_kwargs["max_tokens"] = agent_max_tokens
                    result_str = invoke_func(**_invoke_kwargs)
                    result = json.loads(result_str) if isinstance(result_str, str) else result_str
                except Exception as e:
                    return {
                        "error": f"Model invocation failed: {str(e)}",
                        "slot": slot_idx,
                        "iterations": iterations_used,
                        "tool_calls": tool_calls_log,
                    }

                if not isinstance(result, dict):
                    return {
                        "error": f"Model invocation returned non-dict response: {type(result).__name__}",
                        "slot": slot_idx,
                        "iterations": iterations_used,
                        "tool_calls": tool_calls_log,
                    }
                if result.get("status") == "error" or result.get("error"):
                    return {
                        "error": "Model invocation failed: " + str(result.get("error", "unknown error")),
                        "slot": slot_idx,
                        "iterations": iterations_used,
                        "tool_calls": tool_calls_log,
                        "name": result.get("name", slot_name),
                    }

                model_output = result.get("output", "")
                slot_name = result.get("name", slot_name)

                # Append model response as assistant message
                chat_messages.append({"role": "assistant", "content": model_output})

                # Parse model output as JSON
                parsed = None
                if isinstance(model_output, str):
                    try:
                        parsed = json.loads(model_output.strip())
                    except (json.JSONDecodeError, ValueError):
                        pass
                    if parsed is None:
                        _decoder = json.JSONDecoder()
                        _scan = 0
                        while _scan < len(model_output):
                            _scan = model_output.find(chr(123), _scan)
                            if _scan == -1:
                                break
                            try:
                                obj, _ = _decoder.raw_decode(model_output, _scan)
                                if isinstance(obj, dict) and ("tool" in obj or "final_answer" in obj):
                                    parsed = obj
                                    break
                            except (json.JSONDecodeError, ValueError):
                                pass
                            _scan += 1

                if parsed is None:
                    final_answer = model_output if isinstance(model_output, str) and model_output.strip() else "Model returned an empty response."
                    break

                if "final_answer" in parsed:
                    final_answer = parsed["final_answer"]
                    break

                if "tool" in parsed:
                    called_tool = parsed["tool"]
                    called_args = parsed.get("args", {})

                    if called_tool not in available_tools:
                        chat_messages.append({
                            "role": "user",
                            "content": f"Tool '{called_tool}' is NOT in your granted tools. Available: {', '.join(granted_tools)}. Try again."
                        })
                        tool_calls_log.append({
                            "tool": called_tool, "args": called_args,
                            "result": "DENIED - not in granted_tools",
                            "iteration": iteration,
                        })
                        continue

                    tool_func = available_tools[called_tool]
                    try:
                        try:
                            sig = inspect.signature(tool_func)
                            has_var_kw = any(
                                p.kind == inspect.Parameter.VAR_KEYWORD
                                for p in sig.parameters.values()
                            )
                            if not has_var_kw and called_args:
                                accepted = set(sig.parameters.keys())
                                called_args = {k: v for k, v in called_args.items() if k in accepted}
                        except (ValueError, TypeError):
                            pass

                        tool_result = tool_func(**called_args)
                        if isinstance(tool_result, str):
                            try:
                                tool_result_parsed = json.loads(tool_result)
                                tool_result_str = json.dumps(tool_result_parsed, indent=2, default=str)
                            except (json.JSONDecodeError, ValueError):
                                tool_result_str = tool_result
                        else:
                            tool_result_str = json.dumps(tool_result, indent=2, default=str)
                    except Exception as e:
                        tool_result_str = f"ERROR: {str(e)}"

                    tool_calls_log.append({
                        "tool": called_tool, "args": called_args,
                        "result": tool_result_str[:500],
                        "iteration": iteration,
                    })

                    # Append tool result as user message (proper role separation)
                    chat_messages.append({
                        "role": "user",
                        "content": f"Tool result for {called_tool}({json.dumps(called_args, default=str)}):\n{tool_result_str}\n\nContinue with your next tool call or provide your final_answer."
                    })
                else:
                    final_answer = json.dumps(parsed, default=str)
                    break

            if final_answer is None:
                final_answer = f"Agent reached max iterations ({max_iterations}) without final answer."

            _agent_result = {
                "final_answer": final_answer,
                "iterations": iterations_used,
                "tool_calls": tool_calls_log,
                "slot": slot_idx,
                "name": slot_name,
            }

            # ── Persist session trace to FelixBag ──
            try:
                import time as _sess_time
                _bag_fn = self._tool_registry.get("bag_induct")
                if _bag_fn:
                    _ts = int(_sess_time.time())
                    _sess_key = f"agent_session:{slot_idx}:{_ts}"
                    _sess_data = json.dumps({
                        "slot": slot_idx,
                        "name": slot_name,
                        "task": task,
                        "final_answer": final_answer[:1000] if isinstance(final_answer, str) else str(final_answer)[:1000],
                        "iterations": iterations_used,
                        "tool_calls": tool_calls_log,
                        "granted_tools": granted_tools,
                        "timestamp": _ts,
                    }, default=str)
                    _bag_fn(key=_sess_key, content=_sess_data, item_type="agent_session")
            except Exception:
                pass

            return _agent_result

        def _execute_input(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute input node - workflow entry point.

            Passes the workflow's $input data through to downstream nodes.
            """
            return dict(context.get("$input", {}))

        def _execute_output(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute output node - workflow exit point.

            Collects all upstream inputs into a single result dict.
            """
            result = {}
            for source_id, source_data in inputs.items():
                if isinstance(source_data, dict):
                    result.update(source_data)
                else:
                    result[source_id] = source_data
            return result

        def _execute_fan_out(self, node: dict, inputs: dict, context: dict) -> dict:
            """Execute fan_out node - parallel dispatch to multiple tool targets.

            Runs multiple tool invocations concurrently using ThreadPoolExecutor.
            Each target specifies a tool_name and parameters.

            Node definition:
                {
                    "type": "fan_out",
                    "targets": [
                        {"id": "embed1", "tool_name": "embed_text", "params": {"text": "..."}},
                        {"id": "embed2", "tool_name": "embed_text", "params": {"text": "..."}}
                    ]
                }
            """
            import json
            import concurrent.futures

            targets = node.get("targets", [])
            if not targets:
                raise ValueError(f"Fan_out node '{node['id']}' has no targets")

            # Collect input from upstream nodes
            fan_input = {}
            for source_id, source_data in inputs.items():
                if isinstance(source_data, dict):
                    fan_input.update(source_data)
                else:
                    fan_input[source_id] = source_data

            def _run_target(target):
                tool_name = target.get("tool_name", "")
                params = target.get("parameters", target.get("params", {}))
                resolved = self._resolve_dict(params, context) if params else dict(fan_input)
                
                # Validate resolved parameters
                is_valid, errors = self._validate_params(resolved, context)
                if not is_valid:
                    return target.get("id", tool_name), {"error": "Invalid parameters: " + ", ".join(errors)}

                tool_func = self._tool_registry.get(tool_name) or globals().get(tool_name)
                if tool_func is None:
                    return target.get("id", tool_name), {"error": f"Tool not found: {tool_name}"}

                # Bypass logged_tool decorator
                while hasattr(tool_func, '__wrapped__'):
                    tool_func = tool_func.__wrapped__

                # Filter params to match tool signature
                import inspect
                try:
                    sig = inspect.signature(tool_func)
                    has_var_kw = any(p.kind == inspect.Parameter.VAR_KEYWORD for p in sig.parameters.values())
                    if not has_var_kw and resolved:
                        accepted = set(sig.parameters.keys())
                        resolved = {k: v for k, v in resolved.items() if k in accepted}
                except (ValueError, TypeError):
                    pass

                try:
                    result_str = tool_func(**resolved)
                    if isinstance(result_str, dict):
                        return target.get("id", tool_name), result_str
                    if isinstance(result_str, str):
                        try:
                            return target.get("id", tool_name), json.loads(result_str)
                        except (json.JSONDecodeError, ValueError):
                            _dec = json.JSONDecoder()
                            _idx = 0
                            while _idx < len(result_str):
                                _idx = result_str.find(chr(123), _idx)
                                if _idx == -1:
                                    break
                                try:
                                    _obj, _ = _dec.raw_decode(result_str, _idx)
                                    if isinstance(_obj, dict):
                                        return target.get("id", tool_name), _obj
                                except (json.JSONDecodeError, ValueError):
                                    pass
                                _idx += 1
                    return target.get("id", tool_name), {"result": result_str}
                except Exception as e:
                    return target.get("id", tool_name), {"error": str(e)}

            results = {}
            with concurrent.futures.ThreadPoolExecutor(max_workers=min(len(targets), 16)) as executor:
                futures = {executor.submit(_run_target, t): t for t in targets}
                for future in concurrent.futures.as_completed(futures):
                    tid, result = future.result()
                    results[tid] = result

            # Propagate target failures to node level
            _failed = {t: r.get("error") for t, r in results.items() if isinstance(r, dict) and r.get("error")}
            if _failed:
                results["error"] = str(len(_failed)) + "/" + str(len(targets)) + " targets failed"
                results["failed_targets"] = _failed
            return results

    # Global workflow executor singleton
    _workflow_executor = None

    def get_workflow_executor():
        """Get or create the global WorkflowExecutor instance."""
        global _workflow_executor
        if _workflow_executor is None:
            _workflow_executor = WorkflowExecutor()
        return _workflow_executor

    # ═══════════════════════════════════════════════════════════════
    # WORKFLOW FUNCTIONS - Standalone implementations for TUI/MCP parity
    # ═══════════════════════════════════════════════════════════════

    def workflow_test() -> str:
        """Test that the workflow engine is operational."""
        import json
        executor = get_workflow_executor()
        return json.dumps({
            "status": "ok",
            "engine": "WorkflowExecutor",
            "version": "2.2.0",
            "node_types": list(executor.node_handlers.keys()),
            "features": ["universal_tool_nodes", "parallel_fan_out", "auto_wire_inputs", "execution_history", "web_search"]
        })

    def workflow_execute(workflow_id: str, input_data: str = "") -> str:
        """Execute a workflow by ID."""
        import json
        workflow_key = f"workflow:{workflow_id}"
        bag = get_bag()
        workflow_json = bag.get(workflow_key)

        if workflow_json is None:
            return json.dumps({
                "error": f"Workflow not found: {workflow_id}",
                "hint": "Use workflow_list to see available workflows"
            })

        try:
            workflow = json.loads(workflow_json) if isinstance(workflow_json, str) else workflow_json
            inputs = json.loads(input_data) if input_data else {}
        except json.JSONDecodeError as e:
            return json.dumps({"error": f"Invalid JSON: {str(e)}"})

        executor = get_workflow_executor()
        result = executor.execute(workflow, inputs)
        return json.dumps(result, default=str)

    def workflow_list() -> str:
        """List all available workflows."""
        import json
        bag = get_bag()
        workflows = []

        try:
            # catalog() returns list of tuples: (id, name, type, preview, size, version)
            catalog_items = bag.catalog() if hasattr(bag, "catalog") else []
            for item in catalog_items:
                # item is tuple: (id, name, type, preview, size, version)
                if len(item) >= 2:
                    item_name = item[1]  # name is second element
                    if item_name.startswith("workflow:") and not item_name.startswith("workflow_exec:"):
                        try:
                            wf_json = bag.get(item_name)
                            if wf_json:
                                wf = json.loads(wf_json) if isinstance(wf_json, str) else wf_json
                                workflows.append({
                                    "id": wf.get("id", item_name.replace("workflow:", "")),
                                    "name": wf.get("name", "Unnamed"),
                                    "description": wf.get("description", ""),
                                    "node_count": len(wf.get("nodes", []))
                                })
                        except:
                            pass
        except Exception:
            pass

        return json.dumps({
            "workflows": workflows,
            "count": len(workflows)
        })

    def workflow_create(definition: str) -> str:
        """Create a new workflow from JSON definition."""
        import json
        try:
            workflow = json.loads(definition)
        except json.JSONDecodeError as e:
            return json.dumps({"error": f"Invalid JSON: {str(e)}"})

        if "id" not in workflow:
            return json.dumps({"error": "Workflow must have an 'id' field"})
        if "nodes" not in workflow:
            return json.dumps({"error": "Workflow must have a 'nodes' array"})
        if "connections" not in workflow:
            return json.dumps({"error": "Workflow must have a 'connections' array"})

        bag = get_bag()
        workflow_key = f"workflow:{workflow['id']}"
        workflow_json = json.dumps(workflow)
        
        # Use induct for proper FelixBag storage with catalog support
        bag.induct(
            name=workflow_key,
            content=workflow_json,
            item_type="workflow",
            preview=f"Workflow: {workflow.get('name', workflow['id'])} ({len(workflow.get('nodes', []))} nodes)"
        )

        return json.dumps({
            "status": "created",
            "id": workflow["id"],
            "name": workflow.get("name", "Unnamed"),
            "node_count": len(workflow.get("nodes", []))
        })

    def workflow_get(workflow_id: str) -> str:
        """Get a workflow definition by ID."""
        import json
        bag = get_bag()
        workflow_key = f"workflow:{workflow_id}"
        workflow_json = bag.get(workflow_key)

        if workflow_json is None:
            return json.dumps({"error": f"Workflow not found: {workflow_id}"})

        try:
            workflow = json.loads(workflow_json) if isinstance(workflow_json, str) else workflow_json
            return json.dumps(workflow)
        except Exception as e:
            return json.dumps({"error": str(e)})

    def workflow_update(workflow_id: str, definition: str) -> str:
        """Update an existing workflow."""
        import json
        bag = get_bag()
        workflow_key = f"workflow:{workflow_id}"

        if bag.get(workflow_key) is None:
            return json.dumps({"error": f"Workflow not found: {workflow_id}"})

        try:
            workflow = json.loads(definition)
            workflow["id"] = workflow_id
            workflow_json = json.dumps(workflow)
            
            # Use induct for proper FelixBag storage with catalog support
            bag.induct(
                name=workflow_key,
                content=workflow_json,
                item_type="workflow",
                preview=f"Workflow: {workflow.get('name', workflow_id)} ({len(workflow.get('nodes', []))} nodes)"
            )
                
            return json.dumps({
                "status": "updated",
                "id": workflow_id,
                "name": workflow.get("name", "Unnamed")
            })
        except json.JSONDecodeError as e:
            return json.dumps({"error": f"Invalid JSON: {str(e)}"})

    def workflow_delete(workflow_id: str) -> str:
        """Delete a workflow by ID."""
        import json
        bag = get_bag()
        workflow_key = f"workflow:{workflow_id}"

        if bag.get(workflow_key) is None:
            return json.dumps({"error": f"Workflow not found: {workflow_id}"})

        # Find item by name and delete by its internal item_id
        deleted = False
        for iid, item in list(bag._bag.items()):
            if item.get('name') == workflow_key:
                bag.forget(iid)
                deleted = True
                break
        if not deleted:
            bag.forget(workflow_key)

        return json.dumps({
            "status": "deleted",
            "id": workflow_id
        })

    def workflow_history(workflow_id: str, limit: int = 10) -> str:
        """Get execution history for a workflow."""
        import json
        bag = get_bag()
        executions = []

        try:
            # catalog() returns list of tuples: (id, name, type, preview, size, version)
            catalog_items = bag.catalog() if hasattr(bag, "catalog") else []
            for item in catalog_items:
                if len(item) >= 2:
                    item_name = item[1]  # name is second element
                    if item_name.startswith("workflow_exec:") and workflow_id in item_name:
                        try:
                            exec_data = bag.get(item_name)
                            if exec_data:
                                if isinstance(exec_data, str):
                                    exec_data = json.loads(exec_data)
                                if exec_data.get("workflow_id") == workflow_id:
                                    executions.append(exec_data)
                        except:
                            pass
        except:
            pass

        executions.sort(key=lambda x: x.get("started_at", ""), reverse=True)
        executions = executions[:limit]

        return json.dumps({
            "workflow_id": workflow_id,
            "executions": executions,
            "count": len(executions)
        })

    def workflow_status(execution_id: str) -> str:
        """Get status of a workflow execution."""
        import json
        bag = get_bag()
        # Search by execution_id in item names (name format: workflow_exec:wf_id:exec_id)
        exec_data = None
        try:
            for iid, item in bag._bag.items():
                if execution_id in item.get('name', ''):
                    exec_data = bag.get(iid)
                    break
        except Exception:
            pass

        if exec_data is None:
            return json.dumps({"error": f"Execution not found: {execution_id}"})

        try:
            if isinstance(exec_data, str):
                exec_data = json.loads(exec_data)
            return json.dumps(exec_data)
        except Exception as e:
            return json.dumps({"error": str(e)})

    def _cleanup_old_capsule_processes():
        """Kill old Python processes that may be holding MCP port or stale capsule instances."""
        import os
        import subprocess
        import sys
        current_pid = os.getpid()
        
        try:
            # Find processes listening on MCP port 8765
            if sys.platform == 'win32':
                result = subprocess.run(
                    ['netstat', '-ano'], capture_output=True, text=True, timeout=5
                )
                for line in result.stdout.split('\n'):
                    if ':8765' in line and 'LISTENING' in line:
                        parts = line.split()
                        if parts:
                            try:
                                pid = int(parts[-1])
                                if pid != current_pid:
                                    subprocess.run(['taskkill', '/F', '/PID', str(pid)], 
                                                   capture_output=True, timeout=5)
                            except (ValueError, subprocess.TimeoutExpired):
                                pass
            else:
                # Unix: use lsof
                result = subprocess.run(
                    ['lsof', '-ti', ':8765'], capture_output=True, text=True, timeout=5
                )
                for pid_str in result.stdout.strip().split('\n'):
                    if pid_str:
                        try:
                            pid = int(pid_str)
                            if pid != current_pid:
                                os.kill(pid, 9)
                        except (ValueError, ProcessLookupError):
                            pass
        except Exception:
            pass  # Silently ignore cleanup failures
    
    # Run cleanup on module load
    _cleanup_old_capsule_processes()

