        def on_worker_state_changed(self, event):
            """Handle worker completion - call stored callback with result."""
            if event.state == WorkerState.SUCCESS:
                worker_name = event.worker.name
                if worker_name in self._worker_callbacks:
                    callback = self._worker_callbacks.pop(worker_name)
                    self._hide_loading()  # Hide spinner on completion
                    try:
                        callback(event.worker.result)
                    except Exception as e:
                        self._log(f"⚠️ Worker callback error: {e}")
            elif event.state == WorkerState.ERROR:
                worker_name = event.worker.name
                if worker_name in self._worker_callbacks:
                    self._worker_callbacks.pop(worker_name)
                    self._hide_loading()  # Hide spinner on error
                    self._log(f"❌ Worker {worker_name} failed: {event.worker.error}")
        
        def _log(self, msg: str):
            """Write plain text to log widget AND file."""
            try:
                log = self.query_one("#log", Log)
                log.write_line(msg)
            except Exception:
                pass
            # Always write to file
            try:
                with open(self._log_file, 'a', encoding='utf-8') as f:
                    f.write(f"{msg}\n")
            except Exception:
                pass
        
        def _mcp_log(self, msg: str):
            """Log to MCP tab."""
            try:
                mcp_log = self.query_one("#mcp-log", Log)
                mcp_log.write_line(msg)
            except Exception:
                pass
        
        async def _watch_mcp_log(self):
            """Watch MCP log file and display in MCP tab."""
            import asyncio
            mcp_log_path = Path(__file__).parent / '.mcp_server.log'
            last_size = 0
            
            while True:
                try:
                    if mcp_log_path.exists():
                        current_size = mcp_log_path.stat().st_size
                        if current_size > last_size:
                            # Read new content
                            with open(mcp_log_path, 'r', encoding='utf-8', errors='replace') as f:
                                f.seek(last_size)
                                new_content = f.read()
                            last_size = current_size
                            # Display in MCP tab
                            for line in new_content.strip().split('\n'):
                                if line.strip():
                                    self._mcp_log(line)
                except Exception:
                    pass
                await asyncio.sleep(0.3)
        
        async def _watch_relay_center(self):
            """
            🎛️ RELAY CENTER WATCHER
            
            Agent writes commands to .relay_center.cmd
            TUI picks them up and executes them live.
            You watch your TUI, agent drives from its terminal.
            
            ROBUST PARSING:
            - Handles commands appended without leading newlines
            - Detects known command prefixes even when concatenated
            - Tracks processed commands by hash to allow repeats
            - Normalizes Windows/Unix line endings
            """
            import asyncio
            import re
            import hashlib
            
            last_mtime = 0
            processed_hashes = set()  # Track processed commands by hash+timestamp
            
            # Known command prefixes that can appear concatenated
            COMMAND_PREFIXES = [
                'vast ', 'hub ', 'plug ', 'unplug', 'status', 'help', 'slots',
                'embed ', 'imagine', 'deliberate ', 'council ', 'bag ',
                'to ', 'pipe ', 'broadcast ', 'who',
                'infer', 'cascade', 'observe', 'save', 'implode', 'defrost',
                'quickstart', 'about', 'provenance', 'lineage', 'heartbeat',
                'hash', 'capabilities', 'caps', 'compare', 'verify', 'pocket',
                'catalog', 'workflow '
            ]
            
            def extract_commands(text):
                """Extract commands even if concatenated without newlines."""
                # Normalize line endings
                text = text.replace('\r\n', '\n').replace('\r', '\n')
                
                # Split by newlines first
                lines = text.split('\n')
                commands = []
                
                for line in lines:
                    line = line.strip()
                    if not line or line.startswith('#'):
                        continue
                    
                    # Check if line contains concatenated commands
                    # e.g. "vast search x>=1vast search y>=2vast search z>=3"
                    remaining = line
                    while remaining:
                        found_cmd = False
                        for prefix in COMMAND_PREFIXES:
                            # Find second occurrence of prefix (first could be at start)
                            first_pos = remaining.lower().find(prefix.lower())
                            if first_pos == 0:
                                # Command at start, look for next command
                                second_pos = -1
                                for p in COMMAND_PREFIXES:
                                    pos = remaining.lower().find(p.lower(), len(prefix))
                                    if pos > 0 and (second_pos == -1 or pos < second_pos):
                                        second_pos = pos
                                
                                if second_pos > 0:
                                    # Found concatenated commands
                                    cmd = remaining[:second_pos].strip()
                                    if len(cmd) > 2:
                                        commands.append(cmd)
                                    remaining = remaining[second_pos:]
                                    found_cmd = True
                                    break
                                else:
                                    # Single command on this line
                                    if len(remaining) > 2:
                                        commands.append(remaining)
                                    remaining = ''
                                    found_cmd = True
                                    break
                        
                        if not found_cmd:
                            # No known prefix at start - treat whole thing as command
                            if len(remaining) > 2:
                                commands.append(remaining)
                            remaining = ''
                
                return commands
            
            while self._relay_listening:
                try:
                    if self._relay_center.exists():
                        # Check if file was modified
                        current_mtime = self._relay_center.stat().st_mtime
                        if current_mtime != last_mtime:
                            # File changed - wait for write to complete (debounce)
                            await asyncio.sleep(0.3)
                            last_mtime = self._relay_center.stat().st_mtime
                            
                            content = self._relay_center.read_text(encoding='utf-8')
                            
                            # Extract commands (handles concatenation)
                            commands = extract_commands(content)
                            
                            # Process each command (only if not already processed)
                            for cmd in commands:
                                # Hash includes timestamp bucket to allow re-runs
                                time_bucket = int(current_mtime * 10)  # 100ms granularity
                                cmd_hash = hashlib.md5(f"{cmd}:{time_bucket}".encode()).hexdigest()[:12]
                                
                                if cmd_hash not in processed_hashes:
                                    processed_hashes.add(cmd_hash)
                                    # Keep hash set bounded
                                    if len(processed_hashes) > 1000:
                                        processed_hashes.clear()
                                    
                                    self._log(f"🤖 RELAY: {cmd}")
                                    await self.on_input_submitted(
                                        type('E', (), {'value': cmd, 'input': type('I', (), {'value': ''})})()
                                    )
                            
                            # After processing, keep only comments (instructions)
                            # and ensure file ends with newline for clean appends
                            lines = content.replace('\r\n', '\n').replace('\r', '\n').split('\n')
                            comment_lines = [line for line in lines if not line.strip() or line.strip().startswith('#')]
                            
                            # Ensure trailing newline for clean appends
                            clean_content = '\n'.join(comment_lines)
                            if clean_content and not clean_content.endswith('\n'):
                                clean_content += '\n'
                            
                            self._relay_center.write_text(clean_content, encoding='utf-8')
                    
                    # UNIVERSAL SIGNAL PORT - check for external signals
                    await self._check_signal_port()
                    
                    # ═══════════════════════════════════════════════════════════
                    # MCP REQUEST BUS - Handle pending requests from MCP proxy
                    # Fast path: check inbox existence (no JSON parse if empty)
                    # ═══════════════════════════════════════════════════════════
                    await self._handle_mcp_request()
                    
                    # HEARTBEAT - Update state file every 10 seconds so proxy mode knows we're alive
                    if not hasattr(self, '_last_heartbeat'):
                        self._last_heartbeat = 0
                    import time as _hb_time
                    if _hb_time.time() - self._last_heartbeat > 10:
                        self._write_capsule_state()
                        self._last_heartbeat = _hb_time.time()
                    
                except Exception as e:
                    self._log(f"❌ RELAY ERROR: {e}")
                await asyncio.sleep(0.1)  # 100ms loop - responsive to MCP
        
        def compose(self):
            yield Header(show_clock=True)
            with Horizontal():
                # LEFT SIDEBAR - Status + Slots
                with Vertical(id="sidebar"):
                    yield Static(self._render_info(), id="info")
                    yield MetricsWidget(id="metrics")
                    yield HoldWidget(id="hold")
                    yield MerkleWidget(id="merkle")
                    with ScrollableContainer(id="slots"):
                        # Show slots for ANY brain with all_members (Council OR Scarecrow)
                        members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
                        if members:
                            # Show filled slots first, then collapsed empty count
                            filled = []
                            empty_count = 0
                            for i, c in enumerate(members):
                                has = getattr(c, 'model', None) is not None
                                if has:
                                    name = getattr(c, 'name', f'slot_{i}')
                                    mid = getattr(c, '_model_source', None)
                                    clones = len(getattr(c, '_clones', []))
                                    filled.append((i, name, mid, clones))
                                else:
                                    empty_count += 1
                            # Yield filled slots
                            for i, name, mid, clones in filled:
                                yield SlotWidget(i, name, 'plugged', mid, clones, id=f"slot-{i}")
                            # Show empty slots - different for Scarecrow vs Council vs Ouroboros
                            if empty_count > 0:
                                if self.brain_type == 'scarecrow':
                                    # Scarecrow: prominent NULL PORT indicator
                                    yield Static("[bold yellow]⚫ NULL PORT[/bold yellow]\n[dim]plug <model> to activate[/]\n[dim]e.g: plug bge-small-en-v1.5[/]")
                                elif self.is_ouroboros:
                                    # Ouroboros: show multi-modal plugging options
                                    yield Static(f"[bold magenta]🐍 {empty_count} PORTS AVAILABLE[/bold magenta]\n[dim]plug <model> <slot>[/]\n[dim]e.g: plug bge-small-en-v1.5 0[/]")
                                else:
                                    # Council: collapsed empty count (no ID to avoid conflicts on refresh)
                                    yield Static(f"[dim]⚫ {empty_count} empty slots[/] [dim](plug <model>)[/]")
                        else:
                            # No members - Ouroboros should still show plugging zone
                            if self.is_ouroboros:
                                yield Static("[bold magenta]🐍 OUROBOROS READY[/bold magenta]\n[dim]plug dreamer <model>[/]\n[dim]plug embedding <model>[/]\n[dim]plug councilor <model> <slot>[/]")
                
                # MAIN AREA - Tabbed content
                with Vertical(id="main"):
                    with TabbedContent(id="tabs"):
                        with TabPane("📜 Log", id="tab-log"):
                            yield Log(id="log", highlight=True, classes="tab-log")
                        with TabPane("🔌 MCP", id="tab-mcp"):
                            yield Log(id="mcp-log", highlight=True, classes="tab-log")
                        with TabPane("🖥️ VAST", id="tab-vast"):
                            yield Static(self._render_vast_tab(), id="vast-view")
                        with TabPane("⚡ Workflows", id="tab-workflows"):
                            yield Static(self._render_workflows_tab(), id="workflows-view")
                        with TabPane("▶️ Execution", id="tab-exec"):
                            yield Static(self._render_execution_tab(), id="exec-view")
                        with TabPane("🌳 Tree", id="tab-tree"):
                            yield Static(self._render_tree(), id="tree-view")
                        with TabPane("🔗 Prov", id="tab-prov"):
                            yield Static(self._render_provenance(), id="provenance")
                    # Loading indicator for downloads (hidden by default)
                    with Horizontal(id="loading-container", classes="progress-hidden"):
                        yield LoadingIndicator(id="loading-spinner")
                        yield Static("Loading...", id="loading-label")
                    yield Input(placeholder="Type 'help' for commands | Examples: plug bge-small-en-v1.5 | infer | status", id="cmd")
            yield Footer()
        
        def _render_workflows_tab(self) -> str:
            """Render the workflows list tab."""
            import json
            lines = []
            lines.append("[bold cyan]═══════════════════════════════════════════════════════════[/]")
            lines.append("[bold cyan]                    ⚡ WORKFLOWS                           [/]")
            lines.append("[bold cyan]═══════════════════════════════════════════════════════════[/]")
            lines.append("")
            
            try:
                result = json.loads(workflow_list())
                workflows = result.get("workflows", [])
                
                if workflows:
                    lines.append("[bold]ID                   │ NAME                      │ NODES[/]")
                    lines.append("─────────────────────┼───────────────────────────┼──────")
                    for wf in workflows:
                        wf_id = wf.get("id", "unknown")[:20]
                        wf_name = wf.get("name", "Unnamed")[:25]
                        node_count = wf.get("node_count", 0)
                        lines.append(f"{wf_id:<20} │ {wf_name:<25} │ {node_count}")
                    lines.append("")
                    lines.append(f"[dim]Total: {len(workflows)} workflow(s)[/]")
                else:
                    lines.append("[dim]No workflows defined yet.[/]")
                    lines.append("")
                    lines.append("[dim]Create one with:[/]")
                    lines.append("[cyan]  workflow new '<json_definition>'[/]")
            except Exception as e:
                lines.append(f"[red]Error loading workflows: {e}[/]")
            
            lines.append("")
            lines.append("[dim]Commands: workflow ls | workflow run <id> | workflow show <id>[/]")
            lines.append("[dim]          workflow new <json> | workflow rm <id> | workflow test[/]")
            
            return "\n".join(lines)
        
        def _render_execution_tab(self) -> str:
            """Render the workflow execution tab."""
            lines = []
            lines.append("[bold green]═══════════════════════════════════════════════════════════[/]")
            lines.append("[bold green]                   ▶️ EXECUTION STATUS                     [/]")
            lines.append("[bold green]═══════════════════════════════════════════════════════════[/]")
            lines.append("")
            
            # Show last execution if available
            last_exec = getattr(self, '_last_workflow_execution', None)
            if last_exec:
                lines.append(f"[bold]Workflow:[/] {last_exec.get('workflow_id', 'unknown')}")
                lines.append(f"[bold]Execution ID:[/] {last_exec.get('execution_id', 'unknown')}")
                
                status = last_exec.get('status', 'unknown')
                status_color = 'green' if status == 'completed' else 'red' if status == 'failed' else 'yellow'
                lines.append(f"[bold]Status:[/] [{status_color}]{status}[/]")
                lines.append(f"[bold]Elapsed:[/] {last_exec.get('elapsed_ms', 0)}ms")
                lines.append("")
                
                # Node states
                node_states = last_exec.get('node_states', {})
                if node_states:
                    lines.append("[bold]Node Execution:[/]")
                    for node_id, state in node_states.items():
                        node_status = state.get('status', 'unknown')
                        icon = '✅' if node_status == 'completed' else '❌' if node_status == 'failed' else '⏭️' if node_status == 'skipped' else '⏳'
                        elapsed = state.get('elapsed_ms', 0)
                        lines.append(f"  {icon} {node_id:<20} {elapsed}ms")
                
                # Output preview
                output = last_exec.get('output')
                if output:
                    lines.append("")
                    lines.append("[bold]Output:[/]")
                    import json
                    output_str = json.dumps(output, indent=2, default=str)
                    for line in output_str.split("\n")[:10]:
                        lines.append(f"  [dim]{line}[/]")
                    if len(output_str.split("\n")) > 10:
                        lines.append("  [dim]...[/]")
            else:
                lines.append("[dim]No recent workflow execution.[/]")
                lines.append("")
                lines.append("[dim]Run a workflow with:[/]")
                lines.append("[cyan]  workflow run <workflow_id>[/]")
            
            lines.append("")
            lines.append("[dim]Commands: workflow run <id> | workflow status <exec_id> | workflow history <id>[/]")
            
            return "\n".join(lines)
        
        def _update_workflows_tab(self):
            """Refresh the workflows tab."""
            try:
                self.query_one("#workflows-view", Static).update(self._render_workflows_tab())
            except Exception:
                pass
        
        def _update_execution_tab(self, execution_result: dict = None):
            """Refresh the execution tab, optionally with new result."""
            if execution_result:
                self._last_workflow_execution = execution_result
            try:
                self.query_one("#exec-view", Static).update(self._render_execution_tab())
            except Exception:
                pass
        
        def _show_loading(self, label: str = "Loading..."):
            """Show loading spinner with label."""
            try:
                container = self.query_one("#loading-container", Horizontal)
                lbl = self.query_one("#loading-label", Static)
                lbl.update(f"[bold cyan]{label}[/]")
                container.remove_class("progress-hidden")
            except Exception:
                pass
        
        def _hide_loading(self):
            """Hide loading spinner."""
            try:
                container = self.query_one("#loading-container", Horizontal)
                container.add_class("progress-hidden")
            except Exception:
                pass
        
        def _render_info(self):
            bt = self.brain_type.upper()
            icon = "🌾" if self.brain_type == 'scarecrow' else "🏛️"
            lines = [
                f"[bold cyan]{icon} {bt}[/bold cyan]",
                f"Gen [yellow]{self.agent.generation}[/] Fit [green]{self.agent.fitness:.4f}[/]",
            ]
            # Show slot info for ANY brain with all_members (Scarecrow = 1 slot, Council = N slots, Ouroboros = multi-modal)
            members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
            if members:
                n = sum(1 for c in members if getattr(c, 'model', None))
                total = len(members)
                clones = sum(len(getattr(c, '_clones', [])) for c in members)
                if self.is_ouroboros:
                    # Ouroboros: show multi-modal slot status
                    lines.append(f"[magenta]🐍 Slots {n}/{total}[/]" + (f" +[cyan]{clones}[/]" if clones else ""))
                    # Check both naming conventions (_dreamer for real brain, dreamer_world_model for quine)
                    has_dreamer = getattr(self.brain, '_dreamer', None) or getattr(self.brain, 'dreamer_world_model', None) or getattr(self.brain, 'dreamer_enabled', False)
                    has_embedder = getattr(self.brain, 'embedding_foundation', None) or getattr(self.brain, '_embedding_model', None)
                    lines.append(f"[dim]dreamer: {'✓' if has_dreamer else '○'}[/]")
                    lines.append(f"[dim]embedder: {'✓' if has_embedder else '○'}[/]")
                elif self.is_council:
                    # Council: show slots with consensus method
                    lines.append(f"Slots [green]{n}[/]/{total}" + (f" +[cyan]{clones}[/]" if clones else ""))
                    cm = getattr(self.brain, 'consensus_method', 'weighted')
                    lines.append(f"[magenta]{cm}[/]")
                else:
                    # Scarecrow: show NULL PORT status
                    if n > 0:
                        mid = getattr(members[0], '_model_source', 'plugged')
                        lines.append(f"[green]⚡ {mid}[/]")
                    else:
                        lines.append("[yellow]⚫ NULL PORT[/] [dim](plug <model>)[/]")
            elif self.is_ouroboros:
                # Ouroboros without slots - still show component status
                lines.append(f"[magenta]🐍 OUROBOROS[/]")
                # Check both naming conventions
                has_dreamer = getattr(self.brain, '_dreamer', None) or getattr(self.brain, 'dreamer_world_model', None) or getattr(self.brain, 'dreamer_enabled', False)
                has_embedder = getattr(self.brain, 'embedding_foundation', None) or getattr(self.brain, '_embedding_model', None)
                lines.append(f"[dim]dreamer: {'✓' if has_dreamer else '○'}[/]")
                lines.append(f"[dim]embedder: {'✓' if has_embedder else '○'}[/]")
            cascade_icon = "[green]●[/]" if _CASCADE_AVAILABLE else "[red]○[/]"
            lines.append(f"CASCADE {cascade_icon}")
            # RELAY CENTER toggle - big and obvious
            if self._relay_listening:
                lines.append("[bold white on green] 🎛️ RELAY ON [/]")
            else:
                lines.append("[dim]🎛️ relay off (L)[/]")
            # MCP SERVER toggle
            if self._mcp_running:
                lines.append("[bold white on blue] 🔌 MCP ON [/]")
            else:
                lines.append("[dim]🔌 mcp off[/]")
            # VAST.AI GPU toggle
            if self._vast_instance_id:
                lines.append(f"[bold white on magenta] 🖥️ VAST {self._vast_instance_id} [/]")
            else:
                lines.append("[dim]🖥️ vast off[/]")
            return "\n".join(lines)
        
        def _render_vast_tab(self):
            """
            🖥️ VAST TAB - Live GPU monitoring and control (MULTI-INSTANCE)

            Shows:
            - ALL rented instances with status, GPU, connection state
            - Models loaded on each instance (color-coded by GPU)
            - Cost tracking per instance and total
            - Quick commands for management

            Color coding by instance index:
            - Instance 0: magenta
            - Instance 1: cyan
            - Instance 2: yellow
            - Instance 3: green
            - Instance 4+: white
            """
            lines = []

            # Color palette for GPU instances
            GPU_COLORS = ['magenta', 'cyan', 'yellow', 'green', 'white', 'blue', 'red', 'bright_magenta']

            # Check for instances in multi-instance tracking dict
            instances = self._vast_instances

            if not instances:
                # ═══════ NO ACTIVE INSTANCES ═══════
                lines.append("[bold cyan]┌─ VAST.AI GPU ─────────────────────────────────────────────┐[/bold cyan]")
                lines.append("")
                lines.append("[dim]  No active GPU instances[/]")
                lines.append("")
                lines.append("  [bold white]Quick Start:[/]")
                lines.append("    [cyan]vast search[/]         → Find available GPUs")
                lines.append("    [cyan]vast rent <#>[/]       → Rent a GPU by number")
                lines.append("    [cyan]vast connect[/]        → Connect to rented GPU")
                lines.append("")
                lines.append("  [bold white]Multi-GPU Workflow:[/]")
                lines.append("    [dim]> vast search gpu_ram>=16 dph<0.25[/]")
                lines.append("    [dim]> vast rent 1[/]           # Rent first GPU")
                lines.append("    [dim]> vast rent 2[/]           # Rent second GPU")
                lines.append("    [dim]> vast instances[/]        # See all rentals")
                lines.append("    [dim]> vast connect 12345[/]    # Connect to specific")
                lines.append("    [dim]> plug MODEL[/]            # Load on connected GPU")
                lines.append("")
                # Show activity log even with no active instances (MCP vast calls)
                activity = getattr(self, '_vast_activity_log', [])
                if activity:
                    lines.append("  [bold cyan]┌─ RECENT ACTIVITY ─────────────────────────────────────────┐[/]")
                    for entry in activity[-5:]:
                        ts = entry.get('time', '--:--:--')
                        tool = entry.get('tool', 'unknown')
                        status = entry.get('status', '??')
                        icon = '✓' if status == 'ok' else '✗' if status == 'error' else '⟳'
                        color = 'green' if status == 'ok' else 'red' if status == 'error' else 'yellow'
                        lines.append(f"  [{color}]{icon} {ts} │ {tool}[/]")
                    lines.append("  [bold cyan]└───────────────────────────────────────────────────────────┘[/]")
                    lines.append("")
                lines.append("[bold cyan]└───────────────────────────────────────────────────────────┘[/bold cyan]")
            else:
                # ═══════ ACTIVE INSTANCES (MULTI-GPU VIEW) ═══════
                total_cost = 0.0
                current_id = str(self._vast_instance_id) if self._vast_instance_id else None

                lines.append("[bold cyan]┌─ VAST.AI GPU FLEET ──────────────────────────────────────┐[/bold cyan]")
                lines.append("")
                lines.append(f"  [bold white]{len(instances)} INSTANCE(S) ACTIVE[/]")
                lines.append("  " + "━" * 55)

                # Iterate through all instances
                for idx, (iid, inst) in enumerate(instances.items()):
                    color = GPU_COLORS[idx % len(GPU_COLORS)]
                    status = inst.get('status', 'unknown')
                    gpu_name = inst.get('gpu', 'GPU')
                    connected = inst.get('connected', False)
                    models = inst.get('models', [])
                    ssh_host = inst.get('ssh_host', '')
                    ssh_port = inst.get('ssh_port', '')
                    cost_hr = inst.get('cost_per_hr', 0.0)
                    total_cost += cost_hr

                    # Status indicators
                    status_icon = '🟢' if status == 'running' else '🟡' if 'loading' in status else '🔴'
                    conn_icon = '⚡' if connected else '○'
                    current_marker = ' ◀ CURRENT' if iid == current_id else ''

                    lines.append("")
                    lines.append(f"  [{color}]━━━ INSTANCE {iid} ━━━[/{color}]{current_marker}")
                    lines.append(f"  {status_icon} [bold {color}]{gpu_name}[/] - {status.upper()}")
                    lines.append(f"  {conn_icon} Connected: {'[green]YES[/]' if connected else '[dim]NO[/]'}  │  ${cost_hr:.3f}/hr")

                    # ─── GPU UTILIZATION BAR ───
                    gpu_util = inst.get('gpu_util', 0)
                    vram_used = inst.get('vram_used', 0)
                    vram_total = inst.get('vram_total', 1)
                    vram_pct = (vram_used / vram_total * 100) if vram_total > 0 else 0
                    
                    # Create visual bar (20 chars wide)
                    bar_width = 20
                    gpu_filled = int(bar_width * gpu_util / 100)
                    gpu_bar = "█" * gpu_filled + "░" * (bar_width - gpu_filled)
                    vram_filled = int(bar_width * vram_pct / 100)
                    vram_bar = "█" * vram_filled + "░" * (bar_width - vram_filled)
                    
                    util_color = 'green' if gpu_util < 50 else 'yellow' if gpu_util < 80 else 'red'
                    lines.append(f"  [dim]GPU:[/] [{util_color}]{gpu_bar}[/] {gpu_util}%")
                    lines.append(f"  [dim]VRAM:[/] [cyan]{vram_bar}[/] {vram_used:.1f}/{vram_total:.1f}GB")

                    # SSH info
                    if ssh_host and ssh_port:
                        lines.append(f"  [dim]SSH: {ssh_host}:{ssh_port}[/]")

                    # Models loaded on this instance (color-coded)
                    if models:
                        lines.append(f"  [bold {color}]📦 Models ({len(models)}):[/]")
                        for model_name in models[:5]:  # Show max 5
                            lines.append(f"     [{color}]●[/{color}] {model_name}")
                        if len(models) > 5:
                            lines.append(f"     [dim]... and {len(models) - 5} more[/]")
                    else:
                        lines.append(f"  [dim]No models loaded - use 'plug MODEL'[/]")

                # Total cost summary with LIVE accumulator
                lines.append("")
                lines.append("  " + "━" * 55)
                # Calculate accumulated cost based on runtime
                total_accumulated = 0.0
                for iid, inst in instances.items():
                    cost_hr = inst.get('cost_per_hr', 0.0)
                    start_time = inst.get('start_time', 0)
                    if start_time:
                        runtime_hours = (__import__('time').time() - start_time) / 3600
                        total_accumulated += cost_hr * runtime_hours
                lines.append(f"  [bold white]💰 RATE: ${total_cost:.3f}/hr[/] │ [bold yellow]📊 SPENT: ~${total_accumulated:.2f}[/]")

                # ─── TOOL ACTIVITY STREAM ───
                activity = getattr(self, '_vast_activity_log', [])
                if activity:
                    lines.append("")
                    lines.append("  [bold cyan]┌─ RECENT ACTIVITY ─────────────────────────────────────────┐[/]")
                    # Show last 5 activity entries (most recent first)
                    for entry in activity[-5:]:
                        ts = entry.get('time', '--:--:--')
                        tool = entry.get('tool', 'unknown')
                        status = entry.get('status', '??')
                        icon = '✓' if status == 'ok' else '✗' if status == 'error' else '⟳'
                        color = 'green' if status == 'ok' else 'red' if status == 'error' else 'yellow'
                        lines.append(f"  [{color}]{icon} {ts} │ {tool}[/]")
                    lines.append("  [bold cyan]└───────────────────────────────────────────────────────────┘[/]")

                # Commands
                lines.append("")
                lines.append("  [bold white]Commands:[/]")
                lines.append("    vast connect <id>     Switch to instance")
                lines.append("    vast stop <id>        Stop specific instance")
                lines.append("    vast broadcast <cmd>  Send to ALL GPUs")
                lines.append("    vast distribute ...   Send different cmds to each")
                lines.append("")
                lines.append("[bold cyan]└───────────────────────────────────────────────────────────┘[/bold cyan]")

            return "\n".join(lines)
        
        def _update_vast_tab(self):
            """Refresh the VAST tab display."""
            try:
                vast_view = self.query_one("#vast-view", Static)
                vast_view.update(self._render_vast_tab())
            except Exception:
                pass
        
        def _start_vast_polling(self):
            """Start background thread to poll vast instance status."""
            import threading
            import subprocess
            import json
            import time
            
            def poll_loop():
                while self._vast_state.get('id') and self._vast_poll_thread:
                    try:
                        # Get instance status
                        result = subprocess.run(
                            ['vastai', 'show', 'instance', str(self._vast_state['id']), '--raw'],
                            capture_output=True, text=True, timeout=30
                        )
                        if result.returncode == 0:
                            data = json.loads(result.stdout)
                            self._vast_state['status'] = data.get('actual_status', 'unknown')
                            self._vast_state['gpu'] = data.get('gpu_name', 'GPU')
                            self._vast_state['public_ip'] = data.get('public_ipaddr', '')
                            self._vast_state['cost_per_hr'] = data.get('dph_total', 0)
                            self._vast_state['vram_total'] = data.get('gpu_ram', 0) / 1024  # MB to GB
                            self._vast_state['ssh_host'] = data.get('ssh_host', '')
                            self._vast_state['ssh_port'] = data.get('ssh_port', '')
                            
                            # Parse ports for MCP URL
                            ports = data.get('ports', {})
                            if '8765/tcp' in ports and ports['8765/tcp']:
                                host_port = ports['8765/tcp'][0].get('HostPort', '8765')
                                self._vast_state['mcp_url'] = f"http://{self._vast_state['public_ip']}:{host_port}/sse"
                            
                            # Get GPU stats via SSH if possible
                            if self._vast_ssh_key and self._vast_state['status'] == 'running':
                                ssh_port = None
                                if '22/tcp' in ports and ports['22/tcp']:
                                    ssh_port = ports['22/tcp'][0].get('HostPort')
                                if ssh_port:
                                    try:
                                        gpu_result = subprocess.run([
                                            'ssh', '-i', self._vast_ssh_key,
                                            '-o', 'StrictHostKeyChecking=no',
                                            '-o', 'ConnectTimeout=5',
                                            '-p', ssh_port,
                                            f"root@{self._vast_state['public_ip']}",
                                            "nvidia-smi --query-gpu=utilization.gpu,memory.used,memory.total --format=csv,noheader,nounits 2>/dev/null | head -1"
                                        ], capture_output=True, text=True, timeout=10)
                                        if gpu_result.returncode == 0 and gpu_result.stdout.strip():
                                            parts = gpu_result.stdout.strip().split(',')
                                            if len(parts) >= 3:
                                                self._vast_state['gpu_util'] = int(parts[0].strip())
                                                self._vast_state['vram_used'] = float(parts[1].strip()) / 1024
                                                self._vast_state['vram_total'] = float(parts[2].strip()) / 1024
                                        
                                        # Also get MCP logs
                                        log_result = subprocess.run([
                                            'ssh', '-i', self._vast_ssh_key,
                                            '-o', 'StrictHostKeyChecking=no',
                                            '-o', 'ConnectTimeout=5',
                                            '-p', ssh_port,
                                            f"root@{self._vast_state['public_ip']}",
                                            "tail -20 /workspace/mcp.log 2>/dev/null || echo 'No logs yet'"
                                        ], capture_output=True, text=True, timeout=10)
                                        if log_result.returncode == 0:
                                            self._vast_state['logs'] = log_result.stdout.strip().split('\n')[-20:]
                                    except Exception:
                                        pass
                            
                            # Sync to _vast_instances so _render_vast_tab sees fresh data
                            iid = str(self._vast_state['id'])
                            if iid in self._vast_instances:
                                self._vast_instances[iid]['status'] = self._vast_state['status']
                                self._vast_instances[iid]['gpu'] = self._vast_state['gpu']
                                self._vast_instances[iid]['cost_per_hr'] = self._vast_state['cost_per_hr']
                                self._vast_instances[iid]['ssh_host'] = self._vast_state['ssh_host']
                                self._vast_instances[iid]['ssh_port'] = self._vast_state['ssh_port']
                                self._vast_instances[iid]['gpu_util'] = self._vast_state.get('gpu_util', 0)
                                self._vast_instances[iid]['vram_used'] = self._vast_state.get('vram_used', 0)
                                self._vast_instances[iid]['vram_total'] = self._vast_state.get('vram_total', 0)

                            # Update display (thread-safe)
                            try:
                                self.call_from_thread(self._update_vast_tab)
                            except AttributeError:
                                pass
                    except Exception as e:
                        pass

                    time.sleep(10)  # Poll every 10 seconds
            
            self._vast_poll_thread = threading.Thread(target=poll_loop, daemon=True)
            self._vast_poll_thread.start()
        
        def _stop_vast_polling(self):
            """Stop the vast polling thread."""
            self._vast_poll_thread = None
        
        def action_quit(self):
            """Override quit to stop polling threads first."""
            self._stop_vast_polling()
            self.exit()
        
        def _render_tree(self):
            """
            🌐 AGENT TREE - Infinite Nested Tree View
            
            Features:
            - Infinite nesting depth for agent hierarchies
            - Empty ports collapsed by default (shown as summary)
            - Active models shown prominently with full details
            - Scales to thousands of nested agents
            - Tree structure: parent → children → grandchildren → ...
            """
            import json
            import time
            lines = []
            
            # Toggle state for showing empty slots (default: hidden)
            show_empty = getattr(self, '_show_empty_slots', False)
            
            # ═══════════════════════════════════════════════════════════════
            # HEADER
            # ═══════════════════════════════════════════════════════════════
            lines.append(f"[bold cyan]┌─ AGENT TREE ──────────────────────────────────────────────┐[/bold cyan]")
            lines.append("")
            
            # ═══════════════════════════════════════════════════════════════
            # SLOTS - Recursive infinite nesting
            # ═══════════════════════════════════════════════════════════════
            lines.append("[bold white]│ ┌─ SLOTS ───────────────────────────────────────────┐ │[/bold white]")
            
            # Parse CASCADE feed for latency data
            cascade_stats = self._parse_cascade_for_stats()
            
            # Count active vs empty
            members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
            
            def count_tree_nodes(node, depth=0):
                """Recursively count all nodes in tree."""
                count = 1
                children = getattr(node, '_clones', []) + getattr(node, '_children', []) + getattr(node, 'councilors', [])
                for child in children:
                    count += count_tree_nodes(child, depth + 1)
                return count
            
            def render_node(node, depth=0, prefix="", is_last=True, slot_idx=None):
                """Recursively render a node and its children."""
                node_lines = []
                
                name = getattr(node, 'name', f'agent_{slot_idx or 0}')
                model = getattr(node, 'model', None)
                mid = getattr(node, '_model_source', None) or ''
                
                # Tree branch characters
                if depth == 0:
                    branch = ""
                    next_prefix = "    "
                else:
                    branch = prefix + ("└── " if is_last else "├── ")
                    next_prefix = prefix + ("    " if is_last else "│   ")
                
                # Only show if active OR show_empty is True
                is_active = model is not None
                
                if is_active or show_empty or depth == 0:
                    # Status icon
                    if is_active:
                        status = "[green]●[/green]"
                    else:
                        status = "[dim]○[/dim]"
                    
                    # Model type detection (handles both local and remote models)
                    # GPU color palette for remote models
                    GPU_COLORS = ['magenta', 'cyan', 'yellow', 'green', 'white', 'blue', 'red', 'bright_magenta']

                    if model is not None:
                        is_remote = getattr(node, '_is_remote', False) or (isinstance(model, str) and model.startswith('REMOTE:'))

                        if is_remote:
                            # REMOTE MODEL - color by GPU instance
                            instance_id = str(getattr(node, '_vast_instance_id', '') or getattr(self, '_vast_instance_id', '') or '')
                            # Find instance index for color
                            instance_keys = list(self._vast_instances.keys()) if hasattr(self, '_vast_instances') else []
                            gpu_idx = instance_keys.index(instance_id) if instance_id in instance_keys else 0
                            gpu_color = GPU_COLORS[gpu_idx % len(GPU_COLORS)]
                            mtype = f"[bold {gpu_color}]🖥️ GPU{instance_id[-4:] if len(instance_id) > 4 else instance_id}[/]"
                        elif hasattr(model, 'encode'):
                            mtype = "[blue]EMBED[/blue]"
                        elif hasattr(model, 'generate'):
                            mtype = "[magenta]LLM[/magenta]"
                        elif hasattr(model, 'detect'):
                            mtype = "[yellow]VISION[/yellow]"
                        elif hasattr(model, 'classify'):
                            mtype = "[cyan]CLASS[/cyan]"
                        elif hasattr(model, 'rerank'):
                            mtype = "[green]RERANK[/green]"
                        else:
                            mtype = "[dim]GEN[/dim]"
                    else:
                        mtype = "[dim]--[/dim]"
                    
                    # Dimensions (skip for remote models which are string references)
                    dims = ""
                    if model is not None and not isinstance(model, str):
                        try:
                            if hasattr(model, 'get_sentence_embedding_dimension'):
                                dims = f"{model.get_sentence_embedding_dimension()}d"
                            elif hasattr(model, 'config') and hasattr(model.config, 'hidden_size'):
                                dims = f"{model.config.hidden_size}d"
                        except Exception:
                            pass
                    
                    # Latency
                    slot_key = str(slot_idx) if slot_idx is not None else "0"
                    latency = cascade_stats.get('slot_latencies', {}).get(slot_key, None)
                    lat_str = ""
                    if latency:
                        if latency > 100:
                            lat_str = f" [yellow]⚡{latency:.0f}ms[/yellow]"
                        elif latency < 30:
                            lat_str = f" [green]⚡{latency:.0f}ms[/green]"
                        else:
                            lat_str = f" ⚡{latency:.0f}ms"
                    
                    # Short model ID or name
                    short_mid = mid[:20] if mid else name[:20]
                    
                    # Count children for summary
                    children = getattr(node, '_clones', []) + getattr(node, '_children', [])
                    child_count = len(children)
                    child_summary = f" [dim]({child_count} nested)[/dim]" if child_count > 0 else ""
                    
                    if is_active:
                        node_lines.append(f"│ │  {branch}{status} {short_mid} {mtype} {dims}{lat_str}{child_summary}")
                    else:
                        node_lines.append(f"│ │  {branch}{status} [dim]{short_mid}[/dim]{child_summary}")
                
                # Recurse into children (clones, children, sub-councilors)
                children = getattr(node, '_clones', []) + getattr(node, '_children', [])
                
                # Count active children for collapse summary
                active_children = [c for c in children if getattr(c, 'model', None) is not None]
                empty_children = [c for c in children if getattr(c, 'model', None) is None]
                
                # Limit depth display to prevent overwhelming output
                max_display_depth = 5
                if depth < max_display_depth:
                    # Show active children always
                    for idx, child in enumerate(active_children):
                        is_child_last = (idx == len(active_children) - 1) and len(empty_children) == 0
                        node_lines.extend(render_node(child, depth + 1, next_prefix, is_child_last, slot_idx=idx))
                    
                    # Show empty children only if toggled
                    if show_empty:
                        for idx, child in enumerate(empty_children):
                            is_child_last = (idx == len(empty_children) - 1)
                            node_lines.extend(render_node(child, depth + 1, next_prefix, is_child_last, slot_idx=len(active_children) + idx))
                    elif len(empty_children) > 0:
                        # Show collapsed summary for empty
                        node_lines.append(f"│ │  {next_prefix}[dim]└── ({len(empty_children)} empty ports collapsed)[/dim]")
                
                elif len(children) > 0:
                    # At max depth, show summary
                    total_below = count_tree_nodes(node) - 1
                    active_below = len([c for c in children if getattr(c, 'model', None)])
                    node_lines.append(f"│ │  {next_prefix}[dim]└── ... ({total_below} more: {active_below} active)[/dim]")
                
                return node_lines
            
            # Render root brain/council
            if members:
                total_active = sum(1 for c in members if getattr(c, 'model', None) is not None)
                total_empty = len(members) - total_active
                
                # Show summary header
                lines.append(f"│ │  [bold]🧠 {self.brain_type.upper()}[/bold] [dim]({total_active} active, {total_empty} empty)[/dim]")
                lines.append("│ │")
                
                for i, c in enumerate(members):
                    is_last = (i == len(members) - 1)
                    # Only render if active or show_empty
                    if getattr(c, 'model', None) is not None or show_empty:
                        lines.extend(render_node(c, depth=1, prefix="", is_last=is_last, slot_idx=i))
                
                # If hiding empty and there are empty slots, show summary
                if not show_empty and total_empty > 0 and total_active < len(members):
                    lines.append(f"│ │  [dim]    └── ({total_empty} empty ports - press E to expand)[/dim]")
            else:
                lines.append("│ │  [dim]No agents - use 'plug <model_id>'[/dim]")
            
            lines.append("│ │")
            lines.append("[dim]│ └─────────────────────────────────────────────────────┘ │[/dim]")
            lines.append("")
            
            # ═══════════════════════════════════════════════════════════════
            # IMAGINATION TRAJECTORIES - Dreamer's Projected Futures
            # Each trajectory is a POTENTIAL WORK TREE that can be allocated
            # to adapters for differential interpretation
            # ═══════════════════════════════════════════════════════════════
            show_imagination = getattr(self, '_show_imagination', True)
            if self.is_ouroboros or self.brain_type == 'dreamer':
                lines.append("[bold magenta]│ ┌─ IMAGINATION (Dreamer Trajectories) ─────────────────┐ │[/bold magenta]")
                
                # Get last imagination from dreamer
                dreamer = getattr(self.brain, '_dreamer', None) or getattr(self.brain, 'dreamer_world_model', None)
                last_imagination = getattr(dreamer, '_last_imagination', []) if dreamer else []
                
                # Get adapter topology if available
                adapter_topo = None
                if hasattr(self.brain, 'get_adapter_topology'):
                    adapter_topo = self.brain.get_adapter_topology()
                
                if last_imagination and show_imagination:
                    n_branches = len(last_imagination)
                    horizon = len(last_imagination[0]) if last_imagination and last_imagination[0] else 0
                    real_rssm = last_imagination[0][0].get('real_rssm', False) if last_imagination and last_imagination[0] else False
                    
                    rssm_badge = "[green]●RSSM[/green]" if real_rssm else "[dim]○sim[/dim]"
                    
                    # Show adapter count if multi-adapter
                    if adapter_topo and adapter_topo['count'] > 1:
                        adapter_badge = f"[cyan]×{adapter_topo['count']}adapt[/cyan]"
                        lines.append(f"│ │  {rssm_badge} {adapter_badge} [bold]{n_branches} branches × {horizon} steps[/bold]")
                    else:
                        lines.append(f"│ │  {rssm_badge} [bold]{n_branches} branches × {horizon} steps[/bold]")
                    lines.append("│ │")
                    
                    # Get trajectory interpretation if brain supports it
                    trajectory_interps = []
                    if hasattr(self.brain, 'interpret_trajectory'):
                        for traj in last_imagination[:8]:
                            if traj:
                                # Extract latent vectors from trajectory
                                latents = [step.get('latent', step.get('stoch', None)) for step in traj]
                                latents = [l for l in latents if l is not None]
                                if latents:
                                    try:
                                        interp = self.brain.interpret_trajectory(latents)
                                        trajectory_interps.append(interp)
                                    except Exception:
                                        trajectory_interps.append(None)
                                else:
                                    trajectory_interps.append(None)
                            else:
                                trajectory_interps.append(None)
                    
                    # Render each branch as collapsible tree
                    for branch_idx, trajectory in enumerate(last_imagination[:8]):  # Max 8 branches
                        if not trajectory:
                            continue
                        
                        first_step = trajectory[0]
                        branch_action = first_step.get('branch_action', branch_idx)
                        total_value = first_step.get('trajectory_total_value', sum(s.get('value', 0) for s in trajectory))
                        
                        # Get trajectory interpretation confidence
                        traj_conf = None
                        hotspots = []
                        if branch_idx < len(trajectory_interps) and trajectory_interps[branch_idx]:
                            traj_conf = trajectory_interps[branch_idx].get('trajectory_confidence', None)
                            hotspots = trajectory_interps[branch_idx].get('divergence_hotspots', [])
                        
                        # Branch header with value bar
                        value_bar = "█" * min(10, int(abs(total_value) * 2))
                        if total_value > 0:
                            value_color = "green" if total_value > 2 else "yellow"
                        else:
                            value_color = "red"
                        
                        is_best = branch_idx == 0  # Assuming sorted by value
                        star = "[bold yellow]★[/bold yellow]" if is_best else " "
                        
                        # Confidence badge from multi-adapter interpretation
                        conf_badge = ""
                        if traj_conf is not None:
                            if traj_conf > 0.8:
                                conf_badge = "[green]⬤[/green]"  # High confidence
                            elif traj_conf > 0.5:
                                conf_badge = "[yellow]◐[/yellow]"  # Medium
                            else:
                                conf_badge = "[red]○[/red]"  # Low - adapters disagreed
                        
                        lines.append(f"│ │  {star} {conf_badge} [bold cyan]Action {branch_action}[/bold cyan] → [{value_color}]{value_bar} {total_value:.2f}[/{value_color}]")
                        
                        # Show trajectory steps (collapsed by default, show first 3)
                        show_steps = getattr(self, '_expand_trajectories', False)
                        steps_to_show = trajectory if show_steps else trajectory[:3]
                        
                        for step_idx, step in enumerate(steps_to_show):
                            is_last_step = step_idx == len(steps_to_show) - 1
                            branch_char = "└──" if is_last_step else "├──"
                            
                            step_val = step.get('value', 0)
                            step_action = step.get('action', '?')
                            latent_norm = step.get('latent_norm', 0)
                            
                            # Mini value indicator
                            val_char = "↑" if step_val > 0.5 else "↓" if step_val < -0.5 else "→"
                            
                            # Mark divergence hotspots
                            hotspot_mark = "[bold red]![/bold red]" if step_idx in hotspots else ""
                            
                            lines.append(f"│ │      {branch_char} t={step_idx}: a={step_action} {val_char}{step_val:.2f} [dim]‖{latent_norm:.0f}[/dim] {hotspot_mark}")
                        
                        if not show_steps and len(trajectory) > 3:
                            lines.append(f"│ │      [dim]└── ... ({len(trajectory) - 3} more steps)[/dim]")
                    
                    lines.append("│ │")
                    expand_hint = "[T]=collapse" if getattr(self, '_expand_trajectories', False) else "[T]=expand steps"
                    lines.append(f"│ │  [dim]{expand_hint} | [I]=imagine now[/dim]")
                    
                    # Show adapter divergence legend if applicable
                    if adapter_topo and adapter_topo['count'] > 1:
                        lines.append(f"│ │  [dim]Confidence: [green]⬤[/green]=agree [yellow]◐[/yellow]=partial [red]○[/red]=divergent  [bold red]![/bold red]=hotspot[/dim]")
                else:
                    lines.append("│ │  [dim]No imagination yet - type 'imagine' to project futures[/dim]")
                
                lines.append("[dim]│ └─────────────────────────────────────────────────────┘ │[/dim]")
                lines.append("")
            
            # ═══════════════════════════════════════════════════════════════
            # DECISION MATRIX - Best Actions from Imagination
            # ═══════════════════════════════════════════════════════════════
            if self.is_ouroboros or self.brain_type == 'dreamer':
                dreamer = getattr(self.brain, '_dreamer', None) or getattr(self.brain, 'dreamer_world_model', None)
                last_imagination = getattr(dreamer, '_last_imagination', []) if dreamer else []
                
                if last_imagination:
                    lines.append("[bold yellow]│ ┌─ DECISION MATRIX ─────────────────────────────────────┐ │[/bold yellow]")
                    
                    # Rank trajectories by total value
                    ranked = []
                    for i, traj in enumerate(last_imagination):
                        if traj:
                            total_val = traj[0].get('trajectory_total_value', sum(s.get('value', 0) for s in traj))
                            ranked.append((i, total_val, traj[0].get('branch_action', i)))
                    
                    ranked.sort(key=lambda x: -x[1])  # Best first
                    
                    # Show top 5 as decision candidates
                    for rank, (branch_idx, total_val, action) in enumerate(ranked[:5]):
                        prob = max(0.1, min(1.0, (total_val + 2) / 4))  # Normalize to [0,1]-ish
                        bar = "█" * int(prob * 15)
                        
                        if rank == 0:
                            prefix = "[bold green]★[/bold green]"
                            color = "green"
                        elif rank == 1:
                            prefix = "[yellow]▸[/yellow]"
                            color = "yellow"
                        else:
                            prefix = "[dim]▸[/dim]"
                            color = "white"
                        
                        lines.append(f"│ │  {prefix} [{color}]Action {action}[/{color}] │ [{color}]{bar}[/{color}] [dim]{total_val:+.2f}[/dim]")
                    
                    best = ranked[0] if ranked else None
                    if best:
                        lines.append("│ │")
                        lines.append(f"│ │  [bold]RECOMMENDED: Action {best[2]}[/bold] [dim](value {best[1]:+.2f})[/dim]")
                    
                    lines.append("[dim]│ └─────────────────────────────────────────────────────┘ │[/dim]")
                    lines.append("")
            
            # ═══════════════════════════════════════════════════════════════
            # ADAPTER TOPOLOGY - Dynamic SymbioticAdapter allocation per slot
            # Shows how Scarecrows have configured their internal adapters
            # based on wrapped model architecture (MoE, Council, Multimodal)
            # ═══════════════════════════════════════════════════════════════
            if members:
                # Collect adapter topologies from all slots
                adapter_info = []
                
                def collect_adapter_topology(node, path=""):
                    """Recursively collect adapter topology from all Scarecrows."""
                    results = []
                    if hasattr(node, 'get_adapter_topology'):
                        topo = node.get_adapter_topology()
                        if topo and topo.get('count', 0) > 0:
                            name = getattr(node, 'name', None) or getattr(node, 'model_id', None) or type(node).__name__
                            results.append({
                                'path': path or name[:20],
                                'count': topo['count'],
                                'labels': topo.get('labels', []),
                                'patterns': topo.get('patterns_learned', 0)
                            })
                    
                    # Recurse into children
                    children = getattr(node, '_clones', []) + getattr(node, '_children', [])
                    for i, child in enumerate(children):
                        child_path = f"{path}/{i}" if path else str(i)
                        results.extend(collect_adapter_topology(child, child_path))
                    
                    return results
                
                for i, member in enumerate(members):
                    adapter_info.extend(collect_adapter_topology(member, str(i)))
                
                # Only show section if there are multi-adapter Scarecrows
                multi_adapter_slots = [a for a in adapter_info if a['count'] > 1]
                if multi_adapter_slots:
                    lines.append("[bold cyan]│ ┌─ ADAPTER TOPOLOGY ────────────────────────────────────┐ │[/bold cyan]")
                    
                    for slot in multi_adapter_slots[:6]:  # Show max 6 slots
                        count = slot['count']
                        labels = slot['labels'][:4]  # First 4 labels
                        patterns = slot['patterns']
                        
                        # Adapter count badge with color
                        if count >= 8:
                            count_badge = f"[bold magenta]{count}×[/bold magenta]"
                        elif count >= 4:
                            count_badge = f"[cyan]{count}×[/cyan]"
                        else:
                            count_badge = f"[green]{count}×[/green]"
                        
                        # Labels as compact pills
                        label_str = " ".join(f"[dim]·{l[:8]}[/dim]" for l in labels)
                        if len(slot['labels']) > 4:
                            label_str += f" [dim]+{len(slot['labels'])-4}[/dim]"
                        
                        lines.append(f"│ │  {count_badge} [bold]{slot['path']}[/bold] {label_str}")
                        
                        # Pattern learning progress
                        if patterns > 0:
                            pattern_bar = "▪" * min(10, patterns // 10)
                            lines.append(f"│ │      [dim]learned: {pattern_bar} {patterns} patterns[/dim]")
                    
                    if len(multi_adapter_slots) > 6:
                        lines.append(f"│ │  [dim]... +{len(multi_adapter_slots)-6} more multi-adapter slots[/dim]")
                    
                    lines.append("[dim]│ └─────────────────────────────────────────────────────┘ │[/dim]")
                    lines.append("")
            
            # ═══════════════════════════════════════════════════════════════
            # QUICK STATS BAR
            # ═══════════════════════════════════════════════════════════════
            total_nodes = sum(count_tree_nodes(c) for c in members) if members else 0
            total_infs = cascade_stats.get('total_inferences', 0)
            avg_lat = cascade_stats.get('avg_latency', 0)
            uptime = self._format_uptime()
            total_active = sum(1 for c in members if getattr(c, 'model', None) is not None) if members else 0
            
            lines.append("[bold white]│ ┌─ STATS ────────────────────────────────────────────┐ │[/bold white]")
            lines.append(f"│ │  Nodes: [bold]{total_nodes}[/bold] │ Active: [bold]{total_active}[/bold] │ Infs: [bold]{total_infs}[/bold] │ Avg: [bold]{avg_lat:.0f}ms[/bold] │ Up: [bold]{uptime}[/bold] │ │")
            lines.append("[dim]│ └─────────────────────────────────────────────────────┘ │[/dim]")
            
            lines.append("")
            lines.append("[bold cyan]└─────────────────────────────────────────────────────────┘[/bold cyan]")
            lines.append("")
            # Keyboard hints
            traj_hint = "[bold]T[/bold]=trajs" if self.is_ouroboros or self.brain_type == 'dreamer' else ""
            imag_hint = "[bold]M[/bold]=imagine" if self.is_ouroboros or self.brain_type == 'dreamer' else ""
            toggle_hint = "[bold]E[/bold]=empty"
            lines.append(f"[dim]{toggle_hint} | {traj_hint} | {imag_hint} | [bold]W[/bold]=refresh | [bold]I[/bold]=infer[/dim]")
            
            return "\n".join(lines)
        
        def _parse_cascade_for_stats(self) -> dict:
            """Parse CASCADE feed for real-time stats."""
            import json
            stats = {
                'total_inferences': 0,
                'avg_latency': 0,
                'slot_latencies': {},
                'recent_events': []
            }
            
            try:
                feed_file = _CASCADE_FEED_DIR / 'feed.jsonl' if _CASCADE_FEED_DIR else None
                if feed_file and feed_file.exists():
                    lines = feed_file.read_text(encoding='utf-8').strip().split('\n')
                    events = []
                    latencies = []
                    
                    for line in lines[-100:]:  # Last 100 events
                        try:
                            evt = json.loads(line)
                            events.append(evt)
                            
                            etype = evt.get('event_type', '')
                            data = evt.get('data', {})
                            
                            if etype in ('inference', 'embed'):
                                stats['total_inferences'] += 1
                                if 'elapsed_ms' in data:
                                    latencies.append(data['elapsed_ms'])
                                    slot = str(data.get('slot', 0))
                                    stats['slot_latencies'][slot] = data['elapsed_ms']
                        except Exception:
                            pass
                    
                    stats['recent_events'] = events[-10:]
                    if latencies:
                        stats['avg_latency'] = sum(latencies) / len(latencies)
            except Exception:
                pass
            
            return stats
        
        def _format_uptime(self) -> str:
            """Format uptime as human-readable string."""
            import time
            elapsed = time.time() - self._start_time
            if elapsed < 60:
                return f"{int(elapsed)}s"
            elif elapsed < 3600:
                return f"{int(elapsed // 60)}m {int(elapsed % 60)}s"
            else:
                hours = int(elapsed // 3600)
                mins = int((elapsed % 3600) // 60)
                return f"{hours}h {mins}m"
        
        def _render_provenance(self):
            """
            Render CASCADE CAUSATION GRAPH - live event topology + merkle chain.

            Shows: graph stats, component breakdown, causation chains,
            root/leaf events, merkle root history, and feed.jsonl backup.
            """
            import json
            lines = ["[bold blue]🔗 CASCADE CAUSATION GRAPH[/bold blue]", ""]

            if not _CASCADE_AVAILABLE:
                lines.append("[yellow]⚠ cascade-lattice not installed[/yellow]")
                lines.append("")
                lines.append("[dim]pip install cascade-lattice[/dim]")
                return "\n".join(lines)

            lines.append("[green]✓ cascade.store active[/green]")

            # ─── GRAPH STATS ───
            if self._causation_graph is not None:
                try:
                    stats = self._causation_graph.get_stats()
                    evt_count = stats.get('event_count', 0)
                    link_count = stats.get('link_count', 0)
                    components = stats.get('components', [])
                    event_types = stats.get('event_types', [])

                    lines.append("")
                    lines.append("[bold cyan]┌─ GRAPH TOPOLOGY ─────────────────────────┐[/]")
                    lines.append(f"  [bold]Events:[/] [cyan]{evt_count}[/]  │  [bold]Links:[/] [cyan]{link_count}[/]")
                    if components:
                        lines.append(f"  [bold]Components:[/] [dim]{', '.join(str(c) for c in components[:5])}[/]")
                    if event_types:
                        lines.append(f"  [bold]Event Types:[/] [dim]{', '.join(str(t) for t in event_types[:8])}[/]")
                    lines.append("[bold cyan]└──────────────────────────────────────────┘[/]")
                except Exception as e:
                    lines.append(f"[dim]Graph stats error: {e}[/]")
            else:
                lines.append("[dim]CausationGraph not initialized[/]")

            # ─── MERKLE ROOT HISTORY ───
            if self._merkle_roots:
                lines.append("")
                lines.append("[bold green]┌─ MERKLE CHAIN ───────────────────────────┐[/]")
                lines.append(f"  [bold]Current Root:[/] [bold green]⟐ {self._merkle_roots[-1][:16]}[/]")
                lines.append(f"  [bold]Chain Length:[/] [cyan]{len(self._merkle_roots)}[/] roots")
                # Show last few roots
                for i, root in enumerate(self._merkle_roots[-5:]):
                    idx = len(self._merkle_roots) - 5 + i
                    if idx < 0:
                        continue
                    lines.append(f"  [dim]#{idx+1}[/] [green]{root[:16]}[/]")
                lines.append("[bold green]└──────────────────────────────────────────┘[/]")

            # ─── RECENT EVENTS (from graph) ───
            if self._causation_graph is not None:
                try:
                    recent = self._causation_graph.get_recent_events(8)
                    if recent:
                        lines.append("")
                        lines.append("[bold white]┌─ RECENT EVENTS ──────────────────────────┐[/]")
                        for evt in recent:
                            etype = evt.event_type if hasattr(evt, 'event_type') else str(evt)
                            comp = evt.component if hasattr(evt, 'component') else '?'
                            eid = evt.event_id[:8] if hasattr(evt, 'event_id') else '?'
                            # Color by type
                            color = MerkleWidget._EVENT_COLORS.get(etype, 'dim white')
                            lines.append(f"  [{color}]▸ {eid}[/] {etype} [dim]({comp})[/]")
                        lines.append("[bold white]└──────────────────────────────────────────┘[/]")
                except Exception:
                    pass

                # ─── ROOT & LEAF EVENTS ───
                try:
                    roots = self._causation_graph.get_root_events()
                    leaves = self._causation_graph.get_leaf_events()
                    if roots or leaves:
                        lines.append("")
                        lines.append("[bold magenta]┌─ CAUSATION ENDPOINTS ────────────────────┐[/]")
                        if roots:
                            root_types = [r.event_type for r in roots[:3]] if hasattr(roots[0], 'event_type') else ['?']
                            lines.append(f"  [bold]Entry Points:[/] [dim]{', '.join(root_types)}[/] ({len(roots)} total)")
                        if leaves:
                            leaf_types = [l.event_type for l in leaves[:3]] if hasattr(leaves[0], 'event_type') else ['?']
                            lines.append(f"  [bold]Current State:[/] [dim]{', '.join(leaf_types)}[/] ({len(leaves)} total)")
                        lines.append("[bold magenta]└──────────────────────────────────────────┘[/]")
                except Exception:
                    pass

            # ─── FEED.JSONL BACKUP ───
            try:
                feed_file = _CASCADE_FEED_DIR / 'feed.jsonl' if _CASCADE_FEED_DIR else None
                if feed_file and feed_file.exists():
                    feed_lines = feed_file.read_text(encoding="utf-8").strip().split('\n')
                    lines.append("")
                    lines.append(f"[dim]📁 feed.jsonl: {len(feed_lines)} persisted events[/]")
            except Exception:
                pass

            # ─── IN-MEMORY EVENT LOG ───
            if self._cascade_events:
                lines.append("")
                lines.append("[bold]In-Memory Log (last 5):[/bold]")
                for evt in self._cascade_events[-5:]:
                    lines.append(f"  {evt}")

            return "\n".join(lines)
        
        async def on_mount(self):
            import asyncio
            brain_label = "🐍 OUROBOROS" if self.is_ouroboros else "🌾 SCARECROW ADAPTER" if self.brain_type == 'scarecrow' else "🏛️ COUNCIL ORCHESTRATOR" if self.brain_type == 'council' else f"🔮 {self.brain_type.upper()}"
            self._log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
            self._log(brain_label)
            self._log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
            self._log(f"Agent Gen {self.agent.generation} | Fitness {self.agent.fitness:.4f}")
            self._log("")
            if _CASCADE_AVAILABLE:
                self._log("✅ CASCADE-LATTICE active (provenance logging)")
            else:
                self._log("⚠️ CASCADE not installed - pip install cascade-lattice")
            self._log("")
            self._log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
            self._log("🚀 NEW USER? Type one of these:")
            self._log("   quickstart  → 3-step guide to get going")
            self._log("   help        → Full command reference")
            self._log("   about       → What is this thing?")
            self._log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
            self._log("")
            # Pre-populate bag with embedded artifacts
            try:
                added = populate_bag_with_embedded()
                if added > 0:
                    self._log(f"🎒 FelixBag loaded {added} embedded artifacts")
            except Exception as e:
                self._log(f"[dim]Bag init: {e}[/]")
            # Write initial state for external tools
            self._write_capsule_state()

            # 🔗 MCP→TUI bridge: _observe_mcp_tool calls _ACTIVE_TUI._record_cascade directly
            # No polling needed - mcp remote runs in-process, so direct function call works
