        async def action_vast(self, subcmd: str = None, args: list = None):
            """Control Vast.ai GPU rental for remote model hosting.
            
            Usage:
                vast                    - Show status and help
                vast search <query>     - Search GPU offers (e.g. 'gpu_ram>=48')
                vast rent <offer_id>    - Rent a GPU and deploy vLLM
                vast instances          - List your active instances
                vast connect <id>       - Route model inference to instance
                vast stop               - Destroy current instance
            """
            args = args or []
            
            # ═══════════════════════════════════════════════════════════════
            # AUTO SSH KEY SETUP - No user intervention required!
            # ═══════════════════════════════════════════════════════════════
            def ensure_ssh_key():
                """Auto-generate and register SSH key with Vast.ai if needed."""
                import subprocess
                from pathlib import Path as P
                ssh_dir = P.home() / '.ssh'
                key_path = ssh_dir / 'vastai_key'
                pub_path = ssh_dir / 'vastai_key.pub'
                
                # Create .ssh dir if needed
                ssh_dir.mkdir(parents=True, exist_ok=True)
                
                # Generate key if not exists (no passphrase)
                if not key_path.exists():
                    self._log("🔑 Generating SSH key for Vast.ai (no passphrase)...")
                    try:
                        result = subprocess.run([
                            'ssh-keygen', '-t', 'ed25519',
                            '-f', str(key_path),
                            '-N', '',  # Empty passphrase
                            '-C', 'vastai-auto'
                        ], capture_output=True, text=True, timeout=30)
                        if result.returncode != 0:
                            self._log(f"❌ SSH keygen failed: {result.stderr}")
                            return False
                        self._log(f"✅ SSH key generated: {key_path}")
                    except FileNotFoundError:
                        # ssh-keygen not available, try Python crypto
                        try:
                            from cryptography.hazmat.primitives import serialization
                            from cryptography.hazmat.primitives.asymmetric.ed25519 import Ed25519PrivateKey
                            
                            private_key = Ed25519PrivateKey.generate()
                            
                            # Save private key (no encryption)
                            private_bytes = private_key.private_bytes(
                                encoding=serialization.Encoding.PEM,
                                format=serialization.PrivateFormat.OpenSSH,
                                encryption_algorithm=serialization.NoEncryption()
                            )
                            key_path.write_bytes(private_bytes)
                            
                            # Save public key
                            public_key = private_key.public_key()
                            public_bytes = public_key.public_bytes(
                                encoding=serialization.Encoding.OpenSSH,
                                format=serialization.PublicFormat.OpenSSH
                            )
                            pub_path.write_bytes(public_bytes + b' vastai-auto\n')
                            
                            self._log(f"✅ SSH key generated (Python crypto): {key_path}")
                        except ImportError:
                            self._log("❌ Need ssh-keygen or: pip install cryptography")
                            return False
                        except Exception as e:
                            self._log(f"❌ Key generation failed: {e}")
                            return False
                
                # Read public key
                if not pub_path.exists():
                    self._log(f"❌ Public key not found: {pub_path}")
                    return False
                
                pubkey = pub_path.read_text().strip()
                
                # Register with Vast.ai (use 'create ssh-key' - 'set ssh-key' is deprecated)
                self._log("🔑 Registering SSH key with Vast.ai...")
                try:
                    result = subprocess.run(
                        ['vastai', 'create', 'ssh-key', pubkey],
                        capture_output=True, text=True, timeout=30
                    )
                    if result.returncode == 0:
                        self._log("✅ SSH key registered with Vast.ai")
                        return True
                    elif 'already' in result.stdout.lower() or 'already' in result.stderr.lower():
                        self._log("✅ SSH key already registered")
                        return True
                    else:
                        # Key might already be set, try anyway
                        self._log(f"⚠️ Key registration: {result.stdout or result.stderr}")
                        return True  # Proceed anyway
                except Exception as e:
                    self._log(f"⚠️ Could not register key: {e}")
                    return True  # Proceed anyway - key might already be set

            # Vast SDK initialization (uses module-level _vast_sdk globals)
            def _init_vast_sdk():
                """Initialize Vast.ai SDK with API key from environment."""
                global _vast_sdk, _vast_sdk_available
                if _vast_sdk is not None:
                    return _vast_sdk_available
                try:
                    from vastai import VastAI
                    api_key = os.environ.get('VAST_API_KEY', '')
                    if api_key:
                        _vast_sdk = VastAI(api_key=api_key)
                        _vast_sdk_available = True
                        return True
                    else:
                        # Try to read from vastai config file
                        config_path = Path.home() / '.vast_api_key'
                        if config_path.exists():
                            api_key = config_path.read_text().strip()
                            _vast_sdk = VastAI(api_key=api_key)
                            _vast_sdk_available = True
                            return True
                except ImportError:
                    pass
                except Exception:
                    pass
                return False
            
            def vast_available():
                """Check if Vast.ai SDK or CLI is available."""
                # Try SDK first
                if _init_vast_sdk():
                    return True
                # Fall back to CLI
                import subprocess
                try:
                    result = subprocess.run(['vastai', '--version'], capture_output=True, text=True, timeout=5)
                    return result.returncode == 0
                except Exception:
                    return False
            
            def run_vast(cmd_args, raw=True):
                """Run vastai command via SDK (preferred) or CLI fallback."""
                import subprocess
                import json
                
                # Try SDK first (no external CLI needed)
                if _init_vast_sdk() and _vast_sdk:
                    try:
                        # Map CLI commands to SDK methods
                        if len(cmd_args) >= 2:
                            action = cmd_args[0]
                            target = cmd_args[1]
                            
                            if action == 'search' and target == 'offers':
                                query = ' '.join(cmd_args[2:]) if len(cmd_args) > 2 else ''
                                return _vast_sdk.search_offers(query=query)
                            
                            elif action == 'show' and target == 'instances':
                                return _vast_sdk.show_instances()
                            
                            elif action == 'show' and target == 'instance':
                                instance_id = int(cmd_args[2]) if len(cmd_args) > 2 else 0
                                return _vast_sdk.show_instance(id=instance_id)
                            
                            elif action == 'create' and target == 'instance':
                                offer_id = int(cmd_args[2]) if len(cmd_args) > 2 else 0
                                # Parse additional args
                                image = 'vastai/pytorch:latest'
                                disk = 50
                                for arg in cmd_args[3:]:
                                    if arg.startswith('--image'):
                                        image = arg.split('=')[1] if '=' in arg else cmd_args[cmd_args.index(arg)+1]
                                    elif arg.startswith('--disk'):
                                        disk = int(arg.split('=')[1] if '=' in arg else cmd_args[cmd_args.index(arg)+1])
                                result = _vast_sdk.launch_instance(
                                    num_gpus=1,
                                    gpu_name=None,  # Use offer_id instead
                                    image=image,
                                    disk=disk,
                                )
                                return result
                            
                            elif action == 'destroy' and target == 'instance':
                                instance_id = int(cmd_args[2]) if len(cmd_args) > 2 else 0
                                return _vast_sdk.destroy_instance(id=instance_id)
                            
                            elif action == 'ssh-keys' and target == 'list':
                                return _vast_sdk.show_ssh_keys()
                            
                            elif action == 'create' and target == 'ssh-key':
                                ssh_key = cmd_args[2] if len(cmd_args) > 2 else ''
                                return _vast_sdk.create_ssh_key(ssh_key=ssh_key)
                    except Exception as sdk_err:
                        # SDK failed, fall through to CLI
                        pass
                
                # Fall back to CLI
                try:
                    full_cmd = ['vastai'] + cmd_args
                    if raw:
                        full_cmd.append('--raw')
                    result = subprocess.run(full_cmd, capture_output=True, text=True, timeout=60)
                    if result.returncode != 0:
                        return {'error': result.stderr or 'Command failed'}
                    if raw:
                        try:
                            return json.loads(result.stdout)
                        except Exception:
                            return {'output': result.stdout}
                    return {'output': result.stdout}
                except subprocess.TimeoutExpired:
                    return {'error': 'Command timed out'}
                except FileNotFoundError:
                    return {'error': 'vastai CLI not found. Set VAST_API_KEY env var or: pip install vastai'}
                except Exception as e:
                    return {'error': str(e)}
            
            if subcmd == 'search' and args:
                # Search for GPU offers - show ALL with pagination
                # Parse page number if present
                page = 1
                page_size = 20
                query_parts = []
                for arg in args:
                    if arg.startswith('page=') or arg.startswith('p='):
                        try:
                            page = int(arg.split('=')[1])
                        except Exception:
                            pass
                    elif arg.startswith('size='):
                        try:
                            page_size = int(arg.split('=')[1])
                        except Exception:
                            pass
                    else:
                        query_parts.append(arg)
                
                query = ' '.join(query_parts) if query_parts else 'rentable=true'
                self._log(f"🔍 Searching Vast.ai: {query}")
                result = run_vast(['search', 'offers', query])
                
                if 'error' in result:
                    self._log(f"❌ {result['error']}")
                    return
                
                offers = result if isinstance(result, list) else []
                self._vast_offers_cache = offers  # Cache ALL results
                
                if not offers:
                    self._log("📭 No offers found")
                    return
                
                # Pagination
                total = len(offers)
                total_pages = (total + page_size - 1) // page_size
                start_idx = (page - 1) * page_size
                end_idx = min(start_idx + page_size, total)
                page_offers = offers[start_idx:end_idx]
                
                self._log(f"━━━━━━ GPU OFFERS (Page {page}/{total_pages}, {total} total) ━━━━━━")
                self._log("")
                self._log("  #   | ID       | GPU              | VRAM  | $/hr   | Rel%  | GPUs")
                self._log("  ----+----------+------------------+-------+--------+-------+-----")
                
                for i, offer in enumerate(page_offers):
                    idx = start_idx + i + 1
                    gpu = offer.get('gpu_name', '?').replace('_', ' ')[:16]
                    vram = offer.get('gpu_ram', 0)
                    price = offer.get('dph_total', 0)
                    reliability = offer.get('reliability', 0) * 100
                    oid = str(offer.get('id', '?'))[:8]
                    num_gpus = offer.get('num_gpus', 1)
                    self._log(f"  {idx:3} | {oid:8} | {gpu:16} | {vram:5.0f}GB | ${price:5.2f} | {reliability:5.1f}% | {num_gpus}x")
                
                self._log("")
                self._log(f"📊 Showing {start_idx+1}-{end_idx} of {total} offers")
                if page < total_pages:
                    self._log(f"📄 Next page: vast search {query} page={page+1}")
                if page > 1:
                    self._log(f"📄 Prev page: vast search {query} page={page-1}")
                self._log("")
                self._log("💡 HUMAN: Pick a GPU number, then tell the AI")
                self._log("   AI: Run 'vast rent <number>' to rent your choice")
                
            elif subcmd == 'rent':
                # Rent a GPU instance (simple SSH-only approach)
                if not args:
                    self._log("❌ Usage: vast rent <offer_id>")
                    self._log("   Run 'vast search' first to find offers")
                    return
                
                # AUTO SSH KEY SETUP
                ensure_ssh_key()
                
                offer_id = args[0]
                # Check if it's a number referencing cache
                try:
                    idx = int(offer_id) - 1
                    if 0 <= idx < len(self._vast_offers_cache):
                        offer_id = str(self._vast_offers_cache[idx].get('id'))
                        self._log(f"📎 Using cached offer: {offer_id}")
                except ValueError:
                    pass

                # === RENTAL SAFETY GUARDS ===
                # Guard 1: Check rental limit
                if len(self._vast_instances) >= self._max_concurrent_rentals:
                    self._log(f"[bold red]BLOCKED: Rental limit reached ({self._max_concurrent_rentals})[/]")
                    self._log(f"   Active instances: {list(self._vast_instances.keys())}")
                    self._log("   Stop an existing instance first: vast stop <id>")
                    return

                # Guard 2: Check if another rental is in progress
                if self._rental_in_progress:
                    self._log("[bold red]BLOCKED: Another rental operation in progress[/]")
                    self._log("   Wait for the current rental to complete.")
                    return

                # Guard 3: Ensure existing instances are fully configured
                for iid, inst in self._vast_instances.items():
                    status = inst.get('status', 'unknown')
                    connected = inst.get('connected', False)
                    models = inst.get('models', [])

                    if status not in ['running', 'ready']:
                        self._log(f"[bold yellow]BLOCKED: Instance {iid} is still {status}[/]")
                        self._log("   Wait for it to be running before renting another.")
                        return

                    if status == 'running' and not connected:
                        self._log(f"[bold yellow]BLOCKED: Instance {iid} not connected[/]")
                        self._log(f"   Run: vast connect {iid}")
                        return

                    if connected and not models:
                        self._log(f"[bold yellow]BLOCKED: Instance {iid} has no models[/]")
                        self._log("   Load a model first: plug <model_name>")
                        return

                # Set rental in progress flag
                self._rental_in_progress = True

                self._log(f"🚀 Renting GPU instance...")
                self._log("   Image: vastai/pytorch:latest (pre-cached, SSH-ready)")

                result = run_vast([
                    'create', 'instance', offer_id,
                    '--image', 'vastai/pytorch:latest',
                    '--disk', '50',
                    '--ssh',
                    '--direct'
                ])

                if 'error' in result:
                    self._log(f"❌ {result['error']}")
                    self._rental_in_progress = False  # Reset flag on error
                    return

                if 'new_contract' in result:
                    new_instance_id = str(result['new_contract'])  # Ensure string for dict key
                    self._vast_instance_id = new_instance_id  # Set as current
                    
                    # Create state for this instance
                    instance_state = {
                        'id': new_instance_id,
                        'status': 'created',
                        'start_time': __import__('time').time(),
                        'gpu': None,
                        'cost_per_hr': 0.0,
                        'ssh_host': None,
                        'ssh_port': None,
                        'connected': False,
                        'models': [],  # Track models loaded on this instance
                    }
                    
                    # Try to get cost from cached offer
                    try:
                        idx = int(offer_id) - 1
                        if 0 <= idx < len(self._vast_offers_cache):
                            instance_state['cost_per_hr'] = self._vast_offers_cache[idx].get('dph_total', 0)
                            instance_state['gpu'] = self._vast_offers_cache[idx].get('gpu_name', 'GPU')
                    except Exception:
                        pass
                    
                    # Add to multi-instance tracking
                    self._vast_instances[new_instance_id] = instance_state
                    
                    # Also update legacy _vast_state for backward compat
                    self._vast_state['id'] = new_instance_id
                    self._vast_state['status'] = 'created'
                    self._vast_state['start_time'] = instance_state['start_time']
                    self._vast_state['cost_per_hr'] = instance_state['cost_per_hr']
                    self._vast_state['gpu'] = instance_state['gpu']
                    
                    # Start polling thread
                    self._start_vast_polling()
                    self._log(f"✅ Instance created: {new_instance_id}")
                    self._log(f"   📊 Total instances: {len(self._vast_instances)}")
                    self._log("   ⏳ Waiting for SSH to be ready...")
                    self._log("   💡 Use 'vast connect' once running")
                    # Switch to VAST tab
                    try:
                        self.query_one("#tabs", TabbedContent).active = "tab-vast"
                    except Exception:
                        pass
                    # Log to relay
                    try:
                        with open(self._relay_center, 'a', encoding='utf-8') as f:
                            f.write(f"# Vast.ai GPU rented: instance {new_instance_id}\n")
                    except Exception:
                        pass
                    # Reset rental flag and update display
                    self._rental_in_progress = False
                    self._update_vast_tab()
                else:
                    self._log(f"⚠️ Unexpected response: {result}")
                    self._rental_in_progress = False  # Reset on unexpected response too
            
            elif subcmd == 'details' or subcmd == 'info':
                # Show detailed info for a cached offer (for AI to present to human)
                if not args:
                    self._log("❌ Usage: vast details <number>")
                    self._log("   Run 'vast search' first")
                    return
                
                try:
                    idx = int(args[0]) - 1
                    if idx < 0 or idx >= len(self._vast_offers_cache):
                        self._log(f"❌ Invalid offer number. Have {len(self._vast_offers_cache)} cached.")
                        return
                    
                    offer = self._vast_offers_cache[idx]
                    self._log(f"━━━━━━ GPU OFFER DETAILS (#{idx+1}) ━━━━━━")
                    self._log("")
                    self._log(f"  Offer ID:      {offer.get('id', '?')}")
                    self._log(f"  GPU:           {offer.get('gpu_name', '?').replace('_', ' ')}")
                    self._log(f"  GPU Count:     {offer.get('num_gpus', 1)}x")
                    self._log(f"  VRAM:          {offer.get('gpu_ram', 0):.0f} GB")
                    self._log(f"  Total VRAM:    {offer.get('gpu_total_ram', 0):.0f} GB")
                    self._log("")
                    self._log(f"  Price/hr:      ${offer.get('dph_total', 0):.3f}")
                    self._log(f"  Storage/mo:    ${offer.get('storage_cost', 0):.2f}/GB")
                    self._log("")
                    self._log(f"  Reliability:   {offer.get('reliability', 0)*100:.1f}%")
                    self._log(f"  CUDA:          {offer.get('cuda_max_good', '?')}")
                    self._log(f"  Driver:        {offer.get('driver_version', '?')}")
                    self._log("")
                    self._log(f"  CPU Cores:     {offer.get('cpu_cores', '?')}")
                    self._log(f"  RAM:           {offer.get('cpu_ram', 0)/1024:.0f} GB")
                    self._log(f"  Disk:          {offer.get('disk_space', 0):.0f} GB")
                    self._log("")
                    self._log(f"  Net Down:      {offer.get('inet_down', 0):.0f} Mbps")
                    self._log(f"  Net Up:        {offer.get('inet_up', 0):.0f} Mbps")
                    self._log(f"  Location:      {offer.get('geolocation', '?')}")
                    self._log("")
                    self._log("💡 To rent this GPU: vast rent {idx+1}")
                    
                except ValueError:
                    self._log("❌ Please provide a number from the search results")
                
            elif subcmd == 'instances':
                # List active instances
                self._log("📋 Fetching your Vast.ai instances...")
                result = run_vast(['show', 'instances'])
                
                if 'error' in result:
                    self._log(f"❌ {result['error']}")
                    return
                
                instances = result if isinstance(result, list) else []
                if not instances:
                    self._log("📭 No active instances")
                    return
                
                # Update our tracking dict with fresh data
                for inst in instances:
                    iid = str(inst.get('id', '?'))
                    status = inst.get('actual_status', 'unknown')
                    gpu = inst.get('gpu_name', '?')
                    ssh = inst.get('ssh_host', '')
                    port = inst.get('ssh_port', '')
                    cost = inst.get('dph_total', 0.0)  # FIX: Extract cost from API
                    
                    # Update or create tracking entry
                    if iid not in self._vast_instances:
                        self._vast_instances[iid] = {
                            'id': iid,
                            'status': status,
                            'gpu': gpu,
                            'ssh_host': ssh,
                            'ssh_port': port,
                            'cost_per_hr': cost,  # FIX: Include cost in new entry
                            'connected': False,
                            'models': [],
                        }
                    else:
                        self._vast_instances[iid]['status'] = status
                        self._vast_instances[iid]['gpu'] = gpu
                        self._vast_instances[iid]['ssh_host'] = ssh
                        self._vast_instances[iid]['ssh_port'] = port
                        self._vast_instances[iid]['cost_per_hr'] = cost  # FIX: Update cost
                    
                    # Display with current instance indicator
                    is_current = (iid == str(self._vast_instance_id))
                    icon = '🟢' if status == 'running' else '🟡' if 'loading' in status else '🔴'
                    current_marker = ' ◀ CURRENT' if is_current else ''
                    self._log(f"  {icon} [{iid}] {gpu} - {status}{current_marker}")
                    if ssh:
                        self._log(f"      SSH: {ssh}:{port}")
                    
                    # Show models loaded on this instance
                    tracked = self._vast_instances.get(iid, {})
                    models = tracked.get('models', [])
                    if models:
                        self._log(f"      Models: {', '.join(models)}")
                
                # Show total cost
                total_cost = sum(inst.get('cost_per_hr', 0) for inst in self._vast_instances.values())
                if total_cost > 0:
                    self._log(f"\n💰 Total: ${total_cost:.2f}/hr across {len(instances)} instance(s)")
                
            elif subcmd == 'connect':
                # Connect to instance via SSH
                target_instance_id = None
                if args:
                    # Explicit instance ID provided
                    target_instance_id = args[0]
                elif self._vast_instance_id:
                    # Use last rented instance
                    target_instance_id = self._vast_instance_id
                else:
                    self._log("❌ Usage: vast connect <instance_id>")
                    self._log("   Or rent an instance first with 'vast rent'")
                    return
                
                # Update current instance ID
                self._vast_instance_id = target_instance_id
                
                self._log(f"🔗 Connecting to instance {target_instance_id} via SSH...")
                
                # Get SSH details
                result = run_vast(['show', 'instance', str(target_instance_id)])
                if 'error' in result:
                    self._log(f"❌ {result['error']}")
                    return
                
                ssh_host = result.get('ssh_host', '')
                ssh_port = result.get('ssh_port', 22)
                status = result.get('actual_status', '')
                
                if status != 'running':
                    self._log(f"⚠️ Instance not running (status: {status})")
                    self._log("   Wait for instance to start, then try again")
                    return
                
                if not ssh_host:
                    self._log("❌ SSH not ready yet")
                    return
                
                # Create RemoteGPUExecutor (embedded in capsule)
                try:
                    from pathlib import Path
                    
                    key_path = Path.home() / '.ssh' / 'id_rsa'
                    if not key_path.exists():
                        key_path = Path.home() / '.ssh' / 'vast_nopass'
                    
                    self._log(f"   Host: {ssh_host}:{ssh_port}")
                    self._log(f"   Key: {key_path}")
                    self._log("   Establishing SSH connection...")
                    
                    self._remote_gpu = RemoteGPUExecutor(
                        host=ssh_host,
                        port=ssh_port,
                        username='root',
                        key_path=str(key_path)
                    )
                    
                    if self._remote_gpu.connect():
                        self._log(f"✅ Connected to GPU via SSH!")
                        self._log(f"   💡 Models will now load on remote GPU")
                        self._log(f"   💡 Use 'plug MODEL' to load models on GPU")
                        
                        # Store connection details
                        self._vast_state['ssh_host'] = ssh_host
                        self._vast_state['ssh_port'] = ssh_port
                        self._vast_state['connected'] = True
                        
                        # Update multi-instance tracking
                        target_id_str = str(target_instance_id)
                        if target_id_str in self._vast_instances:
                            self._vast_instances[target_id_str]['connected'] = True
                            self._vast_instances[target_id_str]['ssh_host'] = ssh_host
                            self._vast_instances[target_id_str]['ssh_port'] = ssh_port
                        
                        # Store executor for this instance (for broadcast)
                        self._remote_gpus[target_id_str] = self._remote_gpu
                        
                        # Mark other instances as not the current focus
                        for iid in self._vast_instances:
                            if iid != target_id_str:
                                self._vast_instances[iid]['connected'] = False
                        # Update VAST tab to show connection status change
                        self._update_vast_tab()
                    else:
                        self._log(f"❌ SSH connection failed")
                        self._log(f"   Check that instance is running and SSH is ready")
                        self._remote_gpu = None
                    
                except ImportError:
                    self._log(f"❌ remote_gpu module not found")
                    self._log(f"   Install paramiko: pip install paramiko")
                except Exception as e:
                    self._log(f"❌ Connection failed: {e}")
                    self._remote_gpu = None
            
            elif subcmd == 'logs':
                # Show instance logs (for debugging auto-deploy)
                if not self._vast_instance_id:
                    self._log("❌ No active Vast.ai instance")
                    self._log("   Use 'vast rent' first")
                    return
                
                tail_count = '50'
                if args:
                    try:
                        tail_count = str(int(args[0]))
                    except ValueError:
                        pass
                
                self._log(f"📋 Fetching last {tail_count} lines of instance logs...")
                
                result = run_vast(['logs', str(self._vast_instance_id), '--tail', tail_count])
                
                if 'error' in result:
                    self._log(f"❌ {result['error']}")
                    return
                
                logs = result.get('logs', '') or str(result)
                if not logs:
                    self._log("   (No logs available yet)")
                else:
                    self._log("━━━━━━ INSTANCE LOGS ━━━━━━")
                    for line in logs.strip().split('\n')[-int(tail_count):]:
                        self._log(f"  {line}")
                    self._log("━━━━━━━━━━━━━━━━━━━━━━━━━━━")
            
            elif subcmd == 'stop' or subcmd == 'destroy':
                # Stop and destroy instance
                target_id = None
                if args:
                    # Explicit instance ID provided
                    target_id = args[0]
                elif self._vast_instance_id:
                    target_id = self._vast_instance_id
                else:
                    self._log("❌ No active Vast.ai instance")
                    self._log("   Usage: vast stop <instance_id>")
                    self._log("   Or use 'vast instances' to see all instances")
                    return
                
                self._log(f"🛑 Destroying instance {target_id}...")
                result = run_vast(['destroy', 'instance', str(target_id)])
                
                if 'error' in result:
                    self._log(f"❌ {result['error']}")
                    return
                
                self._log("✅ Instance destroyed")
                
                # Remove from multi-instance tracking
                target_id_str = str(target_id)
                if target_id_str in self._vast_instances:
                    del self._vast_instances[target_id_str]
                    self._log(f"   📊 Remaining instances: {len(self._vast_instances)}")
                
                # Remove from remote GPUs dict
                if target_id_str in self._remote_gpus:
                    del self._remote_gpus[target_id_str]
                
                # If this was the current instance, clear it
                if str(self._vast_instance_id) == target_id_str:
                    self._vast_instance_id = None
                    self._remote_gpu = None
                    # Stop polling only if no instances left
                    if not self._vast_instances:
                        self._stop_vast_polling()
                        self._vast_state = {
                            'id': None,
                            'status': 'OFF',
                            'gpu': None,
                            'public_ip': None,
                            'mcp_url': None,
                            'ssh_host': None,
                            'ssh_port': None,
                            'cost_per_hr': 0.0,
                            'start_time': None,
                            'logs': [],
                            'gpu_util': 0,
                            'vram_used': 0,
                            'vram_total': 0,
                        }
                
                # Update displays
                self._update_vast_tab()
                self.query_one("#info", Static).update(self._render_info())
            
            elif subcmd == 'broadcast':
                # Broadcast command to ALL connected GPU instances
                if not args:
                    self._log("❌ Usage: vast broadcast <command>")
                    self._log("   Example: vast broadcast plug codellama/CodeLlama-13b-Instruct-hf")
                    return
                
                cmd_to_broadcast = ' '.join(args)
                connected_gpus = {iid: gpu for iid, gpu in self._remote_gpus.items() if gpu and gpu._connected}
                
                if not connected_gpus:
                    self._log("❌ No connected GPU instances")
                    self._log("   Use 'vast connect <id>' to connect to instances first")
                    return
                
                self._log(f"📡 Broadcasting to {len(connected_gpus)} GPU(s): {cmd_to_broadcast}")
                self._log("━" * 50)
                
                import threading
                results = {}
                
                def send_to_gpu(instance_id, executor):
                    try:
                        # Write command to remote relay file
                        relay_cmd = f'echo "{cmd_to_broadcast}" >> /workspace/.relay_center.cmd'
                        result = executor.execute(relay_cmd)
                        
                        # Wait a moment for execution
                        __import__('time').sleep(2)
                        
                        # Read result from remote log
                        log_result = executor.execute('tail -20 /workspace/tui.log 2>/dev/null || echo "No log"')
                        results[instance_id] = {
                            'status': 'ok',
                            'output': log_result.get('output', '') if isinstance(log_result, dict) else str(log_result)
                        }
                    except Exception as e:
                        results[instance_id] = {'status': 'error', 'error': str(e)}
                
                # Send to all GPUs in parallel
                threads = []
                for iid, executor in connected_gpus.items():
                    t = threading.Thread(target=send_to_gpu, args=(iid, executor))
                    t.start()
                    threads.append(t)
                
                # Wait for all to complete
                for t in threads:
                    t.join(timeout=30)
                
                # Report results
                for iid, res in results.items():
                    gpu_name = self._vast_instances.get(iid, {}).get('gpu', 'GPU')
                    if res.get('status') == 'ok':
                        self._log(f"✅ [{iid}] {gpu_name}")
                        # Show last few lines of output
                        output_lines = res.get('output', '').strip().split('\n')[-5:]
                        for line in output_lines:
                            if line.strip():
                                self._log(f"   {line}")
                    else:
                        self._log(f"❌ [{iid}] {gpu_name}: {res.get('error', 'Unknown error')}")
                
                self._log("━" * 50)
                self._log(f"📡 Broadcast complete: {len([r for r in results.values() if r.get('status') == 'ok'])}/{len(connected_gpus)} succeeded")
            
            elif subcmd == 'distribute':
                # Distribute different commands to specific GPU instances
                # Syntax: vast distribute <id>:<cmd> <id>:<cmd> ...
                if not args:
                    self._log("❌ Usage: vast distribute <instance_id>:<command> ...")
                    self._log("   Example: vast distribute 30736390:plug codellama 30736411:plug mistral")
                    return
                
                # Parse id:command pairs
                tasks = {}
                current_id = None
                current_cmd_parts = []
                
                for arg in args:
                    if ':' in arg and arg.split(':')[0].isdigit():
                        # Save previous task if exists
                        if current_id and current_cmd_parts:
                            tasks[current_id] = ' '.join(current_cmd_parts)
                        # Start new task
                        parts = arg.split(':', 1)
                        current_id = parts[0]
                        current_cmd_parts = [parts[1]] if len(parts) > 1 and parts[1] else []
                    else:
                        # Continue current command
                        if current_id:
                            current_cmd_parts.append(arg)
                
                # Save last task
                if current_id and current_cmd_parts:
                    tasks[current_id] = ' '.join(current_cmd_parts)
                
                if not tasks:
                    self._log("❌ No valid tasks parsed")
                    self._log("   Format: <instance_id>:<command>")
                    return
                
                # Validate all target instances are connected
                missing = []
                for iid in tasks:
                    if iid not in self._remote_gpus or not self._remote_gpus[iid]._connected:
                        missing.append(iid)
                
                if missing:
                    self._log(f"❌ Instances not connected: {', '.join(missing)}")
                    self._log("   Use 'vast connect <id>' first")
                    return
                
                self._log(f"📦 Distributing {len(tasks)} task(s):")
                for iid, cmd in tasks.items():
                    gpu_name = self._vast_instances.get(iid, {}).get('gpu', 'GPU')
                    self._log(f"   [{iid}] {gpu_name} ← {cmd}")
                self._log("━" * 50)
                
                import threading
                results = {}
                
                def send_task(instance_id, command):
                    executor = self._remote_gpus.get(instance_id)
                    if not executor:
                        results[instance_id] = {'status': 'error', 'error': 'No executor'}
                        return
                    try:
                        # Write command to remote relay file
                        relay_cmd = f'echo "{command}" >> /workspace/.relay_center.cmd'
                        result = executor.execute(relay_cmd)
                        
                        # Wait for execution
                        __import__('time').sleep(3)
                        
                        # Read result from remote log
                        log_result = executor.execute('tail -15 /workspace/tui.log 2>/dev/null || echo "No log"')
                        results[instance_id] = {
                            'status': 'ok',
                            'command': command,
                            'output': log_result.get('output', '') if isinstance(log_result, dict) else str(log_result)
                        }
                    except Exception as e:
                        results[instance_id] = {'status': 'error', 'command': command, 'error': str(e)}
                
                # Execute all tasks in parallel
                threads = []
                for iid, cmd in tasks.items():
                    t = threading.Thread(target=send_task, args=(iid, cmd))
                    t.start()
                    threads.append(t)
                
                # Wait for completion
                for t in threads:
                    t.join(timeout=60)
                
                # Report results
                for iid, res in results.items():
                    gpu_name = self._vast_instances.get(iid, {}).get('gpu', 'GPU')
                    cmd = res.get('command', '?')
                    if res.get('status') == 'ok':
                        self._log(f"✅ [{iid}] {gpu_name}: {cmd}")
                        output_lines = res.get('output', '').strip().split('\n')[-3:]
                        for line in output_lines:
                            if line.strip():
                                self._log(f"   {line}")
                    else:
                        self._log(f"❌ [{iid}] {gpu_name}: {res.get('error', 'Unknown error')}")
                
                self._log("━" * 50)
                succeeded = len([r for r in results.values() if r.get('status') == 'ok'])
                self._log(f"📦 Distribution complete: {succeeded}/{len(tasks)} succeeded")
            
            elif subcmd == 'ready':
                # Check if instance is ready with Ouroboros stack
                if not self._vast_instance_id:
                    self._log("❌ No active Vast.ai instance")
                    return
                
                self._log(f"🔍 Checking if instance {self._vast_instance_id} is ready...")
                
                # Check via SSH if connected
                if self._remote_gpu and self._remote_gpu._connected:
                    try:
                        result = self._remote_gpu.execute("cat /tmp/ouroboros_ready 2>/dev/null || echo 'NOT_READY'")
                        output = result.get('output', '') if isinstance(result, dict) else str(result)
                        if 'OUROBOROS_READY=1' in output:
                            self._log("✅ Instance READY - Ouroboros stack installed")
                            self._log("   💡 Use 'vast load MODEL' to load a model")
                        else:
                            self._log("⏳ Instance still setting up...")
                            self._log("   Packages installing via onstart script")
                    except Exception as e:
                        self._log(f"⚠️ Could not check: {e}")
                else:
                    self._log("⚠️ Not connected - use 'vast connect' first")
            
            elif subcmd == 'run':
                # Execute Python code on remote GPU
                if not args:
                    self._log("❌ Usage: vast run <python_code>")
                    self._log("   Example: vast run print(torch.cuda.is_available())")
                    return
                
                if not self._remote_gpu or not self._remote_gpu._connected:
                    self._log("❌ Not connected to GPU - use 'vast connect' first")
                    return
                
                code = ' '.join(args)
                self._log(f"🐍 Executing on GPU: {code[:50]}...")
                
                try:
                    # Send Python code directly to the REPL (not shell commands!)
                    result = self._remote_gpu.execute(code)
                    output = result.get('output', '') if isinstance(result, dict) else str(result)
                    self._log("━━━━━━ OUTPUT ━━━━━━")
                    for line in output.strip().split('\n'):
                        self._log(f"  {line}")
                    self._log("━━━━━━━━━━━━━━━━━━━━")
                except Exception as e:
                    self._log(f"❌ Execution failed: {e}")
            
            elif subcmd == 'load':
                # Load HuggingFace model on remote GPU
                if not args:
                    self._log("❌ Usage: vast load <model_id> [quantization]")
                    self._log("   Example: vast load BAAI/bge-small-en-v1.5")
                    self._log("   Example: vast load meta-llama/Llama-2-7b-hf 4bit")
                    return
                
                if not self._remote_gpu or not self._remote_gpu._connected:
                    self._log("❌ Not connected to GPU - use 'vast connect' first")
                    return
                
                model_id = args[0]
                quant = args[1] if len(args) > 1 else 'auto'
                
                self._log("⬇️ Loading " + model_id + " on remote GPU...")
                self._log("   Quantization: " + quant)
                
                try:
                    # Build load script - use string concat to avoid f-string backslash issues
                    # Uses AutoModelForCausalLM for text generation (matches MCP)
                    # Saves to /tmp/ouroboros_model.pkl (matches MCP path)
                    nl = "\n"
                    q = '\"'
                    lb = "{"  # left brace escaped for f-string
                    rb = "}"  # right brace escaped for f-string
                    load_script = (
                        "import torch" + nl +
                        "from transformers import AutoModelForCausalLM, AutoTokenizer, BitsAndBytesConfig" + nl +
                        "import json" + nl +
                        "import pickle" + nl +
                        "model_id = " + q + model_id + q + nl +
                        "quant = " + q + quant + q + nl +
                        "try:" + nl +
                        "    print('Loading tokenizer...')" + nl +
                        "    tokenizer = AutoTokenizer.from_pretrained(model_id, trust_remote_code=True)" + nl +
                        "    if quant == " + q + "4bit" + q + ":" + nl +
                        "        bnb_config = BitsAndBytesConfig(load_in_4bit=True, bnb_4bit_quant_type='nf4', bnb_4bit_compute_dtype=torch.float16, bnb_4bit_use_double_quant=True)" + nl +
                        "    elif quant == " + q + "8bit" + q + ":" + nl +
                        "        bnb_config = BitsAndBytesConfig(load_in_8bit=True)" + nl +
                        "    else:" + nl +
                        "        bnb_config = None" + nl +
                        "    print('Loading model with quantization=' + quant + '...')" + nl +
                        "    model = AutoModelForCausalLM.from_pretrained(model_id, quantization_config=bnb_config, device_map=" + q + "auto" + q + ", trust_remote_code=True)" + nl +
                        "    with open('/tmp/ouroboros_model.pkl', 'wb') as f:" + nl +
                        "        pickle.dump(" + lb + "'model_id': model_id, 'quantization': quant" + rb + ", f)" + nl +
                        "    inputs = tokenizer('Hello, I am', return_tensors='pt').to(model.device)" + nl +
                        "    outputs = model.generate(**inputs, max_new_tokens=20, do_sample=False)" + nl +
                        "    test_output = tokenizer.decode(outputs[0], skip_special_tokens=True)" + nl +
                        "    print(json.dumps(" + lb + q + "status" + q + ": " + q + "loaded" + q + ", " + q + "model" + q + ": model_id, " + q + "device" + q + ": str(model.device), " + q + "test" + q + ": test_output" + rb + "))" + nl +
                        "except Exception as e:" + nl +
                        "    print(json.dumps(" + lb + q + "status" + q + ": " + q + "error" + q + ", " + q + "error" + q + ": str(e)" + rb + "))"
                    )
                    result = self._remote_gpu.execute('python3 -c "' + load_script + '"')
                    output = result.get('output', '') if isinstance(result, dict) else str(result)
                    
                    import json
                    try:
                        resp = json.loads(output.strip().split('\n')[-1])
                        if resp.get('status') == 'loaded':
                            self._log("✅ Loaded " + model_id)
                            self._log("   Device: " + resp.get('device', 'unknown'))
                        else:
                            self._log("❌ Load failed: " + resp.get('error', 'unknown'))
                    except Exception:
                        self._log("⚠️ Response: " + output[:200])
                except Exception as e:
                    self._log("❌ Load failed: " + str(e))
            
            elif subcmd == 'generate':
                # Generate text on remote GPU
                if not args:
                    self._log("❌ Usage: vast generate <prompt>")
                    self._log("   Example: vast generate What is the meaning of life?")
                    return
                
                if not self._remote_gpu or not self._remote_gpu._connected:
                    self._log("❌ Not connected to GPU - use 'vast connect' first")
                    return
                
                prompt = ' '.join(args)
                self._log("🤖 Generating from: " + prompt[:50] + "...")
                
                try:
                    # Build generate script - matches MCP vast_generate
                    # Uses pickle path /tmp/ouroboros_model.pkl (same as vast load)
                    # Note: Extra escaping for f-string quine context
                    escaped_prompt = prompt.replace('\\', '\\\\').replace('"', '\\"').replace("'", "\\'")
                    nl = "\n"
                    q = '\"'
                    lb = "{"  # left brace escaped for f-string
                    rb = "}"  # right brace escaped for f-string
                    gen_script = (
                        "import torch" + nl +
                        "import json" + nl +
                        "import pickle" + nl +
                        "try:" + nl +
                        "    with open('/tmp/ouroboros_model.pkl', 'rb') as f:" + nl +
                        "        model_info = pickle.load(f)" + nl +
                        "    model_id = model_info['model_id']" + nl +
                        "    quant = model_info.get('quantization', 'none')" + nl +
                        "    from transformers import AutoModelForCausalLM, AutoTokenizer, BitsAndBytesConfig" + nl +
                        "    tokenizer = AutoTokenizer.from_pretrained(model_id, trust_remote_code=True)" + nl +
                        "    if quant == '4bit':" + nl +
                        "        bnb_config = BitsAndBytesConfig(load_in_4bit=True, bnb_4bit_quant_type='nf4', bnb_4bit_compute_dtype=torch.float16)" + nl +
                        "    elif quant == '8bit':" + nl +
                        "        bnb_config = BitsAndBytesConfig(load_in_8bit=True)" + nl +
                        "    else:" + nl +
                        "        bnb_config = None" + nl +
                        "    model = AutoModelForCausalLM.from_pretrained(model_id, quantization_config=bnb_config, device_map='auto', trust_remote_code=True)" + nl +
                        "    prompt = '" + escaped_prompt + "'" + nl +
                        "    inputs = tokenizer(prompt, return_tensors='pt').to(model.device)" + nl +
                        "    _in_len = inputs['input_ids'].shape[-1]" + nl +
                        "    outputs = model.generate(**inputs, max_new_tokens=256, do_sample=True, temperature=0.7)" + nl +
                        "    text = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)" + nl +
                        "    print(json.dumps(" + lb + "'status': 'ok', 'text': text, 'model': model_id" + rb + "))" + nl +
                        "except Exception as e:" + nl +
                        "    print(json.dumps(" + lb + "'status': 'error', 'error': str(e)" + rb + "))"
                    )
                    result = self._remote_gpu.execute('python3 -c "' + gen_script + '"')
                    output = result.get('output', '') if isinstance(result, dict) else str(result)
                    
                    import json
                    try:
                        resp = json.loads(output.strip().split('\n')[-1])
                        if resp.get('status') == 'ok':
                            self._log("━━━━━━ GENERATED ━━━━━━")
                            self._log(resp.get('text', ''))
                            self._log("━━━━━━━━━━━━━━━━━━━━━━━")
                        else:
                            self._log("❌ Generate failed: " + resp.get('error', 'unknown'))
                    except Exception:
                        self._log("⚠️ Response: " + output[:200])
                except Exception as e:
                    self._log("❌ Generate failed: " + str(e))
            
            elif subcmd == 'embed':
                # Generate embeddings on remote GPU
                # Matches MCP vast_embed - uses bge-large by default
                if not args:
                    self._log("❌ Usage: vast embed <text> [model]")
                    self._log("   Example: vast embed Hello world")
                    self._log("   Example: vast embed Hello world BAAI/bge-small-en-v1.5")
                    self._log("   Default model: BAAI/bge-large-en-v1.5 (1024 dims)")
                    return
                
                if not self._remote_gpu or not self._remote_gpu._connected:
                    self._log("❌ Not connected to GPU - use 'vast connect' first")
                    return
                
                # Check if last arg looks like a model ID
                embed_model = "BAAI/bge-large-en-v1.5"  # Match MCP default
                if len(args) > 1 and '/' in args[-1]:
                    embed_model = args[-1]
