            # Apply alias mapping - translate MCP tool names to TUI commands
            if action in _MCP_TO_TUI_ALIASES:
                alias_cmd = _MCP_TO_TUI_ALIASES[action]
                if ' ' in alias_cmd:
                    # Multi-word alias (e.g., 'hub search')
                    alias_parts = alias_cmd.split()
                    action = alias_parts[0]
                    args = alias_parts[1:] + args
                else:
                    action = alias_cmd
            
            # 🔗 UNIVERSAL CASCADE - every command merkle-hashed. One system.
            self._record_cascade(action, {
                'command': action,
                'args': ' '.join(args) if args else '',
                'source': 'relay' if hasattr(event, '__class__') and event.__class__.__name__ == 'E' else 'user',
            })

            if action == 'plug' and args:
                model_id = args[0]
