                def _generate_worker(model=model, prompt=prompt, model_source=model_source):
                    import time as t
                    t0 = t.perf_counter()
                    try:
                        result = model.generate(prompt)
                        elapsed = (t.perf_counter() - t0) * 1000
                        return result, elapsed, model_source, len(prompt), None
                    except Exception as e:
                        return None, 0, model_source, len(prompt), str(e)
                
                def _on_generate_complete(result):
                    res, elapsed, src, prompt_len, error = result
