                    self._log("    text-classification   Sentiment, topics")
                    self._log("    question-answering    QA models")
                    self._log("    summarization         Text summarizers")
                    self._log("    translation           Language translation")
                    self._log("")
                    self._log("  EMBEDDINGS:")
                    self._log("    feature-extraction    Embedding models (BGE, E5)")
                    self._log("    sentence-similarity   Sentence transformers")
                    self._log("")
