                    self._log("    image-classification  Image classifiers")
                    self._log("    object-detection      YOLO, DETR")
                    self._log("    image-segmentation    Semantic/instance seg")
                    self._log("    image-to-text         Image captioning")
                    self._log("    text-to-image         Stable Diffusion, DALL-E")
                    self._log("    depth-estimation      Depth prediction")
                    self._log("    video-classification  Video understanding")
                    self._log("")
                    self._log("  AUDIO:")
                    self._log("    automatic-speech-recognition  Whisper, etc.")
                    self._log("    text-to-speech        TTS models")
                    self._log("    audio-classification  Sound classification")
                    self._log("")
                    self._log("  MULTIMODAL:")
                    self._log("    visual-question-answering  VQA models")
                    self._log("    image-text-to-text    LLaVA, etc.")
                    self._log("    document-question-answering  DocVQA")
                    self._log("")
