    # NORMAL MODE - Direct agent access (TUI not running)
    # ═══════════════════════════════════════════════════════════════
    
    # Shared agent singleton - use provided agent or create new
    # Defined before FastMCP so _build_mcp_instructions() can access council state
    _agent_cache = {'agent': shared_agent} if shared_agent else {}

    def get_agent():
        if 'agent' not in _agent_cache:
            _agent_cache['agent'] = CapsuleAgent()
            # Wire HOLD brain ref for reward capture
            if _HOLD_AVAILABLE:
                try:
                    _router = _agent_cache['agent']._brain if hasattr(_agent_cache['agent'], '_brain') else None
                    _rbrain = getattr(_router, '_brain', _router) if _router else None
                    if _rbrain:
                        _HOLD_SYSTEM._brain_ref = _rbrain
                except Exception:
                    pass
        return _agent_cache['agent']

    mcp = FastMCP(capsule_name + "-quine", instructions=_build_mcp_instructions(), host=host or '127.0.0.1', port=port)
    
    # Store transport mode for later
    _transport_mode = 'http' if host else 'stdio'
    _http_host = host
    _http_port = port
    
