    _rerun_initialized = False
    _rerun_inference_step = 0
    
    @logged_tool()
    def start_rerun_viewer(recording_name: str = None) -> str:
        """Start Rerun visualization viewer for observing inference.

        If a Rerun viewer is already running (from TUI init), this reuses
        that recording instead of creating a duplicate.

        Args:
            recording_name: Optional name for this recording session

        Returns:
            JSON with viewer status
        """
        nonlocal _rerun_initialized
        if not _HAS_RERUN:
            return json.dumps({"error": "Rerun not installed. Run: pip install rerun-sdk"})

        # If TUI already initialized rerun, reuse it
        if _RERUN_INITIALIZED:
            _rerun_initialized = True
            return json.dumps({"status": "ok", "recording": "shared_with_tui", "message": "Rerun already active (shared with TUI)"})

        try:
            import rerun as rr
            import rerun.blueprint as rrb
            name = recording_name or f"{Path(__file__).stem}_session"
            rr.init(name, spawn=True)

            # Apply the canonical Glass Box blueprint
            _apply_glass_box_blueprint()
            _log_capsule_metadata()

            # Log initial capsule info
            agent = get_agent()
            gen = getattr(agent, 'generation', 0)
            fit = getattr(agent, 'fitness', 0.0)
            rr.log("logs", rr.TextLog(f"🔌 MCP Debug Session: Gen {gen}, Fitness {fit:.4f}", level=rr.TextLogLevel.INFO))
            rr.log("capsule/state", rr.TextDocument(f"Generation: {gen}\nFitness: {fit:.4f}\nBrain: {_BRAIN_CONFIG.get('brain_type', 'unknown')}"))

            _rerun_initialized = True
            return json.dumps({"status": "ok", "recording": name, "message": "Rerun viewer spawned with Glass Box blueprint"})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def log_to_rerun(entity_path: str, data_type: str, value: str) -> str:
        """Log data to Rerun viewer for visualization.
        
        Args:
            entity_path: Path in rerun hierarchy (e.g., 'brain/inference/step_1')
            data_type: Type of data - 'scalar', 'text', 'tensor', 'point3d', 'log'
            value: The value to log (JSON string for complex types)
        
        Returns:
            Confirmation JSON
        """
        if not _HAS_RERUN:
            return json.dumps({"error": "Rerun not installed"})
        
        try:
            import rerun as rr
            if data_type == 'scalar':
                rr.log(entity_path, rr.Scalars([float(value)]))
            elif data_type == 'text':
                rr.log(entity_path, rr.TextDocument(value))
            elif data_type == 'log':
                rr.log(entity_path, rr.TextLog(value, level=rr.TextLogLevel.INFO))
            elif data_type == 'tensor':
                arr = np.array(json.loads(value))
                rr.log(entity_path, rr.Tensor(arr))
            elif data_type == 'point3d':
                points = np.array(json.loads(value))
                rr.log(entity_path, rr.Points3D(points))
            elif data_type == 'bar':
                vals = json.loads(value) if isinstance(value, str) else value
                rr.log(entity_path, rr.BarChart(vals))
            else:
                rr.log(entity_path, rr.TextDocument(str(value)))
            return json.dumps({"status": "ok", "path": entity_path})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def rerun_log_inference(text: str = "", step: int = None) -> str:
        """Run inference and log full pipeline to Rerun for debugging.
        
        Args:
            text: Optional text input
            step: Optional step number (auto-increments if not provided)
        
        Returns:
            JSON with inference result and Rerun log status
        """
        nonlocal _rerun_inference_step
        if not _HAS_RERUN or not _rerun_initialized:
            return json.dumps({"error": "Rerun not initialized. Call start_rerun_viewer first."})
        
        try:
            import rerun as rr
            
            # Auto-increment step
            if step is None:
                _rerun_inference_step += 1
                step = _rerun_inference_step
            
            rr.set_time("inference", sequence=step)
            
            agent = get_agent()
            brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
            
            # Log input
            rr.log("logs", rr.TextLog(f"📥 Inference #{step}: '{text[:50]}...'", level=rr.TextLogLevel.DEBUG))
            
            # Create observation
            obs = {'text': text or 'test', 'input': np.random.rand(384).astype(np.float32)}
            
            # Run forward
            result = agent.forward(obs)
            
            # Log embedding if available
            if 'embedding' in result:
                emb = result['embedding']
                if hasattr(emb, 'tolist'):
                    emb = emb.tolist()
                rr.log("inference/embedding", rr.Tensor(np.array(emb[:64])))  # First 64 dims
                rr.log("metrics/embedding_norm", rr.Scalars([float(np.linalg.norm(emb))]))
            
            # Log action if available
            if 'action' in result:
                act = result['action']
                if hasattr(act, 'tolist'):
                    act = act.tolist()
                if isinstance(act, list):
                    rr.log("inference/action", rr.BarChart(act))
            
            # Log confidence
            if 'confidence' in result:
                rr.log("metrics/confidence", rr.Scalars([float(result['confidence'])]))
            
            rr.log("logs", rr.TextLog(f"✅ Inference #{step} complete", level=rr.TextLogLevel.INFO))
            
            # Serialize for return (recursive to handle nested numpy arrays)
            serialized = _sanitize_for_hash(result)

            return json.dumps({"step": step, "logged": True, "result": serialized}, indent=2)
        except Exception as e:
            import traceback
            return json.dumps({"error": str(e), "traceback": traceback.format_exc()})
    
    @logged_tool()
    def rerun_log_evolution() -> str:
        """Log full evolution history to Rerun as time series.
        
        Returns:
            JSON with log status
        """
        if not _HAS_RERUN:
            return json.dumps({"error": "Rerun not installed"})
        
        try:
            import rerun as rr
            agent = get_agent()
            prov = agent.get_full_provenance()
            
            pop_ctx = prov.get('population_context', {})
            history = pop_ctx.get('recent_history', [])
            trajectory = pop_ctx.get('fitness_trajectory', {})
            
            # Log trajectory
            gens = trajectory.get('generations', [])
            best = trajectory.get('best_fitness', [])
            avg = trajectory.get('avg_fitness', [])
            
            for i, gen in enumerate(gens):
                rr.set_time("evolution", sequence=gen)
                if i < len(best):
                    rr.log("evolution/best_fitness", rr.Scalars([best[i]]))
                if i < len(avg):
                    rr.log("evolution/avg_fitness", rr.Scalars([avg[i]]))
            
            rr.log("logs", rr.TextLog(f"📊 Logged {len(gens)} generations of evolution", level=rr.TextLogLevel.INFO))
            
            return json.dumps({"status": "ok", "generations_logged": len(gens)})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
