    @logged_tool()
    def chat(message: str, slot: int = None, system_prompt: str = None) -> str:
        """Multi-turn chat with LLM in a slot.
        
        Args:
            message: User message
            slot: Specific slot index (None = first LLM found)
            system_prompt: Optional system prompt for first message
        
        Returns:
            JSON with assistant response and conversation state
        """
        nonlocal _chat_history
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots for chat", "brain_type": type(brain).__name__})
        
        # Find LLM slot
        target_slot = None
        for i, c in enumerate(brain.councilors):
            if slot is not None and i != slot:
                continue
            model = getattr(c, 'model', None)
            if model and hasattr(model, 'generate'):
                target_slot = c
                break
        
        if not target_slot:
            return json.dumps({"error": "No LLM found in slots. Plug an LLM model first.", "available_slots": len(brain.councilors)})
        
        # Build conversation
        if not _chat_history:
            _sys = system_prompt if system_prompt else _council_system_prompt(i, brain)
            _chat_history.append({"role": "system", "content": _sys})
        _chat_history.append({"role": "user", "content": message})
        
        # Generate response
        try:
            model = target_slot.model
            tokenizer = getattr(target_slot, 'tokenizer', None)
            _lim = getattr(target_slot, '_limits', getattr(model, '_limits', {}))
            _ctx = _lim.get('context_length', 4096)
            _gen = _lim.get('max_gen_tokens', 256)

            if tokenizer and hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                prompt = tokenizer.apply_chat_template(_chat_history, tokenize=False, add_generation_prompt=True)
            else:
                prompt = "\n".join([f"{m['role']}: {m['content']}" for m in _chat_history]) + "\nassistant:"

            if hasattr(model, 'generate'):
                if getattr(model, '_is_remote_provider', False):
                    response = model.generate(prompt=prompt, messages=_chat_history, max_tokens=_gen, temperature=0.7)
                elif tokenizer:
                    _raw = getattr(model, 'model', model)
                    inputs = tokenizer(prompt, return_tensors="pt", truncation=True, max_length=_ctx)
                    _in_len = inputs['input_ids'].shape[-1]
                    outputs = _raw.generate(**inputs, max_new_tokens=_gen, do_sample=True, temperature=0.7, pad_token_id=tokenizer.eos_token_id)
                    response = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                else:
                    try:
                        response = model.generate(prompt=prompt, max_tokens=_gen, temperature=0.7)
                    except TypeError:
                        response = model.generate(prompt)
            else:
                response = "Model does not support generation"
            
            _chat_history.append({"role": "assistant", "content": response})
            return json.dumps({"response": response, "turn": len(_chat_history) // 2})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def chat_reset() -> str:
        """Reset chat conversation history.
        
        Returns:
            Confirmation JSON
        """
        nonlocal _chat_history
        _chat_history = []
        return json.dumps({"status": "ok", "message": "Chat history cleared"})
    
    @logged_tool()
    def chat_history() -> str:
        """Get current chat conversation history.
        
        Returns:
            JSON with full conversation
        """
        return json.dumps({"history": _chat_history, "turns": len(_chat_history) // 2})

    @logged_tool()
    def agent_chat(message: str, slot: int = 0, session_id: str = "", granted_tools: list = None,
                   max_iterations: int = 5, max_tokens: int = 0, reset: bool = False) -> str:
        """Interactive agentic session for a slot using workflow-agent semantics."""
        nonlocal _agent_chat_sessions
        import time as _achat_time
        import uuid as _achat_uuid
        import json as _achat_json

        _executor = get_workflow_executor()
        _sid = session_id.strip() if isinstance(session_id, str) else ""
        if not _sid:
            _sid = f"agent_chat:{slot}:{_achat_uuid.uuid4().hex[:10]}"

        if reset:
            _agent_chat_sessions.pop(_sid, None)

        _session = _agent_chat_sessions.get(_sid)
        if not _session:
            _session = dict(
                id=_sid,
                slot=int(slot),
                started_ms=int(_achat_time.time() * 1000),
                turns=[],
                granted_tools=list(_agent_chat_default_granted_tools),
            )
            _agent_chat_sessions[_sid] = _session

        if granted_tools and isinstance(granted_tools, list):
            _session["granted_tools"] = [str(t) for t in granted_tools if str(t).strip()]
        _granted = [t for t in _session.get("granted_tools", []) if t not in _agent_chat_blocked_tools]
        if not _granted:
            _granted = list(_agent_chat_default_granted_tools)

        _slot = int(slot if slot is not None else _session.get("slot", 0))
        _session["slot"] = _slot
        _session["last_used_ms"] = int(_achat_time.time() * 1000)
        _session["turns"].append(dict(role="user", content=message, ts=_session["last_used_ms"]))

        _turns = _session["turns"][-20:]
        _transcript_lines = []
        for _t in _turns:
            _role = str(_t.get("role", "user")).upper()
            _content = str(_t.get("content", ""))
            _transcript_lines.append(f"{_role}: {_content}")
        _transcript = "\n".join(_transcript_lines)

        _task = (
            "You are in an interactive drill-down agent chat session.\n"
            "Use your granted tools when needed.\n"
            "Do NOT attempt workflow_execute unless explicitly pre-authorized by operator policy.\n\n"
            "Conversation transcript (latest at bottom):\n"
            f"{_transcript}\n\n"
            "Respond to the latest USER message."
        )

        _node = {
            "type": "agent",
            "parameters": {
                "slot": _slot,
                "task": _task,
                "granted_tools": _granted,
                "max_iterations": int(max_iterations),
                "max_tokens": int(max_tokens),
            }
        }

        _result = _executor._execute_agent(_node, {}, {"$input": {}})
        if isinstance(_result, dict) and _result.get("final_answer"):
            _session["turns"].append(
                dict(
                    role="assistant",
                    content=str(_result.get("final_answer", "")),
                    ts=int(_achat_time.time() * 1000),
                )
            )
        _session["last_tool_calls"] = _result.get("tool_calls", []) if isinstance(_result, dict) else []
        _session["last_iterations"] = _result.get("iterations", 0) if isinstance(_result, dict) else 0
        _agent_chat_sessions[_sid] = _session

        return _achat_json.dumps(
            {
                "session_id": _sid,
                "slot": _slot,
                "result": _result,
                "blocked_tools": sorted(list(_agent_chat_blocked_tools)),
                "turn_count": len(_session.get("turns", [])),
                "history": _session.get("turns", [])[-12:],
            },
            indent=2,
            default=str,
        )
    
    # ═══════════════════════════════════════════════════════════
    # MCP TOOLS - Batch Processing
    # ═══════════════════════════════════════════════════════════
    
    @logged_tool()
    def batch_forward(inputs: list) -> str:
        """Run batch inference on multiple inputs.
        
        Args:
            inputs: List of input strings or dicts
        
        Returns:
            JSON with list of results
        """
        agent = get_agent()
        brain_type = _BRAIN_CONFIG.get('brain_type', 'unknown')
        results = []
        
        # Deep serializer for numpy arrays
        def deep_serialize(v):
            if hasattr(v, 'tolist'):
                return v.tolist()
            elif isinstance(v, dict):
                return {k: deep_serialize(vv) for k, vv in v.items()}
            elif isinstance(v, (list, tuple)):
                return [deep_serialize(x) for x in v]
            return v
        
        for i, inp in enumerate(inputs):
            try:
                if isinstance(inp, str):
                    obs = {'text': inp, 'input': np.random.rand(384).astype(np.float32)}
                else:
                    obs = inp
                result = agent.forward(obs)
                # Deep serialize all values
                serialized = deep_serialize(result)
                results.append({"index": i, "status": "ok", "result": serialized})
            except Exception as e:
                results.append({"index": i, "status": "error", "error": str(e)})
        
        return json.dumps({"batch_size": len(inputs), "results": results}, indent=2, default=str)
    
    @logged_tool()
    def batch_embed(texts: list) -> str:
        """Generate embeddings for multiple texts.
        
        Args:
            texts: List of strings to embed
        
        Returns:
            JSON with list of embeddings
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain
        
        # Find embed function
        embed_fn = None
        if hasattr(brain, 'embedding_foundation') and brain.embedding_foundation is not None:
            embed_fn = lambda t: brain.embedding_foundation.encode(t, convert_to_numpy=True)
        elif hasattr(brain, 'embed'):
            embed_fn = brain.embed
        elif hasattr(brain, 'get_embedding'):
            embed_fn = brain.get_embedding
        
        if not embed_fn:
            return json.dumps({"error": "Brain does not support embedding", "brain_type": type(brain).__name__})
        
        results = []
        for i, text in enumerate(texts):
            try:
                emb = embed_fn(text)
                if hasattr(emb, 'tolist'):
                    emb = emb.tolist()
                results.append({"index": i, "status": "ok", "embedding": emb})
            except Exception as e:
                results.append({"index": i, "status": "error", "error": str(e)})
        
        return json.dumps({"batch_size": len(texts), "results": results})
    
    # ═══════════════════════════════════════════════════════════
    # MCP TOOLS - Inter-Model Piping
    # ═══════════════════════════════════════════════════════════
    
    @logged_tool()
    def pipe(input_text: str, pipeline: Optional[list] = None) -> str:
        """Chain outputs between slots. Each slot's output becomes next slot's input.

        Args:
            input_text: Initial input text
            pipeline: List of slot indices to chain through, e.g. [0, 2, 1]

        Returns:
            JSON with intermediate and final results
        """
        if not pipeline:
            return json.dumps({"error": "pipeline must contain at least one slot index", "hint": "Example: pipe(input_text='Hello', pipeline=[0, 1])"})
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain

        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots for piping", "brain_type": type(brain).__name__})
        
        current_input = input_text
        trace = [{"slot": "input", "output": current_input}]
        
        for slot_idx in pipeline:
            if slot_idx >= len(brain.councilors):
                return json.dumps({"error": f"Slot {slot_idx} does not exist", "available": len(brain.councilors)})
            
            councilor = brain.councilors[slot_idx]
            model = getattr(councilor, 'model', None)
            
            if not model:
                trace.append({"slot": slot_idx, "status": "empty", "output": current_input})
                continue
            
            try:
                # Detect model type and invoke appropriately
                tokenizer = getattr(councilor, 'tokenizer', None)
                _lim = getattr(councilor, '_limits', getattr(model, '_limits', {}))
                _ctx = _lim.get('context_length', 4096)
                _gen = _lim.get('max_gen_tokens', 256)

                if hasattr(model, 'encode'):
                    # Embedding model
                    result = model.encode(current_input)
                    if hasattr(result, 'tolist'):
                        result = result.tolist()
                    current_input = json.dumps(result[:10]) + "..."  # Truncate for chaining
                    trace.append({"slot": slot_idx, "type": "embed", "output": current_input})
                
                elif hasattr(model, 'generate'):
                    # LLM
                    if tokenizer:
                        _raw = getattr(model, 'model', model)
                        if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                            _sys = _council_system_prompt(slot_idx, brain)
                            _msgs = [{"role": "system", "content": _sys}, {"role": "user", "content": current_input}]
                            _chat_text = tokenizer.apply_chat_template(_msgs, tokenize=False, add_generation_prompt=True)
                            inputs = tokenizer(_chat_text, return_tensors="pt", truncation=True, max_length=_ctx)
                        else:
                            inputs = tokenizer(current_input, return_tensors="pt", truncation=True, max_length=_ctx)
                        _in_len = inputs['input_ids'].shape[-1]
                        outputs = _raw.generate(**inputs, max_new_tokens=_gen, pad_token_id=tokenizer.eos_token_id)
                        result = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                    else:
                        try:
                            result = model.generate(prompt=current_input, max_tokens=_gen)
                        except TypeError:
                            result = model.generate(current_input)
                        result = str(result)
                    current_input = result
                    trace.append({"slot": slot_idx, "type": "generate", "output": current_input[:200]})
                
                elif getattr(model, '_model_type_hint', None) == 'RERANKER' or type(model).__name__ == 'CrossEncoder':
                    _h = hash(current_input) % 1000 / 1000.0
                    current_input = str(_h)
                    trace.append({"slot": slot_idx, "type": "reranker_hash", "output": current_input})
                
                elif hasattr(model, 'predict') or hasattr(model, 'classify'):
                    fn = getattr(model, 'predict', None) or getattr(model, 'classify', None)
                    result = fn(current_input)
                    current_input = str(result)
                    trace.append({"slot": slot_idx, "type": "classification", "output": current_input[:200]})
                
                elif callable(model):
                    result = model(current_input)
                    current_input = str(result)
                    trace.append({"slot": slot_idx, "type": "forward", "output": current_input[:200]})
                
                else:
                    trace.append({"slot": slot_idx, "type": "skip", "reason": "no invocable interface"})
                    
            except Exception as e:
                trace.append({"slot": slot_idx, "status": "error", "error": str(e)})
        
        return json.dumps({"final_output": current_input, "trace": trace}, indent=2)
    
    # ═══════════════════════════════════════════════════════════
    # MCP TOOLS - Comparison Mode
    # ═══════════════════════════════════════════════════════════
    
    @logged_tool()
    def compare(input_text: str, slots: list = None) -> str:
        """Run same input through multiple slots and compare outputs.
        
        Args:
            input_text: Input to test
            slots: List of slot indices to compare (None = all plugged slots)
        
        Returns:
            JSON with outputs from each slot for comparison
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots for comparison"})
        
        results = []
        for i, councilor in enumerate(brain.councilors):
            if slots is not None and i not in slots:
                continue
            
            model = getattr(councilor, 'model', None)
            name = getattr(councilor, 'name', f'slot_{i}')
            
            if not model:
                results.append({"slot": i, "name": name, "status": "empty"})
                continue
            
            try:
                tokenizer = getattr(councilor, 'tokenizer', None)
                _lim = getattr(councilor, '_limits', getattr(model, '_limits', {}))
                _ctx = _lim.get('context_length', 4096)
                _gen = _lim.get('max_gen_tokens', 256)

                if hasattr(model, 'encode'):
                    output = model.encode(input_text)
                    if hasattr(output, 'tolist'):
                        output = output.tolist()
                    results.append({"slot": i, "name": name, "type": "embedding", "output_dim": len(output), "sample": output[:5]})

                elif hasattr(model, 'generate'):
                    if tokenizer:
                        _raw = getattr(model, 'model', model)
                        if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                            _sys = _council_system_prompt(i, brain)
                            _msgs = [{"role": "system", "content": _sys}, {"role": "user", "content": input_text}]
                            _chat_text = tokenizer.apply_chat_template(_msgs, tokenize=False, add_generation_prompt=True)
                            inputs = tokenizer(_chat_text, return_tensors="pt", truncation=True, max_length=_ctx)
                        else:
                            inputs = tokenizer(input_text, return_tensors="pt", truncation=True, max_length=_ctx)
                        _in_len = inputs['input_ids'].shape[-1]
                        outputs = _raw.generate(**inputs, max_new_tokens=_gen, pad_token_id=tokenizer.eos_token_id)
                        output = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                    else:
                        try:
                            output = model.generate(prompt=input_text, max_tokens=_gen)
                        except TypeError:
                            output = model.generate(input_text)
                        output = str(output)
                    results.append({"slot": i, "name": name, "type": "generation", "output": output[:300]})
                
                elif getattr(model, '_model_type_hint', None) == 'RERANKER':
                    _h = hash(input_text) % 1000 / 1000.0
                    results.append({"slot": i, "name": name, "type": "reranker_hash", "output": str(_h)})
                
                elif hasattr(model, 'predict') or hasattr(model, 'classify'):
                    fn = getattr(model, 'predict', None) or getattr(model, 'classify', None)
                    output = fn(input_text)
                    results.append({"slot": i, "name": name, "type": "classification", "output": str(output)[:300]})
                
                elif callable(model):
                    output = model(input_text)
                    results.append({"slot": i, "name": name, "type": "forward", "output": str(output)[:300]})
                
                else:
                    results.append({"slot": i, "name": name, "type": "unknown"})
                    
            except Exception as e:
                results.append({"slot": i, "name": name, "status": "error", "error": str(e)})
        
        return json.dumps({"input": input_text, "comparisons": results}, indent=2)
    
    # ═══════════════════════════════════════════════════════════
    # MCP TOOLS - Slot-Specific Invocation
    # ═══════════════════════════════════════════════════════════
    
    @logged_tool()
    def invoke_slot(slot: int, text: str, mode: str = "auto", max_tokens: int = 0, messages: list = None) -> str:
        """Invoke a specific slot by index with explicit mode control.

        Args:
            slot: Slot index to invoke
            text: Input text
            mode: 'auto', 'embed', 'generate', 'classify', or 'forward'
            max_tokens: Override max generation tokens (0 = use model default)
            messages: Optional structured message list for chat models.
                      List of dicts with 'role' and 'content' keys.
                      When provided, overrides text for generation mode.

        Returns:
            JSON with slot output
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots", "brain_type": type(brain).__name__})
        
        if slot >= len(brain.councilors):
            return json.dumps({"error": f"Slot {slot} does not exist. Max: {len(brain.councilors) - 1}"})
        
        councilor = brain.councilors[slot]
        model = getattr(councilor, 'model', None)
        name = getattr(councilor, 'name', f'slot_{slot}')
        
        if not model:
            return json.dumps({"error": f"Slot {slot} ({name}) is empty"})
        
        tokenizer = getattr(councilor, 'tokenizer', None)
        _raw_model = getattr(model, 'model', model)
        _lim = getattr(councilor, '_limits', getattr(model, '_limits', {}))
        _ctx = _lim.get('context_length', 4096)
        _gen = int(max_tokens) if max_tokens and int(max_tokens) > 0 else _lim.get('max_gen_tokens', 256)

        # Track slot invocation count
        if not hasattr(brain, '_slot_counts'):
            brain._slot_counts = [0] * len(brain.councilors)
        brain._slot_counts[slot] += 1
        
        def _log_slot_state(slot_idx, mode_used, success=True):
            try:
                import rerun as rr
                rr.log("state/slots/activity", rr.BarChart(brain._slot_counts))
                rr.log("state/slots/count", rr.Scalars([sum(brain._slot_counts)]))
                level = rr.TextLogLevel.INFO if success else rr.TextLogLevel.ERROR
                rr.log("state/slots/log", rr.TextLog(f"⚡ Slot {slot_idx} ({mode_used})", level=level))
            except Exception:
                pass
        
        try:
            _is_remote_provider = bool(getattr(model, '_is_remote_provider', False))
            _model_hint = str(getattr(model, '_model_type_hint', '') or '').upper()
            _auto_generate = (
                mode == "auto" and hasattr(model, 'generate') and (
                    _is_remote_provider or
                    _model_hint in ('LLM', 'SEQ2SEQ', 'VLM') or
                    not hasattr(model, 'encode')
                )
            )

            if mode == "generate" or _auto_generate:
                if tokenizer:
                    if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                        if messages:
                            # Use caller-provided structured messages directly
                            _chat_msgs = messages
                        else:
                            # Default: wrap text in system/user format
                            _sys = _council_system_prompt(slot, brain)
                            _chat_msgs = [{"role": "system", "content": _sys}, {"role": "user", "content": text}]
                        input_text = tokenizer.apply_chat_template(_chat_msgs, tokenize=False, add_generation_prompt=True)
                        inputs = tokenizer(input_text, return_tensors="pt", truncation=True, max_length=_ctx)
                    else:
                        inputs = tokenizer(text, return_tensors="pt", truncation=True, max_length=_ctx)
                    input_len = inputs['input_ids'].shape[-1]
                    outputs = _raw_model.generate(**inputs, max_new_tokens=_gen, do_sample=True, pad_token_id=tokenizer.eos_token_id)
                    output = tokenizer.decode(outputs[0][input_len:], skip_special_tokens=True)
                else:
                    try:
                        if messages:
                            output = model.generate(prompt=text, messages=messages, max_tokens=_gen)
                        else:
                            output = model.generate(prompt=text, max_tokens=_gen)
                    except TypeError:
                        if messages:
                            output = model.generate(messages, max_tokens=_gen)
                        else:
                            output = model.generate(text)
                    output = str(output)
                _log_slot_state(slot, "generate")
                return json.dumps({"slot": slot, "name": name, "mode": "generate", "output": output})

            elif mode == "embed" or (mode == "auto" and hasattr(model, 'encode')):
                output = model.encode(text)
                if hasattr(output, 'tolist'):
                    output = output.tolist()
                _log_slot_state(slot, "embed")
                return json.dumps({"slot": slot, "name": name, "mode": "embed", "dim": len(output), "embedding": output})
            
            elif mode == "classify" or (mode == "auto" and hasattr(model, 'predict')):
                if getattr(model, '_model_type_hint', None) == 'RERANKER':
                    _h = hash(text) % 1000 / 1000.0
                    _log_slot_state(slot, "reranker_hash")
                    return json.dumps({"slot": slot, "name": name, "mode": "reranker_hash", "output": str(_h)})
                output = model.predict([text])
                _log_slot_state(slot, "classify")
                return json.dumps({"slot": slot, "name": name, "mode": "classify", "output": str(output)})
            
            else:
                # Forward mode
                output = model(text) if callable(model) else str(model)
                _log_slot_state(slot, "forward")
                return json.dumps({"slot": slot, "name": name, "mode": "forward", "output": str(output)})
                
        except Exception as e:
            _log_slot_state(slot, mode, success=False)
            return json.dumps({"slot": slot, "name": name, "status": "error", "error": str(e)})
    
    # ═══════════════════════════════════════════════════════════
    # MCP TOOLS - HuggingFace Hub
    # ═══════════════════════════════════════════════════════════
    
    @logged_tool()
    def hub_search(query: str, limit: int = 50, page: int = 1) -> str:
        """Search HuggingFace Hub for models.
        
        Args:
            query: Search query (model name, task, etc.)
            limit: Max results per page (default 50)
            page: Page number (default 1)
        
        Returns:
            JSON with model list
        """
        try:
            from huggingface_hub import list_models
            skip = (page - 1) * limit
            fetch_count = skip + limit
            # Use timeout to prevent hanging
            import os
            os.environ.setdefault('HF_HUB_DOWNLOAD_TIMEOUT', '30')
            all_models = list(list_models(search=query, sort='downloads', direction=-1, limit=fetch_count))
            models = all_models[skip:skip + limit]
            results = []
            for m in models:
                dl = m.downloads or 0
                results.append({
                    "id": m.id,
                    "task": getattr(m, 'pipeline_tag', '') or '',
                    "downloads": dl,
                    "likes": getattr(m, 'likes', 0)
                })
            result = {"query": query, "page": page, "count": len(results), "models": results}
            if len(results) == 0 and query:
                result['hint'] = 'No results found. Try broader terms like "embedding", "llm", "vision", or specific model names like "mistral", "llama", "qwen"'
            return json.dumps(result, indent=2)
        except ImportError:
            return json.dumps({"error": "huggingface_hub not installed", "fix": "pip install huggingface_hub"})
        except Exception as e:
            error_str = str(e)
            result = {"error": error_str, "query": query}
            if 'timeout' in error_str.lower() or 'connection' in error_str.lower():
                result['hint'] = 'Network issue - check internet connection or try again'
            elif 'rate' in error_str.lower():
                result['hint'] = 'Rate limited - wait a moment and try again, or set HF_TOKEN env var'
            return json.dumps(result)
    
    @logged_tool()
    def hub_search_datasets(query: str, limit: int = 50, page: int = 1) -> str:
        """Search HuggingFace Hub for datasets.
        
        Args:
            query: Search query (dataset name, task, topic)
            limit: Max results per page (default 50)
            page: Page number (default 1)
        
        Returns:
            JSON with dataset list
        """
        try:
            from huggingface_hub import list_datasets
            skip = (page - 1) * limit
            fetch_count = skip + limit
            import os
            os.environ.setdefault('HF_HUB_DOWNLOAD_TIMEOUT', '30')
            all_datasets = list(list_datasets(search=query, sort='downloads', direction=-1, limit=fetch_count))
            datasets = all_datasets[skip:skip + limit]
            results = []
            for d in datasets:
                dl = d.downloads or 0
                results.append({
                    "id": d.id,
                    "downloads": dl,
                    "likes": getattr(d, 'likes', 0),
                    "tags": (getattr(d, 'tags', []) or [])[:5]
                })
            result = {"query": query, "page": page, "count": len(results), "datasets": results}
            if len(results) == 0 and query:
                result['hint'] = 'No datasets found. Try terms like "sentiment", "qa", "embeddings", "text-classification"'
            return json.dumps(result, indent=2)
        except ImportError:
            return json.dumps({"error": "huggingface_hub not installed", "fix": "pip install huggingface_hub"})
        except Exception as e:
            error_str = str(e)
            result = {"error": error_str, "query": query}
            if 'timeout' in error_str.lower() or 'connection' in error_str.lower():
                result['hint'] = 'Network issue - check internet connection or try again'
            elif 'rate' in error_str.lower():
                result['hint'] = 'Rate limited - wait a moment and try again, or set HF_TOKEN env var'
            return json.dumps(result)
    
    @logged_tool()
    def hub_top(task: str = None, limit: int = 50, page: int = 1) -> str:
        """Get top trending models from HuggingFace Hub.
        
        Args:
            task: Filter by task (text-generation, feature-extraction, etc.)
            limit: Max results per page
            page: Page number
        
        Returns:
            JSON with top models
        """
        try:
            from huggingface_hub import list_models
            skip = (page - 1) * limit
            fetch_count = skip + limit
            kwargs = {'sort': 'downloads', 'direction': -1, 'limit': fetch_count}
            if task:
                kwargs['filter'] = task
            all_models = list(list_models(**kwargs))
            models = all_models[skip:skip + limit]
            results = []
            for m in models:
                dl = m.downloads or 0
                results.append({"id": m.id, "downloads": dl, "task": getattr(m, 'pipeline_tag', '')})
            return json.dumps({"task": task, "page": page, "count": len(results), "models": results}, indent=2)
        except ImportError:
            return json.dumps({"error": "huggingface_hub not installed"})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def hub_info(model_id: str) -> str:
        """Get detailed information about a HuggingFace model.
        
        Args:
            model_id: Full model ID (e.g., 'BAAI/bge-small-en-v1.5')
        
        Returns:
            JSON with model details
        """
        try:
            from huggingface_hub import model_info
            info = model_info(model_id)
            result = {
                "id": info.id,
                "author": info.author or 'unknown',
                "task": info.pipeline_tag or 'unknown',
                "downloads": info.downloads,
                "likes": info.likes,
                "license": getattr(info, 'license', 'unknown') or 'unknown',
                "tags": info.tags[:10] if info.tags else [],
                "url": f"https://huggingface.co/{model_id}"
            }
            # Try safetensors_params first (most accurate), then siblings with files_metadata
            _total_size = 0
            if hasattr(info, 'safetensors') and info.safetensors:
                _st = info.safetensors
                _total_size = _st.get('total', 0) if isinstance(_st, dict) else 0
            if _total_size == 0 and hasattr(info, 'siblings') and info.siblings:
                _total_size = sum(getattr(s, 'size', 0) or 0 for s in info.siblings)
            if _total_size == 0:
                try:
                    _fi = model_info(model_id, files_metadata=True)
                    if hasattr(_fi, 'siblings') and _fi.siblings:
                        _total_size = sum(getattr(s, 'size', 0) or 0 for s in _fi.siblings)
                except Exception:
                    pass
            result["size_mb"] = round(_total_size / (1024*1024), 1) if _total_size > 0 else 0.0
            return json.dumps(result, indent=2)
        except ImportError:
            return json.dumps({"error": "huggingface_hub not installed"})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def hub_download(model_id: str) -> str:
        """Download a model from HuggingFace Hub.
        
        Args:
            model_id: Full model ID to download
        
        Returns:
            JSON with download path
        """
        try:
            from huggingface_hub import snapshot_download
            path = snapshot_download(model_id)
            return json.dumps({"status": "ok", "model": model_id, "path": path})
        except ImportError:
            return json.dumps({"error": "huggingface_hub not installed"})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
