    @logged_tool()
    def vast_search(query: str = "rentable=true", page: int = 1, page_size: int = 20) -> str:
        """Search Vast.ai for GPU rental offers.
        
        Args:
            query: Search query (e.g., 'gpu_ram>=48', 'rentable=true')
            page: Page number
            page_size: Results per page
        
        Returns:
            JSON with GPU offers
        """
        import subprocess
        try:
            result = subprocess.run(['vastai', 'search', 'offers', query, '--raw'], 
                                   capture_output=True, text=True, timeout=60)
            if result.returncode != 0:
                return json.dumps({"error": result.stderr or "Command failed"})
            offers = json.loads(result.stdout)
            # Cache ALL results so vast_details can use them
            _MCP_VAST_CACHE.clear()
            _MCP_VAST_CACHE.extend(offers)
            total = len(offers)
            start = (page - 1) * page_size
            end = min(start + page_size, total)
            page_offers = offers[start:end]
            results = []
            for i, o in enumerate(page_offers):
                results.append({
                    "index": start + i + 1,
                    "id": o.get('id'),
                    "gpu": o.get('gpu_name', '?').replace('_', ' '),
                    "vram_gb": o.get('gpu_ram', 0),
                    "price_hr": o.get('dph_total', 0),
                    "reliability": o.get('reliability', 0) * 100,
                    "num_gpus": o.get('num_gpus', 1)
                })
            return json.dumps({"page": page, "total": total, "offers": results}, indent=2)
        except FileNotFoundError:
            return json.dumps({"error": "vastai CLI not installed (pip install vastai)"})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def vast_details(offer_index: int) -> str:
        """Get detailed specs for a Vast.ai GPU offer.

        Args:
            offer_index: Offer number from vast_search results

        Returns:
            JSON with full GPU specifications
        """
        try:
            # Use cached results from last vast_search (preserves filters)
            if not _MCP_VAST_CACHE:
                return json.dumps({"error": "No offers cached. Run vast_search first."})
            idx = offer_index - 1
            if idx < 0 or idx >= len(_MCP_VAST_CACHE):
                return json.dumps({"error": f"Invalid index {offer_index}. Have {len(_MCP_VAST_CACHE)} cached offers (1-{len(_MCP_VAST_CACHE)})."})
            o = _MCP_VAST_CACHE[idx]
            return json.dumps({
                "id": o.get('id'),
                "gpu": o.get('gpu_name', '?').replace('_', ' '),
                "num_gpus": o.get('num_gpus', 1),
                "vram_gb": o.get('gpu_ram', 0),
                "total_vram_gb": o.get('gpu_total_ram', 0),
                "price_hr": o.get('dph_total', 0),
                "storage_cost_gb_mo": o.get('storage_cost', 0),
                "reliability_pct": o.get('reliability', 0) * 100,
                "cuda": o.get('cuda_max_good', '?'),
                "driver": o.get('driver_version', '?'),
                "cpu_cores": o.get('cpu_cores', '?'),
                "ram_gb": o.get('cpu_ram', 0) / 1024,
                "disk_gb": o.get('disk_space', 0),
                "net_down_mbps": o.get('inet_down', 0),
                "net_up_mbps": o.get('inet_up', 0),
                "location": o.get('geolocation', '?')
            }, indent=2)
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def vast_rent(instance_id: str, image: str = 'vastai/pytorch:latest', disk: int = 50) -> str:
        """Rent a GPU instance on vast.ai with full Ouroboros facilities.
        
        Args:
            instance_id: Instance ID from vast_search results
            image: Docker image (default: vastai/pytorch - pre-cached, SSH-compatible)
            disk: Disk space in GB (default: 50 for model weights)
        
        Returns:
            JSON with rental confirmation
        
        Note: Uses vastai/pytorch base image which is:
        - Pre-cached on most hosts (fast startup)
        - Compatible with Vast's SSH launch mode
        - Includes CUDA dev libraries, node, OpenCL
        
        Automatically installs Ouroboros inference stack on boot:
        - transformers, accelerate, bitsandbytes (quantized LLMs)
        - sentence-transformers (embeddings)
        - vllm (high-throughput inference)
        - flash-attn (fast attention)
        """
        try:
            import subprocess

            # === RENTAL SAFETY GUARDS ===
            # Check current instances BEFORE renting to prevent runaway GPU costs
            MAX_CONCURRENT_RENTALS = 1

            check_cmd = ['vastai', 'show', 'instances', '--raw']
            check_proc = subprocess.run(check_cmd, capture_output=True, text=True, timeout=30)
            if check_proc.returncode == 0 and check_proc.stdout.strip():
                try:
                    current_instances = json.loads(check_proc.stdout)
                    if isinstance(current_instances, list):
                        # Count active instances (not destroyed)
                        active_count = len([i for i in current_instances if i.get('actual_status') not in ['destroyed', 'exited']])

                        if active_count >= MAX_CONCURRENT_RENTALS:
                            return json.dumps({
                                'error': f'BLOCKED: Rental limit reached ({MAX_CONCURRENT_RENTALS} max)',
                                'active_instances': active_count,
                                'hint': 'Stop an existing instance first with vast_stop'
                            })

                        # Check for any instances still starting/loading
                        for inst in current_instances:
                            status = inst.get('actual_status', '')
                            if status in ['created', 'starting', 'loading']:
                                return json.dumps({
                                    'error': f'BLOCKED: Instance {inst.get("id")} is still {status}',
                                    'hint': 'Wait for it to be running before renting another'
                                })
                except json.JSONDecodeError:
                    pass  # If we can't parse, allow the rental

            # Onstart script installs our full inference stack
            # Updated to include ALL requirements from _write_requirements()
            onstart_script = "#!/bin/bash\npip install --upgrade pip\npip install torch torchvision --index-url https://download.pytorch.org/whl/cu121\npip install transformers>=4.40.0 accelerate>=0.27.0 bitsandbytes>=0.43.0\npip install sentence-transformers>=2.6.0 huggingface-hub>=0.22.0\npip install vllm>=0.4.0 || true\npip install einops safetensors scipy\npip install vastai>=0.3.0 vastai-sdk>=0.1.0 paramiko>=3.0.0\npip install infinity-emb>=0.0.70 cascade-lattice>=0.7.0\npip install 'mcp[cli]>=1.0.0' python-dotenv>=1.0.0\npip install textual>=0.40.0 'rich>=13.0,<14'\necho OUROBOROS_READY=1 > /tmp/ouroboros_ready"
            cmd = [
                'vastai', 'create', 'instance', str(instance_id),
                '--image', image,
                '--disk', str(disk),
                '--ssh',
                '--onstart-cmd', onstart_script,
                '--raw'
            ]
            proc = subprocess.run(cmd, capture_output=True, text=True, timeout=60)
            if proc.returncode == 0:
                rental = json.loads(proc.stdout)
                return json.dumps({
                    'rental': rental,
                    'status': 'rented',
                    'note': 'Instance booting. Packages installing via onstart script. Check /tmp/ouroboros_ready for completion.'
                }, indent=2)
            else:
                return json.dumps({'error': proc.stderr or 'vast rent failed'})
        except Exception as e:
            return json.dumps({'error': str(e)})
    
    @logged_tool()
    def vast_instances() -> str:
        """List your active Vast.ai GPU instances.
        
        Returns:
            JSON with active instances including HTTP URLs
        """
        import subprocess
        try:
            result = subprocess.run(['vastai', 'show', 'instances', '--raw'],
                                   capture_output=True, text=True, timeout=60)
            if result.returncode != 0:
                return json.dumps({"error": result.stderr})
            instances = json.loads(result.stdout)
            results = []
            for inst in instances:
                public_ip = inst.get('public_ipaddr', '')
                ports = inst.get('ports', {})
                # Build HTTP URLs for exposed ports
                http_urls = []
                for port_key, mappings in ports.items():
                    if mappings and '/tcp' in port_key:
                        container_port = port_key.split('/')[0]
                        host_port = mappings[0].get('HostPort', container_port)
                        http_urls.append(f"http://{public_ip}:{host_port}")
                results.append({
                    "id": inst.get('id'),
                    "status": inst.get('actual_status', 'unknown'),
                    "gpu": inst.get('gpu_name', '?'),
                    "public_ip": public_ip,
                    "http_urls": http_urls,
                    "ssh_host": inst.get('ssh_host', ''),
                    "ssh_port": inst.get('ssh_port', '')
                })
            return json.dumps({"instances": results}, indent=2)
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def vast_stop(instance_id: str) -> str:
        """Stop and destroy a Vast.ai instance.
        
        Args:
            instance_id: Instance ID to destroy
        
        Returns:
            JSON with status
        """
        import subprocess
        try:
            result = subprocess.run(['vastai', 'destroy', 'instance', str(instance_id), '--raw'],
                                   capture_output=True, text=True, timeout=60)
            if result.returncode != 0:
                return json.dumps({"error": result.stderr})
            return json.dumps({"status": "ok", "destroyed": instance_id})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def vast_ready(instance_id: str) -> str:
        """Check if a Vast.ai instance is ready with Ouroboros stack installed.
        
        Args:
            instance_id: Instance ID to check
        
        Returns:
            JSON with readiness status and available capabilities
        """
        try:
            import paramiko
            import subprocess
            
            # Get instance details
            result = subprocess.run(['vastai', 'show', 'instances', '--raw'],
                                   capture_output=True, text=True, timeout=30)
            if result.returncode != 0:
                return json.dumps({"error": "Cannot get instance list"})
            
            instances = json.loads(result.stdout)
            target = None
            for inst in instances:
                if str(inst.get('id')) == str(instance_id):
                    target = inst
                    break
            
            if not target:
                return json.dumps({"error": f"Instance {instance_id} not found"})
            
            status = target.get('actual_status', 'unknown')
            if status != 'running':
                return json.dumps({
                    "ready": False,
                    "status": status,
                    "message": f"Instance not running yet (status: {status})"
                })
            
            ssh_host = target.get('ssh_host', '')
            ssh_port = target.get('ssh_port', 22)
            
            if not ssh_host:
                return json.dumps({"ready": False, "error": "No SSH host available"})
            
            # Try SSH connection
            client = paramiko.SSHClient()
            client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
            
            key_path = Path.home() / '.ssh' / 'id_rsa'
            if not key_path.exists():
                return json.dumps({"ready": False, "error": "No SSH key at ~/.ssh/id_rsa"})
            
            try:
                client.connect(ssh_host, port=int(ssh_port), username='root',
                              key_filename=str(key_path), timeout=10,
                              look_for_keys=False, allow_agent=False)
                
                # Check if ouroboros packages are ready
                stdin, stdout, stderr = client.exec_command('cat /tmp/ouroboros_ready 2>/dev/null || echo "NOT_READY"')
                ready_check = stdout.read().decode().strip()
                
                # Check installed packages
                stdin, stdout, stderr = client.exec_command('pip list 2>/dev/null | grep -E "transformers|sentence-transformers|vllm|bitsandbytes" | head -10')
                packages = stdout.read().decode().strip()
                
                # Check GPU
                stdin, stdout, stderr = client.exec_command('nvidia-smi --query-gpu=name,memory.total --format=csv,noheader 2>/dev/null')
                gpu_info = stdout.read().decode().strip()
                
                client.close()
                
                is_ready = 'OUROBOROS_READY=1' in ready_check
                
                return json.dumps({
                    "ready": is_ready,
                    "status": "running",
                    "ssh": f"{ssh_host}:{ssh_port}",
                    "gpu": gpu_info or "unknown",
                    "packages_installed": packages.split('\n') if packages else [],
                    "message": "Ouroboros stack ready!" if is_ready else "Packages still installing..."
                }, indent=2)
                
            except Exception as ssh_err:
                return json.dumps({
                    "ready": False,
                    "status": status,
                    "ssh_error": str(ssh_err),
                    "message": "SSH connection failed - instance may still be booting"
                })
                
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def vast_run(instance_id: str, code: str) -> str:
        """Execute Python code on a remote Vast.ai GPU instance.
        
        This is the core remote execution facility - run ANY Python on rented GPU.
        Use for model loading, inference, training, or any GPU-accelerated task.
        
        Args:
            instance_id: Instance ID to run on
            code: Python code to execute (will be run via python -c)
        
        Returns:
            JSON with stdout, stderr, and return code
        """
        try:
            import paramiko
            import subprocess
            
            # Get instance details
            result = subprocess.run(['vastai', 'show', 'instances', '--raw'],
                                   capture_output=True, text=True, timeout=30)
            if result.returncode != 0:
                return json.dumps({"error": "Cannot get instance list"})
            
            instances = json.loads(result.stdout)
            target = None
            for inst in instances:
                if str(inst.get('id')) == str(instance_id):
                    target = inst
                    break
            
            if not target:
                return json.dumps({"error": f"Instance {instance_id} not found"})
            
            ssh_host = target.get('ssh_host', '')
            ssh_port = target.get('ssh_port', 22)
            
            if not ssh_host:
                return json.dumps({"error": "No SSH host available"})
            
            # SSH connection
            client = paramiko.SSHClient()
            client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
            
            key_path = Path.home() / '.ssh' / 'id_rsa'
            if not key_path.exists():
                return json.dumps({"error": "No SSH key at ~/.ssh/id_rsa"})
            
            client.connect(ssh_host, port=int(ssh_port), username='root',
                          key_filename=str(key_path), timeout=30,
                          look_for_keys=False, allow_agent=False)
            
            # Write code to temp file and execute
            import base64
            code_b64 = base64.b64encode(code.encode()).decode()
            remote_cmd = f'echo {code_b64} | base64 -d > /tmp/ouroboros_run.py && python3 /tmp/ouroboros_run.py'
            
            stdin, stdout, stderr = client.exec_command(remote_cmd, timeout=300)
            
            out = stdout.read().decode()
            err = stderr.read().decode()
            exit_code = stdout.channel.recv_exit_status()
            
            client.close()
            
            return json.dumps({
                "success": exit_code == 0,
                "stdout": out,
                "stderr": err,
                "exit_code": exit_code
            }, indent=2)
            
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def vast_load_model(instance_id: str, model_id: str, quantization: str = "4bit") -> str:
        """Load a HuggingFace model on a remote Vast.ai GPU.
        
        Convenience wrapper around vast_run for model loading.
        Supports quantization for running large models on smaller GPUs.
        
        Args:
            instance_id: Instance ID
            model_id: HuggingFace model ID (e.g. "meta-llama/Llama-3.2-70B")
            quantization: "none", "4bit", or "8bit" (default: 4bit for memory efficiency)
        
        Returns:
            JSON with model loading status
        """
        NL = chr(10)
        quant_config = ""
        if quantization == "4bit":
            quant_config = "from transformers import BitsAndBytesConfig" + NL + "import torch" + NL + "bnb_config = BitsAndBytesConfig(load_in_4bit=True, bnb_4bit_quant_type='nf4', bnb_4bit_compute_dtype=torch.float16, bnb_4bit_use_double_quant=True)"
        elif quantization == "8bit":
            quant_config = "from transformers import BitsAndBytesConfig" + NL + "bnb_config = BitsAndBytesConfig(load_in_8bit=True)"
        else:
            quant_config = "bnb_config = None"
        
        LB = chr(123)
        RB = chr(125)
        code_lines = [
            "import torch",
            "import json", 
            "from transformers import AutoModelForCausalLM, AutoTokenizer",
            quant_config,
            "print('Loading tokenizer...')",
            "tokenizer = AutoTokenizer.from_pretrained('" + model_id + "')",
            "print('Loading model with quantization=" + quantization + "...')",
            "model = AutoModelForCausalLM.from_pretrained('" + model_id + "', quantization_config=bnb_config, device_map='auto', trust_remote_code=True)",
            "import pickle",
            "with open('/tmp/ouroboros_model.pkl', 'wb') as f:",
            "    pickle.dump(" + LB + "'model_id': '" + model_id + "', 'quantization': '" + quantization + "'" + RB + ", f)",
            "inputs = tokenizer('Hello, I am', return_tensors='pt').to(model.device)",
            "outputs = model.generate(**inputs, max_new_tokens=20, do_sample=False)",
            "test_output = tokenizer.decode(outputs[0], skip_special_tokens=True)",
            "print(json.dumps(" + LB + "'status': 'loaded', 'model_id': '" + model_id + "', 'quantization': '" + quantization + "', 'device': str(model.device), 'test_output': test_output" + RB + "))"
        ]
        code = NL.join(code_lines)
        return vast_run(instance_id, code)
    
    @logged_tool()
    def vast_generate(instance_id: str, prompt: str, max_tokens: int = 256) -> str:
        """Generate text using a model loaded on remote Vast.ai GPU.
        
        Requires vast_load_model to be called first.
        
        Args:
            instance_id: Instance ID
            prompt: Text prompt for generation
            max_tokens: Maximum tokens to generate
        
        Returns:
            JSON with generated text
        """
        NL = chr(10)
        LB = chr(123)
        RB = chr(125)
        # Escape the prompt for Python string
        prompt_escaped = prompt.replace("\\", "\\\\").replace("'", "\\'").replace('"', '\\"')
        
        code_lines = [
            "import torch",
            "import json",
            "from transformers import AutoModelForCausalLM, AutoTokenizer",
            "import pickle",
            "with open('/tmp/ouroboros_model.pkl', 'rb') as f:",
            "    model_info = pickle.load(f)",
            "model_id = model_info['model_id']",
            "tokenizer = AutoTokenizer.from_pretrained(model_id)",
            "from transformers import BitsAndBytesConfig",
            "if model_info.get('quantization') == '4bit':",
            "    bnb_config = BitsAndBytesConfig(load_in_4bit=True, bnb_4bit_quant_type='nf4', bnb_4bit_compute_dtype=torch.float16)",
            "elif model_info.get('quantization') == '8bit':",
            "    bnb_config = BitsAndBytesConfig(load_in_8bit=True)",
            "else:",
            "    bnb_config = None",
            "model = AutoModelForCausalLM.from_pretrained(model_id, quantization_config=bnb_config, device_map='auto', trust_remote_code=True)",
            "# Read model's actual context window and generation limits",
            "_ctx = getattr(model.config, 'max_position_embeddings', None) or getattr(model.config, 'n_positions', None) or getattr(model.config, 'max_length', 4096)",
            "_gen_cfg = getattr(model, 'generation_config', None)",
            "_gen_default = getattr(_gen_cfg, 'max_new_tokens', None) if _gen_cfg else None",
            "_max_tokens = " + str(max_tokens) + " if " + str(max_tokens) + " else (_gen_default or 256)",
            "prompt = '" + prompt_escaped + "'",
            "inputs = tokenizer(prompt, return_tensors='pt', truncation=True, max_length=_ctx).to(model.device)",
            "_in_len = inputs['input_ids'].shape[-1]",
            "outputs = model.generate(**inputs, max_new_tokens=_max_tokens, do_sample=True, temperature=0.7)",
            "generated = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)",
            "print(json.dumps(" + LB + "'prompt': prompt, 'generated': generated, 'model': model_id, 'context_length': _ctx, 'gen_tokens': _max_tokens" + RB + "))"
        ]
        code = NL.join(code_lines)
        return vast_run(instance_id, code)
    
    @logged_tool()
    def vast_embed(instance_id: str, texts: list, model_id: str = "BAAI/bge-large-en-v1.5") -> str:
        """Generate embeddings on remote Vast.ai GPU.
        
        Uses sentence-transformers for high-quality embeddings.
        Great for semantic search, clustering, RAG pipelines.
        
        Args:
            instance_id: Instance ID
            texts: List of texts to embed
            model_id: Embedding model (default: BGE-large, 1024 dims)
        
        Returns:
            JSON with embeddings array
        """
        import json as json_mod
        NL = chr(10)
        LB = chr(123)
        RB = chr(125)
        texts_json = json_mod.dumps(texts)
        
        code_lines = [
            "import json",
            "from sentence_transformers import SentenceTransformer",
            "model = SentenceTransformer('" + model_id + "')",
            "texts = " + texts_json,
            "embeddings = model.encode(texts, convert_to_numpy=True)",
            "print(json.dumps(" + LB + "'model': '" + model_id + "', 'count': len(texts), 'dimensions': embeddings.shape[1], 'embeddings': embeddings.tolist()" + RB + "))"
        ]
        code = NL.join(code_lines)
        return vast_run(instance_id, code)
    
    @logged_tool()
    def vast_broadcast(command: str) -> str:
        """Broadcast the same command to ALL connected GPU instances.
        
        Sends identical command to every GPU in _remote_gpus dict.
        Useful for fleet-wide operations like status checks, model loading,
        or synchronized inference.
        
        Args:
            command: TUI command to send to all GPUs (e.g., 'status', 'plug model_id')
        
        Returns:
            JSON with broadcast results from each GPU
        """
        if not command:
            return json.dumps({"error": "command parameter required"})
        
        # Access the capsule's _remote_gpus dict
        # This function runs in the capsule context where _remote_gpus is available
        try:
            # Get connected GPUs from the capsule instance
            connected_gpus = {iid: gpu for iid, gpu in _remote_gpus.items() if gpu and getattr(gpu, '_connected', False)}
            if not connected_gpus:
                return json.dumps({"error": "No connected GPU instances. Use vast_connect first."})
            
            import threading
            results = {}
            
            def send_to_gpu(instance_id, executor):
                try:
                    relay_cmd = f'echo "{command}" >> /workspace/.relay_center.cmd'
                    exec_result = executor.execute(relay_cmd)
                    __import__('time').sleep(2)
                    log_result = executor.execute('tail -20 /workspace/tui.log 2>/dev/null || echo "No log"')
                    results[instance_id] = {
                        'status': 'ok',
                        'output': log_result.get('output', '') if isinstance(log_result, dict) else str(log_result)
                    }
                except Exception as e:
                    results[instance_id] = {'status': 'error', 'error': str(e)}
            
            threads = []
            for iid, executor in connected_gpus.items():
                t = threading.Thread(target=send_to_gpu, args=(iid, executor))
                t.start()
                threads.append(t)
            
            for t in threads:
                t.join(timeout=30)
            
            succeeded = len([r for r in results.values() if r.get('status') == 'ok'])
            return json.dumps({
                'broadcast': command,
                'total_gpus': len(connected_gpus),
                'succeeded': succeeded,
                'results': results
            }, indent=2)
        except NameError:
            return json.dumps({"error": "_remote_gpus not available - use MCP handler instead"})
    
    @logged_tool()
    def vast_distribute(tasks: dict) -> str:
        """Distribute different commands to specific GPU instances.
        
        Send unique commands to each GPU for parallel heterogeneous workloads.
        Perfect for distributed inference, A/B testing, or task sharding.
        
        Args:
            tasks: Dict mapping instance_id to command, e.g., {"12345": "plug model_a", "67890": "plug model_b"}
        
        Returns:
            JSON with results from each GPU
        """
        if not tasks or not isinstance(tasks, dict):
            return json.dumps({"error": "tasks parameter required as dict: {instance_id: command, ...}"})
        
        try:
            # Validate all targets are connected
            missing = []
            for iid in tasks:
                if iid not in _remote_gpus or not getattr(_remote_gpus.get(iid), '_connected', False):
                    missing.append(iid)
            
            if missing:
                return json.dumps({"error": f"Instances not connected: {', '.join(missing)}"})
            
            import threading
            results = {}
            
            def send_task(instance_id, command):
                executor = _remote_gpus.get(instance_id)
                if not executor:
                    results[instance_id] = {'status': 'error', 'error': 'No executor'}
                    return
                try:
                    relay_cmd = f'echo "{command}" >> /workspace/.relay_center.cmd'
                    exec_result = executor.execute(relay_cmd)
                    __import__('time').sleep(3)
                    log_result = executor.execute('tail -15 /workspace/tui.log 2>/dev/null || echo "No log"')
                    results[instance_id] = {
                        'status': 'ok',
                        'command': command,
                        'output': log_result.get('output', '') if isinstance(log_result, dict) else str(log_result)
                    }
                except Exception as e:
                    results[instance_id] = {'status': 'error', 'command': command, 'error': str(e)}
            
            threads = []
            for iid, cmd in tasks.items():
                t = threading.Thread(target=send_task, args=(iid, cmd))
                t.start()
                threads.append(t)
            
            for t in threads:
                t.join(timeout=60)
            
            succeeded = len([r for r in results.values() if r.get('status') == 'ok'])
            return json.dumps({
                'total_tasks': len(tasks),
                'succeeded': succeeded,
                'results': results
            }, indent=2)
        except NameError:
            return json.dumps({"error": "_remote_gpus not available - use MCP handler instead"})
    
    # ═══════════════════════════════════════════════════════════
    # MCP TOOLS - FelixBag Extended Memory
    # ═══════════════════════════════════════════════════════════

    _BAG_CHECKPOINT_PREFIX = "bag_checkpoint:"
    _BAG_CHECKPOINT_TYPE = "checkpoint"

    def _bag_find_item(key: str):
        if not key:
            return None, None
        try:
            _store = getattr(_BAG, '_bag', {})
            if key in _store:
                return key, _store[key]

            _best_id, _best_item = None, None
            _best_ver = -1
            _best_mod = ""
            for _iid, _item in _store.items():
                if str(_item.get('name', '')) != str(key):
                    continue
                _ver = int(_item.get('version', 0) or 0)
                _mod = str((_item.get('metadata', {}) or {}).get('modified', '') or '')
                if _best_item is None or _ver > _best_ver or (_ver == _best_ver and _mod > _best_mod):
                    _best_id, _best_item = _iid, _item
                    _best_ver, _best_mod = _ver, _mod
            if _best_item is not None:
                return _best_id, _best_item
        except Exception:
            pass
        return None, None

    def _bag_item_text(item: dict) -> str:
        if not isinstance(item, dict):
            return ""
        _content = item.get('content', '')
        try:
            if hasattr(_BAG, '_decompress'):
                return _BAG._decompress(_content)
        except Exception:
            pass
        return str(_content)

    def _bag_is_checkpoint_name(name: str) -> bool:
        return str(name).startswith(_BAG_CHECKPOINT_PREFIX)

    def _bag_checkpoint_name(doc_name: str, ts: int = None) -> str:
        import time as _bt
        _ts = ts if ts is not None else int(_bt.time() * 1000)
        return f"{_BAG_CHECKPOINT_PREFIX}{doc_name}:{_ts}"

    def _bag_create_checkpoint(doc_key: str, message: str = "manual", tag: str = "manual") -> dict:
        import json as _bjson
        _iid, _item = _bag_find_item(doc_key)
        if not _item:
            return dict(error=f"Document not found: {doc_key}")
        _doc_name = str(_item.get('name', doc_key))
        if _bag_is_checkpoint_name(_doc_name):
            return dict(error="Cannot checkpoint checkpoint artifacts")

        _content = _bag_item_text(_item)
        _cp_name = _bag_checkpoint_name(_doc_name)
        _payload = _bjson.dumps(
            dict(
                source_key=_doc_name,
                source_item_id=_iid,
                source_type=_item.get('type', 'document'),
                source_version=_item.get('version', 1),
                checkpoint_key=_cp_name,
                checkpoint_message=message or "",
                checkpoint_tag=tag or "manual",
                content=_content,
            ),
            default=str,
        )
        _preview = f"checkpoint {_doc_name} v{_item.get('version', 1)}"
        _cp_id = _BAG.induct(_cp_name, _payload, item_type=_BAG_CHECKPOINT_TYPE, tags=['checkpoint', tag], preview=_preview)
        return dict(status="ok", checkpoint_id=_cp_id, checkpoint_key=_cp_name, source_key=_doc_name)

    def _bag_list_checkpoints(doc_key: str) -> list:
        import json as _bjson
        _prefix = f"{_BAG_CHECKPOINT_PREFIX}{doc_key}:"
        _rows = []
        _store = getattr(_BAG, '_bag', {})
        for _iid, _item in _store.items():
            _name = str(_item.get('name', ''))
            if not _name.startswith(_prefix):
                continue
            _ts = 0
            try:
                _ts = int(_name.rsplit(':', 1)[-1])
            except Exception:
                _ts = 0
            _raw = _bag_item_text(_item)
            _parsed = {}
            try:
                _parsed = _bjson.loads(_raw) if _raw else {}
            except Exception:
                _parsed = dict(content=_raw)
            _rows.append(
                dict(
                    checkpoint_key=_name,
                    checkpoint_id=_iid,
                    timestamp_ms=_ts,
                    source_key=_parsed.get('source_key', doc_key),
                    source_version=_parsed.get('source_version'),
                    message=_parsed.get('checkpoint_message', ''),
                    tag=_parsed.get('checkpoint_tag', ''),
                )
            )
        _rows.sort(key=lambda x: x.get('timestamp_ms', 0), reverse=True)
        return _rows

    def _bag_extract_checkpoint_payload(checkpoint_key: str) -> dict:
        import json as _bjson
        _iid, _item = _bag_find_item(checkpoint_key)
        if not _item:
            return dict(error=f"Checkpoint not found: {checkpoint_key}")
        _name = str(_item.get('name', ''))
        if not _bag_is_checkpoint_name(_name):
            return dict(error=f"Not a checkpoint artifact: {checkpoint_key}")
        _raw = _bag_item_text(_item)
        try:
            _data = _bjson.loads(_raw) if _raw else {}
            if isinstance(_data, dict):
                _data['_checkpoint_id'] = _iid
                _data['_checkpoint_key'] = _name
                return _data
            return dict(error="Checkpoint payload is not an object")
        except Exception as e:
            return dict(error=f"Invalid checkpoint payload: {e}")

    @logged_tool()
    def bag_read_doc(key: str) -> str:
        """Read a FelixBag document by key with metadata."""
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        _iid, _item = _bag_find_item(key)
        if not _item:
            return json.dumps(dict(error=f"Document not found: {key}"))
        _name = str(_item.get('name', key))
        if _bag_is_checkpoint_name(_name):
            return json.dumps(dict(error="Checkpoint artifacts are not regular documents", key=_name))
        _content = _bag_item_text(_item)
        return json.dumps(
            dict(
                key=_name,
                id=_iid,
                type=_item.get('type', 'document'),
                version=_item.get('version', 1),
                metadata=_item.get('metadata', {}),
                content=_content,
            ),
            indent=2,
            default=str,
        )

    @logged_tool()
    def bag_list_docs(filter_type: str = None, prefix: str = "", include_checkpoints: bool = False, limit: int = 200) -> str:
        """List FelixBag documents (workspace-scoped view)."""
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        _items = []
        _store = getattr(_BAG, '_bag', {})
        for _iid, _item in _store.items():
            _name = str(_item.get('name', ''))
            _is_cp = _bag_is_checkpoint_name(_name)
            if _is_cp and not include_checkpoints:
                continue
            if prefix and not _name.startswith(prefix):
                continue
            _itype = str(_item.get('type', ''))
            if filter_type and _itype != filter_type:
                continue
            _meta = _item.get('metadata', {})
            _items.append(
                dict(
                    id=_iid,
                    key=_name,
                    type=_itype,
                    version=_item.get('version', 1),
                    size=_meta.get('size', 0),
                    modified=_meta.get('modified'),
                    is_checkpoint=_is_cp,
                    preview=str(_item.get('preview', ''))[:120],
                )
            )
        # Deduplicate by key, keeping the newest/highest-version item.
        _by_key = {}
        for _it in _items:
            _k = str(_it.get('key', ''))
            _cur = _by_key.get(_k)
            if _cur is None:
                _by_key[_k] = _it
                continue
            _ver = int(_it.get('version', 0) or 0)
            _cur_ver = int(_cur.get('version', 0) or 0)
            _mod = str(_it.get('modified') or '')
            _cur_mod = str(_cur.get('modified') or '')
            if _ver > _cur_ver or (_ver == _cur_ver and _mod > _cur_mod):
                _by_key[_k] = _it
        _items = list(_by_key.values())
        _items.sort(key=lambda x: x.get('key', ''))
        if limit > 0:
            _items = _items[:limit]
        return json.dumps(dict(count=len(_items), items=_items), indent=2, default=str)

    @logged_tool()
    def bag_search_docs(query: str, limit: int = 10, prefix: str = "") -> str:
        """Semantic search over FelixBag documents."""
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        if hasattr(_BAG, 'search'):
            _rows = _BAG.search(query, top_k=limit * 5 if prefix else limit * 3)
            _best = {}
            for _r in _rows:
                _iid = _r[0] if len(_r) > 0 else ""
                _name = _r[1] if len(_r) > 1 else _iid
                _score = float(_r[2] if len(_r) > 2 else 0.0)
                _preview = _r[3] if len(_r) > 3 else ""
                if _bag_is_checkpoint_name(_name):
                    continue
                if prefix and not str(_name).startswith(prefix):
                    continue
                _cur = _best.get(str(_name))
                if _cur is None or _score > float(_cur.get('score', 0.0) or 0.0):
                    _best[str(_name)] = dict(id=_iid, key=_name, score=_score, preview=_preview)
            _results = sorted(_best.values(), key=lambda x: float(x.get('score', 0.0)), reverse=True)
            if limit > 0:
                _results = _results[:limit]
            return json.dumps(dict(query=query, count=len(_results), results=_results), indent=2, default=str)
        return json.dumps(dict(error="FelixBag semantic search unavailable"))

    @logged_tool()
    def bag_tree(prefix: str = "", max_depth: int = 4, include_checkpoints: bool = False) -> str:
        """Build a drillable tree view from FelixBag document keys."""
        _docs_raw = json.loads(bag_list_docs(prefix=prefix, include_checkpoints=include_checkpoints, limit=10000))
        _docs = _docs_raw.get('items', []) if isinstance(_docs_raw, dict) else []
        _tree = {}
        for _doc in _docs:
            _key = str(_doc.get('key', ''))
            if not _key:
                continue
            _parts = [p for p in _key.split('/') if p]
            if not _parts:
                _parts = [_key]
            if max_depth > 0:
                _parts = _parts[:max_depth]
            _node = _tree
            for _idx, _part in enumerate(_parts):
                _node.setdefault(_part, {})
                if _idx == len(_parts) - 1:
                    _node[_part].setdefault("_items", [])
                    _node[_part]["_items"].append(_key)
                _node = _node[_part]
        return json.dumps(dict(prefix=prefix, max_depth=max_depth, tree=_tree, document_count=len(_docs)), indent=2, default=str)

    @logged_tool()
    def bag_checkpoint(key: str, message: str = "", tag: str = "manual") -> str:
        """Create a checkpoint snapshot for a FelixBag document."""
        _cp = _bag_create_checkpoint(key, message=message or "manual checkpoint", tag=tag or "manual")
        if 'error' in _cp:
            return json.dumps(_cp)
        return json.dumps(_cp, indent=2, default=str)

    @logged_tool()
    def bag_versions(key: str, limit: int = 20) -> str:
        """List checkpoint history for a FelixBag document."""
        _iid, _item = _bag_find_item(key)
        if not _item:
            return json.dumps(dict(error=f"Document not found: {key}"))
        _doc_name = str(_item.get('name', key))
        _versions = _bag_list_checkpoints(_doc_name)
        if limit > 0:
            _versions = _versions[:limit]
        return json.dumps(
            dict(
                key=_doc_name,
                current_version=_item.get('version', 1),
                checkpoints=_versions,
                count=len(_versions),
            ),
            indent=2,
            default=str,
        )

    @logged_tool()
    def bag_diff(key: str, from_checkpoint: str = "", to_checkpoint: str = "current", context_lines: int = 3) -> str:
        """Diff a document against checkpoints (or between checkpoints)."""
        import difflib
        _iid, _item = _bag_find_item(key)
        if not _item:
            return json.dumps(dict(error=f"Document not found: {key}"))
        _doc_name = str(_item.get('name', key))
        _checkpoints = _bag_list_checkpoints(_doc_name)
        if not _checkpoints:
            return json.dumps(dict(error="No checkpoints available for diff", key=_doc_name))

        _from_key = from_checkpoint
        if not _from_key:
            _from_key = _checkpoints[0].get('checkpoint_key', '')
        _from_payload = _bag_extract_checkpoint_payload(_from_key)
        if 'error' in _from_payload:
            return json.dumps(_from_payload)
        _from_text = str(_from_payload.get('content', ''))

        if to_checkpoint == "current":
            _to_text = _bag_item_text(_item)
            _to_label = f"current:{_doc_name}"
        else:
            _to_payload = _bag_extract_checkpoint_payload(to_checkpoint)
            if 'error' in _to_payload:
                return json.dumps(_to_payload)
            _to_text = str(_to_payload.get('content', ''))
            _to_label = str(_to_payload.get('_checkpoint_key', to_checkpoint))

        _diff = list(
            difflib.unified_diff(
                _from_text.splitlines(),
                _to_text.splitlines(),
                fromfile=str(_from_payload.get('_checkpoint_key', _from_key)),
                tofile=_to_label,
                lineterm='',
                n=max(0, int(context_lines)),
            )
        )
        _added = sum(1 for _l in _diff if _l.startswith('+') and not _l.startswith('+++'))
        _removed = sum(1 for _l in _diff if _l.startswith('-') and not _l.startswith('---'))
        return json.dumps(
            dict(
                key=_doc_name,
                from_checkpoint=str(_from_payload.get('_checkpoint_key', _from_key)),
                to_target=_to_label,
                added_lines=_added,
                removed_lines=_removed,
                diff="\n".join(_diff),
            ),
            indent=2,
            default=str,
        )

    @logged_tool()
    def bag_restore(key: str, checkpoint_key: str, create_checkpoint: bool = True) -> str:
        """Restore a FelixBag document from a checkpoint snapshot."""
        _payload = _bag_extract_checkpoint_payload(checkpoint_key)
        if 'error' in _payload:
            return json.dumps(_payload)
        _target_key = key or str(_payload.get('source_key', ''))
        if not _target_key:
            return json.dumps(dict(error="Target key required for restore"))
        _content = str(_payload.get('content', ''))
        _source_type = str(_payload.get('source_type', 'document'))

        _existing_id, _existing_item = _bag_find_item(_target_key)
        _backup = None
        if create_checkpoint and _existing_item and not _bag_is_checkpoint_name(str(_existing_item.get('name', ''))):
            _backup = _bag_create_checkpoint(_target_key, message=f"pre-restore backup from {checkpoint_key}", tag="restore_backup")

        _new_id = _BAG.induct(_target_key, _content, item_type=_source_type, tags=['restored'], preview=f"restored from {checkpoint_key}")
        _new_item_id, _new_item = _bag_find_item(_target_key)
        return json.dumps(
            dict(
                status="ok",
                restored_key=_target_key,
                restored_item_id=_new_id or _new_item_id,
                restored_version=_new_item.get('version', 1) if isinstance(_new_item, dict) else None,
                from_checkpoint=str(_payload.get('_checkpoint_key', checkpoint_key)),
                backup_checkpoint=_backup.get('checkpoint_key') if isinstance(_backup, dict) else None,
            ),
            indent=2,
            default=str,
        )

    @logged_tool()
    def web_search(query: str, provider: str = "brave", count: int = 10, freshness: str = "", language: str = "en", api_key: str = "", base_url: str = "") -> str:
        """Run first-class web search (Brave, SearXNG, Serper)."""
        import os
        _executor = get_workflow_executor()
        _params = dict(
            provider=provider or "brave",
            query=query,
            count=int(count),
            freshness=freshness or "",
            language=language or "en",
        )
        if api_key:
            _params["api_key"] = api_key
        if base_url:
            _params["base_url"] = base_url
        _node = dict(id="mcp_web_search", type="web_search", parameters=_params)
        _ctx = {"$input": {}, "$env": dict(os.environ)}
        _result = _executor._execute_web_search(_node, {}, _ctx)
        return json.dumps(_result, indent=2, default=str)
    
    @logged_tool()
    def bag_catalog(filter_type: str = None) -> str:
        """List all items in the FelixBag memory.
        
        Args:
            filter_type: Optional filter ('model', 'text', 'file', etc.)
        
        Returns:
            JSON with bag contents
        """
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        raw = _BAG.catalog(filter_type=filter_type)
        items = [{"id": r[0], "name": r[1], "type": r[2], "preview": r[3], "size": r[4], "version": r[5]} for r in raw]
        return json.dumps({"count": len(items), "items": items}, indent=2)
    
    @logged_tool()
    def bag_induct(key: str, content: str, item_type: str = "text") -> str:
        """Add content to the FelixBag memory.
        
        Args:
            key: Unique key for the item
            content: Content to store
            item_type: Type of content ('text', 'json', 'code', etc.)
        
        Returns:
            JSON with induction result
        """
        # Auto-checkpoint existing document before overwrite (best-effort)
        try:
            _eid, _eitem = _bag_find_item(key)
            if _eitem and not _bag_is_checkpoint_name(str(_eitem.get('name', ''))):
                _bag_create_checkpoint(key, message="auto-checkpoint before bag_induct overwrite", tag="auto")
        except Exception:
            pass

        if hasattr(_BAG, 'induct'):
            _BAG.induct(key, content, item_type=item_type)
        elif hasattr(_BAG, 'put'):
            _BAG.put(key, content)
        else:
            _BAG._bag[key] = content
        try:
            _ragent = get_agent()
            _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
            _rbrain = getattr(_router, '_brain', _router)
            if _rbrain and hasattr(_rbrain, '_capture_reward'):
                _rbrain._capture_reward(source_key='bag_induct', event_id=key, metadata={'key': key, 'type': item_type})
        except Exception:
            pass
        return json.dumps({"status": "ok", "key": key, "type": item_type})
    
    @logged_tool()
    def bag_search(query: str, limit: int = 10) -> str:
        """Semantic search in the FelixBag memory.
        
        Args:
            query: Search query
            limit: Max results to return
        
        Returns:
            JSON with matching items
        """
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        if hasattr(_BAG, 'search'):
            results = _BAG.search(query, top_k=limit)
            return json.dumps({"query": query, "results": results}, indent=2)
        else:
            # Fallback: simple text matching
            items = _BAG.list()
            matches = [k for k in items if query.lower() in k.lower()][:limit]
            return json.dumps({"query": query, "matches": matches})
    
    @logged_tool()
    def bag_forget(key: str = "", pattern: str = "") -> str:
        """Remove item(s) from the FelixBag memory.

        Args:
            key: Single key to remove
            pattern: Prefix pattern for bulk delete (e.g. 'workflow_exec:*')

        Returns:
            JSON with status
        """
        if pattern:
            if hasattr(_BAG, 'forget'):
                count = _BAG.forget(pattern=pattern)
            elif hasattr(_BAG, '_bag'):
                prefix = pattern.rstrip('*')
                targets = [k for k, item in list(_BAG._bag.items()) if item.get('name', '').startswith(prefix) or k.startswith(prefix)]
                for k in targets:
                    del _BAG._bag[k]
                count = len(targets)
            else:
                count = 0
            try:
                _ragent = get_agent()
                _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
                _rbrain = getattr(_router, '_brain', _router)
                if _rbrain and hasattr(_rbrain, '_capture_reward'):
                    _rbrain._capture_reward(source_key='bag_forget', event_id=pattern, metadata={'pattern': pattern, 'deleted': count})
            except Exception:
                pass
            return json.dumps({"status": "ok", "pattern": pattern, "deleted": count})
        if not key:
            return json.dumps({"error": "key or pattern required"})
        _removed = False
        if hasattr(_BAG, 'forget'):
            _removed = bool(_BAG.forget(key))
        elif hasattr(_BAG, '_bag'):
            if key in _BAG._bag:
                del _BAG._bag[key]
                _removed = True
            else:
                # Fallback by name
                _hits = [k for k, item in list(_BAG._bag.items()) if str(item.get('name', '')) == str(key)]
                for _k in _hits:
                    del _BAG._bag[_k]
                _removed = bool(_hits)
        if not _removed:
            return json.dumps({"error": f"Key '{key}' not found"})
        try:
            _ragent = get_agent()
            _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
            _rbrain = getattr(_router, '_brain', _router)
            if _rbrain and hasattr(_rbrain, '_capture_reward'):
                _rbrain._capture_reward(source_key='bag_forget', event_id=key, metadata={'key': key})
        except Exception:
            pass
        return json.dumps({"status": "ok", "removed": key})
    
    @logged_tool()
    def bag_export(output_path: str = None) -> str:
        """Export the entire FelixBag to a file.
        
        Args:
            output_path: Optional output path (default: ./bag_export.json)
        
        Returns:
            JSON with export path
        """
        import json as json_module
        path = output_path or "bag_export.json"
        try:
            data = {}
            for key in _BAG.list():
                val = _BAG.get(key)
                data[key] = val
            with open(path, 'w', encoding='utf-8') as f:
                json_module.dump(data, f, indent=2, default=str)
            return json.dumps({"status": "ok", "path": path, "items": len(data)})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
