    @logged_tool()
    def unplug_slot(slot: int) -> str:
        """Remove a model from a council slot.
        
        Args:
            slot: Slot index to unplug
        
        Returns:
            JSON with status
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors') or slot >= len(brain.councilors):
            return json.dumps({"error": f"Invalid slot {slot}"})
        
        councilor = brain.councilors[slot]
        name = getattr(councilor, 'name', f'slot_{slot}')
        councilor.model = None
        councilor._model_source = None
        return json.dumps({"status": "ok", "unplugged": slot, "was": name})
    
    @logged_tool()
    def clone_slot(slot: int, count: int = 1) -> str:
        """Clone a model from one slot to create copies.
        
        Args:
            slot: Source slot to clone
            count: Number of clones to create
        
        Returns:
            JSON with clone results
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors') or slot >= len(brain.councilors):
            return json.dumps({"error": f"Invalid slot {slot}"})
        
        source = brain.councilors[slot]
        if not getattr(source, 'model', None):
            return json.dumps({"error": f"Slot {slot} is empty"})
        
        if not hasattr(source, '_clones'):
            source._clones = []
        cloned = 0
        for i, c in enumerate(brain.councilors):
            if cloned >= count:
                break
            if i != slot and getattr(c, 'model', None) is None:
                c.model = source.model
                c.name = f"{getattr(source, 'name', 'model')}_clone_{cloned}"
                c._model_source = getattr(source, '_model_source', None)
                source._clones.append(i)
                cloned += 1

        return json.dumps({"status": "ok", "source": slot, "cloned": cloned, "clone_slots": source._clones})
    
    @logged_tool()
    def mutate_slot(slot: int, rate: float = 0.1, scale: float = 0.05) -> str:
        """Mutate the adapter weights of a slot (evolutionary modification).
        
        Args:
            slot: Slot to mutate
            rate: Mutation rate (fraction of weights to change)
            scale: Mutation scale (magnitude of changes)
        
        Returns:
            JSON with mutation results
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors') or slot >= len(brain.councilors):
            return json.dumps({"error": f"Invalid slot {slot}"})
        
        councilor = brain.councilors[slot]
        adapter = getattr(councilor, 'adapter', None)

        # Check brain-level adapter weights (ScarecrowBrain / OuroborosBrain pattern)
        if adapter is None:
            inner_brain = getattr(brain, '_brain', brain)
            if not hasattr(inner_brain, 'adapter_in') and not hasattr(inner_brain, 'lora_A'):
                if hasattr(inner_brain, 'dreamer_world_model') and inner_brain.dreamer_world_model:
                    inner_brain = inner_brain.dreamer_world_model
            for attr_name in ('adapter_in', 'lora_A'):
                if hasattr(inner_brain, attr_name):
                    # Mutate brain-level adapter weights
                    mutated_total = 0
                    for wname in ('adapter_in', 'adapter_out', 'adapter_bias', 'lora_A', 'lora_B', 'lora_bias'):
                        w = getattr(inner_brain, wname, None)
                        if w is not None and hasattr(w, 'shape'):
                            mask = np.random.random(w.shape) < rate
                            noise = np.random.randn(*w.shape) * scale
                            setattr(inner_brain, wname, w + mask * noise)
                            mutated_total += int(mask.sum())
                    return json.dumps({"status": "ok", "slot": slot, "mutated_params": mutated_total, "target": "brain_adapter"})
                    break
            # Check councilor model for mutable weights
            model = getattr(councilor, 'model', None)
            if model is not None and hasattr(model, 'parameters'):
                return json.dumps({"error": "Slot has a model but no mutable adapter. Use plug_model to add an adapter-equipped model."})
            return json.dumps({"error": "Slot has no adapter to mutate"})

        if hasattr(adapter, 'mutate'):
            adapter.mutate(rate=rate, scale=scale)
            return json.dumps({"status": "ok", "slot": slot, "rate": rate, "scale": scale})
        else:
            # Manual mutation
            if hasattr(adapter, 'weight'):
                mask = np.random.random(adapter.weight.shape) < rate
                noise = np.random.randn(*adapter.weight.shape) * scale
                adapter.weight += mask * noise
                return json.dumps({"status": "ok", "slot": slot, "mutated_params": int(mask.sum())})

        return json.dumps({"error": "Could not mutate adapter"})
    
    @logged_tool()
    def rename_slot(slot: int, new_name: str) -> str:
        """Rename a council slot.
        
        Args:
            slot: Slot index
            new_name: New display name
        
        Returns:
            JSON with status
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors') or slot >= len(brain.councilors):
            return json.dumps({"error": f"Invalid slot {slot}"})
        
        old_name = getattr(brain.councilors[slot], 'name', f'slot_{slot}')
        brain.councilors[slot].name = new_name
        return json.dumps({"status": "ok", "slot": slot, "old": old_name, "new": new_name})
    
    @logged_tool()
    def swap_slots(slot_a: int, slot_b: int) -> str:
        """Swap two council slots.
        
        Args:
            slot_a: First slot index
            slot_b: Second slot index
        
        Returns:
            JSON with status
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots"})
        if slot_a >= len(brain.councilors) or slot_b >= len(brain.councilors):
            return json.dumps({"error": "Invalid slot indices"})
        
        brain.councilors[slot_a], brain.councilors[slot_b] = brain.councilors[slot_b], brain.councilors[slot_a]
        return json.dumps({"status": "ok", "swapped": [slot_a, slot_b]})
    
    @logged_tool()
    def slot_info(slot: int) -> str:
        """Get detailed information about a specific slot.
        
        Args:
            slot: Slot index
        
        Returns:
            JSON with slot details
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors') or slot >= len(brain.councilors):
            return json.dumps({"error": f"Invalid slot {slot}"})
        
        c = brain.councilors[slot]
        model = getattr(c, 'model', None)
        # Convert ModelType enum to string for JSON serialization
        model_type = getattr(c, '_model_type', None)
        if hasattr(model_type, 'value'):
            model_type = model_type.value
        elif model_type is not None:
            model_type = str(model_type)
        info = {
            "slot": slot,
            "name": getattr(c, 'name', f'slot_{slot}'),
            "plugged": model is not None,
            "source": getattr(c, '_model_source', None),
            "model_type": model_type
        }
        
        if model:
            info["model_class"] = type(model).__name__
            if hasattr(model, 'num_parameters'):
                info["parameters"] = model.num_parameters()
            elif hasattr(model, 'parameters'):
                try:
                    info["parameters"] = sum(p.numel() for p in model.parameters())
                except Exception:
                    pass
        
        adapter = getattr(c, 'adapter', None)
        if adapter:
            info["has_adapter"] = True
            if hasattr(adapter, 'weight'):
                info["adapter_params"] = adapter.weight.size if hasattr(adapter.weight, 'size') else 0
        
        return json.dumps(info, indent=2)
    
    @logged_tool()
    def get_slot_params() -> str:
        """Get parameter counts for all slots.
        
        Returns:
            JSON with parameter info
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots"})
        
        slots = []
        total_params = 0
        for i, c in enumerate(brain.councilors):
            model = getattr(c, 'model', None)
            params = 0
            if model:
                if hasattr(model, 'num_parameters'):
                    params = model.num_parameters()
                elif hasattr(model, 'parameters'):
                    try:
                        params = sum(p.numel() for p in model.parameters())
                    except Exception:
                        pass
            slots.append({"slot": i, "name": getattr(c, 'name', f'slot_{i}'), "params": params})
            total_params += params
        
        return json.dumps({"total_params": total_params, "slots": slots}, indent=2)
    
    # ═══════════════════════════════════════════════════════════
    # MCP TOOLS - Inference Modes
    # ═══════════════════════════════════════════════════════════
    
    @logged_tool()
    def infer(text: str = "") -> str:
        """Run full consensus inference through all council members.
        
        Args:
            text: Optional text input
        
        Returns:
            JSON with consensus result
        """
        agent = get_agent()
        obs = {'text': text or 'infer', 'input': np.random.rand(384).astype(np.float32)}
        
        try:
            result = agent.forward(obs)
        except Exception as e:
            import traceback
            return json.dumps({"error": str(e), "traceback": traceback.format_exc()})
        
        def serialize(v):
            if hasattr(v, 'tolist'):
                return v.tolist()
            elif isinstance(v, dict):
                return {k: serialize(vv) for k, vv in v.items()}
            elif isinstance(v, list):
                return [serialize(x) for x in v]
            return v
        
        return json.dumps(serialize(result), indent=2, default=str)
    
    @logged_tool()
    def generate(prompt: str, max_tokens: int = 256, temperature: float = 0.7) -> str:
        """Generate text using an LLM in a council slot.
        
        Args:
            prompt: Text prompt
            max_tokens: Maximum tokens to generate
            temperature: Sampling temperature
        
        Returns:
            JSON with generated text
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots"})
        
        for i, c in enumerate(brain.councilors):
            model = getattr(c, 'model', None)
            if model and hasattr(model, 'generate'):
                tokenizer = getattr(c, 'tokenizer', None)
                _lim = getattr(c, '_limits', getattr(model, '_limits', {}))
                _ctx = _lim.get('context_length', 4096)
                _gen = max_tokens or _lim.get('max_gen_tokens', 256)
                try:
                    if tokenizer:
                        _raw = getattr(model, 'model', model)
                        if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                            _sys = _council_system_prompt(i, brain)
                            messages = [{"role": "system", "content": _sys}, {"role": "user", "content": prompt}]
                            input_text = tokenizer.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
                            inputs = tokenizer(input_text, return_tensors="pt", truncation=True, max_length=_ctx)
                        else:
                            inputs = tokenizer(prompt, return_tensors="pt", truncation=True, max_length=_ctx)
                        input_len = inputs['input_ids'].shape[-1]
                        outputs = _raw.generate(**inputs, max_new_tokens=_gen, do_sample=True, temperature=temperature, pad_token_id=tokenizer.eos_token_id)
                        text = tokenizer.decode(outputs[0][input_len:], skip_special_tokens=True)
                    else:
                        try:
                            text = model.generate(prompt=prompt, max_tokens=_gen, temperature=temperature)
                        except TypeError:
                            text = model.generate(prompt)
                        text = str(text)
                    return json.dumps({"slot": i, "prompt": prompt, "output": text, "limits_used": _lim})
                except Exception as e:
                    return json.dumps({"error": str(e), "slot": i})

        return json.dumps({"error": "No LLM found in slots"})
    
    @logged_tool()
    def classify(text: str) -> str:
        """Classify text using a classification model in a council slot.
        
        Args:
            text: Text to classify
        
        Returns:
            JSON with classification result
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots"})
        
        for i, c in enumerate(brain.councilors):
            model = getattr(c, 'model', None)
            if model and hasattr(model, 'predict'):
                try:
                    result = model.predict([text])
                    return json.dumps({"slot": i, "input": text, "output": str(result), "classification": str(result)})
                except Exception as e:
                    pass
        
        return json.dumps({"error": "No classification model found in slots"})
    
    @logged_tool()
    def rerank(query: str, documents: list) -> str:
        """Rerank documents by relevance to a query.
        
        Args:
            query: Search query
            documents: List of documents to rank
        
        Returns:
            JSON with ranked documents
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots"})
        
        # Find embedding model
        embed_fn = None
        for c in brain.councilors:
            model = getattr(c, 'model', None)
            if model and hasattr(model, 'encode'):
                embed_fn = model.encode
                break
        
        if not embed_fn:
            if hasattr(brain, 'embedding_foundation') and brain.embedding_foundation:
                embed_fn = brain.embedding_foundation.encode
        
        if not embed_fn:
            return json.dumps({"error": "No embedding model found"})
        
        try:
            q_emb = embed_fn(query)
            doc_embs = [embed_fn(d) for d in documents]
            
            # Compute cosine similarities
            scores = []
            q_norm = np.linalg.norm(q_emb)
            for i, d_emb in enumerate(doc_embs):
                sim = np.dot(q_emb, d_emb) / (q_norm * np.linalg.norm(d_emb) + 1e-8)
                scores.append((i, float(sim), documents[i]))
            
            ranked = sorted(scores, key=lambda x: x[1], reverse=True)
            return json.dumps({"query": query, "ranked": [{"rank": r+1, "doc_idx": i, "score": s, "text": t[:100]} for r, (i, s, t) in enumerate(ranked)]}, indent=2)
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def broadcast(message: str) -> str:
        """Broadcast a message to all council members and collect responses.
        
        Args:
            message: Message to broadcast
        
        Returns:
            JSON with all responses
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors'):
            return json.dumps({"error": "No council slots"})
        
        responses = []
        for i, c in enumerate(brain.councilors):
            model = getattr(c, 'model', None)
            name = getattr(c, 'name', f'slot_{i}')
            if not model:
                responses.append({"slot": i, "name": name, "status": "empty"})
                continue
            
            _lim = getattr(c, '_limits', getattr(model, '_limits', {}))
            _ctx = _lim.get('context_length', 4096)
            _gen = _lim.get('max_gen_tokens', 256)
            try:
                if hasattr(model, 'encode'):
                    emb = model.encode(message)
                    responses.append({"slot": i, "name": name, "type": "embedding", "dim": len(emb)})
                elif hasattr(model, 'generate'):
                    tokenizer = getattr(c, 'tokenizer', None)
                    if tokenizer:
                        _raw = getattr(model, 'model', model)
                        if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                            _sys = _council_system_prompt(i, brain)
                            _msgs = [{"role": "system", "content": _sys}, {"role": "user", "content": message}]
                            _chat_text = tokenizer.apply_chat_template(_msgs, tokenize=False, add_generation_prompt=True)
                            inputs = tokenizer(_chat_text, return_tensors="pt", truncation=True, max_length=_ctx)
                        else:
                            inputs = tokenizer(message, return_tensors="pt", truncation=True, max_length=_ctx)
                        _in_len = inputs['input_ids'].shape[-1]
                        outputs = _raw.generate(**inputs, max_new_tokens=_gen, pad_token_id=tokenizer.eos_token_id)
                        text = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                    else:
                        try:
                            text = model.generate(prompt=message, max_tokens=_gen)
                        except TypeError:
                            text = model.generate(message)
                        text = str(text)
                    responses.append({"slot": i, "name": name, "type": "generation", "output": text[:200]})
                elif getattr(model, '_model_type_hint', None) == 'RERANKER':
                    _h = hash(message) % 1000 / 1000.0
                    responses.append({"slot": i, "name": name, "type": "reranker_hash", "output": str(_h)})
                elif hasattr(model, 'predict') or hasattr(model, 'classify'):
                    fn = getattr(model, 'predict', None) or getattr(model, 'classify', None)
                    result = fn(message)
                    responses.append({"slot": i, "name": name, "type": "classification", "output": str(result)[:200]})
                elif callable(model):
                    result = model(message)
                    responses.append({"slot": i, "name": name, "type": "forward", "output": str(result)[:200]})
                else:
                    responses.append({"slot": i, "name": name, "type": "unknown"})
            except Exception as e:
                responses.append({"slot": i, "name": name, "error": str(e)})
        
        return json.dumps({"message": message, "responses": responses}, indent=2)
    
    # ═══════════════════════════════════════════════════════════
    # MCP TOOLS - Status & Provenance
    # ═══════════════════════════════════════════════════════════
    
    @logged_tool()
    def get_status() -> str:
        """Get quick status of the capsule.
        
        Returns:
            JSON with status info
        """
        agent = get_agent()
        gen = getattr(agent, 'generation', 0)
        fit = getattr(agent, 'fitness', 0.0)
        
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        # Use dynamic fitness from brain if available
        if hasattr(brain, '_fitness'):
            fit = brain._fitness
        
        slots_filled = 0
        slots_total = 0
        if hasattr(brain, 'councilors'):
            slots_total = len(brain.councilors)
            slots_filled = sum(1 for c in brain.councilors if getattr(c, 'model', None))
        
        # Dreamer enrichment
        import time as _time
        dreamer_section = {"active": False, "fitness": 0.0}
        if hasattr(brain, 'dreamer_world_model') and brain.dreamer_world_model:
            dreamer_model = brain.dreamer_world_model
            has_real_rssm = bool(
                getattr(dreamer_model, '_has_real_rssm', False) and
                getattr(dreamer_model, '_rssm', None) is not None
            )
            dreamer_section["active"] = has_real_rssm
            dreamer_section["dreamer_present"] = True
            dreamer_section["has_real_rssm"] = has_real_rssm
            dreamer_section["rssm_import_error"] = globals().get('_RSSM_IMPORT_ERROR')
            if getattr(dreamer_model, '_rssm_init_error', None):
                dreamer_section["rssm_init_error"] = getattr(dreamer_model, '_rssm_init_error')
            dreamer_section["fitness"] = float(getattr(brain, '_fitness', 0.0))
            try:
                latent = dreamer_model._get_latent_vector()
                dreamer_section["critic_value"] = round(brain._critic.forward(latent), 4) if hasattr(brain, '_critic') else 0.0
            except Exception:
                dreamer_section["critic_value"] = 0.0
            dreamer_section["reward_count"] = getattr(brain, '_reward_count', 0)
            dreamer_section["training_cycles"] = getattr(brain, '_critic_training_count', 0)
            dreamer_section["obs_buffer_size"] = len(getattr(brain, '_obs_buffer', []))
            dreamer_section["reward_buffer_size"] = len(getattr(brain, '_reward_buffer', []))
            now = _time.time()
            window = list(getattr(brain, '_reward_rate_window', []))
            recent = [t for t in window if now - t < 60]
            dreamer_section["reward_rate"] = len(recent)
            if hasattr(dreamer_model, '_last_imagination') and dreamer_model._last_imagination:
                dreamer_section["imagination_branches"] = len(dreamer_model._last_imagination)
            dreamer_section["last_train"] = getattr(brain, '_last_train_stats', {})

            # Hold transmission data
            _hold_cfg = brain._dreamer_config.get('hold', {}) if hasattr(brain, '_dreamer_config') else {}
            dreamer_section["hold_config"] = {
                "confidence_threshold": _hold_cfg.get('confidence_threshold', 0.85),
                "expose_imagination": _hold_cfg.get('expose_imagination', True),
                "blocking": _hold_cfg.get('blocking', False),
                "auto_resolve_timeout": _hold_cfg.get('auto_resolve_timeout', 30),
            }
            dreamer_section["causation_hold_active"] = getattr(brain, '_causation_hold', None) is not None
            dreamer_section["causation_hold_steps"] = getattr(brain, '_hold_step_count', 0)
            try:
                import pathlib as _pathlib
                _state_path = _pathlib.Path(__file__).parent / 'dreamer_state.json'
                dreamer_section["persistence_file_exists"] = _state_path.exists()
            except Exception:
                dreamer_section["persistence_file_exists"] = False

        return json.dumps({
            "generation": gen,
            "fitness": fit,
            "brain_type": _BRAIN_CONFIG.get('brain_type', 'unknown'),
            "quine_hash": _QUINE_HASH,
            "slots_filled": slots_filled,
            "slots_total": slots_total,
            "bag_items": len(_BAG.list()) if hasattr(_BAG, 'list') else 0,
            "dreamer": dreamer_section,
        }, indent=2)

    @logged_tool()
    def get_artifacts() -> str:
        """List all embedded artifacts in the capsule.
        
        Returns:
            JSON with artifact manifest
        """
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        items = _BAG.list() if hasattr(_BAG, 'list') else []
        return json.dumps({"count": len(items), "artifacts": items}, indent=2)
    
    @logged_tool()
    def get_readme() -> str:
        """Get the embedded documentation/README.
        
        Returns:
            JSON with README content
        """
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        readme = _BAG.get('README') or _BAG.get('readme') or _BAG.get('documentation')
        if readme:
            return json.dumps({"readme": readme})
        return json.dumps({"readme": "No embedded documentation found", "available": _BAG.list()[:10]})
    
