    @logged_tool()
    def demo(steps: int = 10) -> str:
        """Run demo inferences to test the capsule.
        
        Args:
            steps: Number of demo steps to run
        
        Returns:
            JSON with demo results
        """
        # Deep serializer for numpy arrays
        def deep_serialize(v):
            if hasattr(v, 'item') and v.ndim == 0:
                return v.item()
            elif hasattr(v, 'tolist'):
                return v.tolist()
            elif isinstance(v, dict):
                return {k: deep_serialize(vv) for k, vv in v.items()}
            elif isinstance(v, (list, tuple)):
                return [deep_serialize(x) for x in v]
            return v
        
        agent = get_agent()
        results = []
        for i in range(steps):
            obs = {'frame': np.random.rand(84,84,3).astype(np.float32), 'step': i}
            r = agent.forward(obs)
            action = deep_serialize(r.get('action', r.get('output', 0)))
            value = deep_serialize(r.get('value', r.get('confidence', 0)))
            results.append({
                "step": i,
                "action": action,
                "value": float(value) if isinstance(value, (int, float)) and not isinstance(value, bool) else value
            })
        return json.dumps({"demo_steps": steps, "results": results}, indent=2)
    
    @logged_tool()
    def show_weights() -> str:
        """Show adapter/LoRA weights for the brain.
        
        Returns:
            JSON with weight statistics
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        result = {"brain_type": type(brain).__name__}
        
        # Check for different weight types
        if hasattr(brain, 'adapter_in'):
            result["adapter_in"] = {
                "shape": list(brain.adapter_in.shape),
                "min": float(brain.adapter_in.min()),
                "max": float(brain.adapter_in.max()),
                "mean": float(brain.adapter_in.mean())
            }
        if hasattr(brain, 'adapter_out'):
            result["adapter_out"] = {
                "shape": list(brain.adapter_out.shape),
                "min": float(brain.adapter_out.min()),
                "max": float(brain.adapter_out.max())
            }
        lora_src = brain
        if not hasattr(brain, 'lora_A') and hasattr(brain, 'dreamer_world_model') and brain.dreamer_world_model:
            lora_src = brain.dreamer_world_model
        if hasattr(lora_src, 'lora_A'):
            result["lora_A"] = {
                "shape": list(lora_src.lora_A.shape),
                "min": float(lora_src.lora_A.min()),
                "max": float(lora_src.lora_A.max())
            }
        if hasattr(lora_src, 'lora_B'):
            result["lora_B"] = {
                "shape": list(lora_src.lora_B.shape),
                "min": float(lora_src.lora_B.min()),
                "max": float(lora_src.lora_B.max())
            }
        if hasattr(brain, '_params') and brain._params is not None and len(brain._params) > 0:
            # Handle NaN/inf values gracefully
            params = brain._params
            finite_mask = np.isfinite(params)
            finite_count = int(np.sum(finite_mask))
            has_nan = bool(np.any(np.isnan(params)))
            has_inf = bool(np.any(np.isinf(params)))
            
            if finite_count > 0:
                finite_params = params[finite_mask]
                # Use nansum/nanmean for extra safety
                param_sum = float(np.nansum(finite_params))
                param_mean = float(np.nanmean(finite_params))
                param_std = float(np.nanstd(finite_params)) if finite_count > 1 else 0.0
                # Clamp to reasonable values if overflow occurred
                if not np.isfinite(param_sum):
                    param_sum = 0.0
                if not np.isfinite(param_mean):
                    param_mean = 0.0
                if not np.isfinite(param_std):
                    param_std = 0.0
                result["params"] = {
                    "count": len(params),
                    "finite_count": finite_count,
                    "sum": param_sum,
                    "mean": param_mean,
                    "std": param_std,
                    "has_nan": has_nan,
                    "has_inf": has_inf
                }
            else:
                result["params"] = {
                    "count": len(params),
                    "finite_count": 0,
                    "sum": 0.0,
                    "mean": 0.0,
                    "std": 0.0,
                    "has_nan": has_nan,
                    "has_inf": has_inf
                }
        
        return json.dumps(result, indent=2)
    
