    @logged_tool()
    def show_rssm() -> str:
        """Show RSSM configuration (Dreamer brains).
        
        Returns:
            JSON with RSSM details
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'config'):
            return json.dumps({"error": "No RSSM config available", "brain_type": type(brain).__name__})
        
        cfg = brain.config
        deter = cfg.get('deter_dim', 0)
        stoch = cfg.get('stoch_dim', 0) * cfg.get('stoch_classes', 0)
        
        result = {
            "deter_dim": cfg.get('deter_dim'),
            "stoch_dim": cfg.get('stoch_dim'),
            "stoch_classes": cfg.get('stoch_classes'),
            "hidden_dim": cfg.get('hidden_dim'),
            "action_dim": cfg.get('action_dim'),
            "imagine_horizon": cfg.get('imagine_horizon', 15),
            "total_latent": deter + stoch,
        }

        # Dreamer enrichment
        import time as _time
        dreamer_model = getattr(brain, 'dreamer_world_model', None) if hasattr(brain, 'dreamer_world_model') else None
        has_real_rssm = bool(
            dreamer_model is not None and
            getattr(dreamer_model, '_has_real_rssm', False) and
            getattr(dreamer_model, '_rssm', None) is not None
        )
        dreamer = {
            "active": has_real_rssm,
            "dreamer_present": dreamer_model is not None,
            "has_real_rssm": has_real_rssm,
            "rssm_import_error": globals().get('_RSSM_IMPORT_ERROR'),
        }
        if dreamer_model is not None and getattr(dreamer_model, '_rssm_init_error', None):
            dreamer["rssm_init_error"] = getattr(dreamer_model, '_rssm_init_error', None)
        if hasattr(brain, 'dreamer_world_model') and brain.dreamer_world_model:
            # Critic
            critic_data = {"value": 0.0, "target_value": 0.0, "param_count": 0}
            if hasattr(brain, '_critic'):
                try:
                    latent = dreamer_model._get_latent_vector()
                    critic_data["value"] = round(brain._critic.forward(latent), 6)
                    critic_data["target_value"] = round(brain._critic.forward_target(latent), 6)
                    critic_data["param_count"] = brain._critic.param_count
                except Exception:
                    pass
                value_hist = list(getattr(brain, '_value_history', []))
                critic_data["history_len"] = len(value_hist)
                if value_hist:
                    vals = [v for _, v in value_hist[-20:]]
                    critic_data["recent_values"] = [round(v, 4) for v in vals]
            dreamer["critic"] = critic_data

            # Rewards
            rewards_data = {
                "total_count": getattr(brain, '_reward_count', 0),
                "total_sum": round(getattr(brain, '_reward_sum', 0.0), 4),
                "buffer_size": len(getattr(brain, '_reward_buffer', [])),
            }
            now = _time.time()
            window = list(getattr(brain, '_reward_rate_window', []))
            rewards_data["rate_per_min"] = len([t for t in window if now - t < 60])
            recent_events = list(getattr(brain, '_reward_buffer', []))[-10:]
            rewards_data["recent"] = [evt.to_dict() for evt in recent_events]
            dreamer["rewards"] = rewards_data

            # Training
            dreamer["training"] = {
                "cycles": getattr(brain, '_training_cycles', 0),
                "critic_updates": getattr(brain, '_critic_training_count', 0),
                "last_stats": getattr(brain, '_last_train_stats', {}),
            }

            # Config (reload for freshness)
            if hasattr(brain, '_load_dreamer_config'):
                try:
                    brain._load_dreamer_config()
                except Exception:
                    pass
            dreamer["config"] = getattr(brain, '_dreamer_config', {})

            # Hold gate status
            _hold_cfg = brain._dreamer_config.get('hold', {}) if hasattr(brain, '_dreamer_config') else {}
            dreamer["hold_gate"] = {
                "confidence_threshold": _hold_cfg.get('confidence_threshold', 0.85),
                "expose_imagination": _hold_cfg.get('expose_imagination', True),
                "blocking": _hold_cfg.get('blocking', False),
                "causation_hold_active": getattr(brain, '_causation_hold', None) is not None,
                "causation_hold_steps": getattr(brain, '_hold_step_count', 0),
            }

        result["dreamer"] = dreamer
        return json.dumps(result, indent=2, default=str)

    @logged_tool()
    def show_lora() -> str:
        """Show LoRA adapter configuration.
        
        Returns:
            JSON with LoRA details
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)

        lora_source = brain
        if not hasattr(brain, 'lora_rank') and hasattr(brain, 'dreamer_world_model') and brain.dreamer_world_model:
            lora_source = brain.dreamer_world_model
        if not hasattr(lora_source, 'lora_rank'):
            return json.dumps({"error": "No LoRA adapter available", "brain_type": type(brain).__name__})

        return json.dumps({
            "lora_rank": lora_source.lora_rank,
            "lora_alpha": getattr(lora_source, 'lora_alpha', 1.0),
            "lora_A_shape": list(lora_source.lora_A.shape) if hasattr(lora_source, 'lora_A') else None,
            "lora_B_shape": list(lora_source.lora_B.shape) if hasattr(lora_source, 'lora_B') else None,
            "lora_bias_shape": list(lora_source.lora_bias.shape) if hasattr(lora_source, 'lora_bias') else None
        }, indent=2)

