    # MCP TOOLS - Quine/Clone Operations
    # ═══════════════════════════════════════════════════════════
    
    @logged_tool()
    def spawn_quine(count: int = 3, observation_seconds: int = 60) -> str:
        """Spawn ephemeral quine clones that self-destruct after observation.
        
        Args:
            count: Number of clones to spawn
            observation_seconds: Seconds before auto-cleanup
        
        Returns:
            JSON with spawn results
        """
        import time
        import subprocess
        import hashlib
        import re
        import sys
        
        spawn_dir = Path(f"quine_spawn_{int(time.time())}")
        spawn_dir.mkdir(exist_ok=True)
        
        clones = []
        own_source = Path(__file__).read_text(encoding='utf-8')
        
        for i in range(count):
            new_genesis = hashlib.sha256(f"{time.time()}_{i}".encode()).hexdigest()[:16]
            clone_name = f"clone_{i}_{new_genesis[:8]}.py"
            clone_path = spawn_dir / clone_name
            
            clone_source = re.sub(
                r'_GENESIS_ROOT = "[a-f0-9]+"',
                f'_GENESIS_ROOT = "{new_genesis}"',
                own_source
            )
            
            clone_path.write_text(clone_source, encoding='utf-8')
            clones.append({"path": str(clone_path), "genesis": new_genesis})
        
        # Spawn cleanup process
        cleanup = f"import time, shutil\ntime.sleep({observation_seconds})\nshutil.rmtree('{spawn_dir}', ignore_errors=True)"
        cleanup_path = spawn_dir / "_cleanup.py"
        cleanup_path.write_text(cleanup, encoding='utf-8')
        
        try:
            if sys.platform == 'win32':
                subprocess.Popen(['python', str(cleanup_path)], 
                    creationflags=subprocess.CREATE_NO_WINDOW | subprocess.DETACHED_PROCESS,
                    stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            else:
                subprocess.Popen(['python', str(cleanup_path)],
                    start_new_session=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        except Exception:
            pass
        
        return json.dumps({
            "status": "ok",
            "spawn_dir": str(spawn_dir),
            "clones": clones,
            "cleanup_in_seconds": observation_seconds
        }, indent=2)
    
    @logged_tool()
    def orchestra(test_input: str = None) -> str:
        """Run swarm orchestration - inference through all spawned clones.
        
        Args:
            test_input: Optional test input text
        
        Returns:
            JSON with orchestrated results
        """
        agent = get_agent()
        swarm = getattr(agent, '_swarm', None)
        
        if not swarm:
            return json.dumps({"error": "No swarm active. Use spawn_swarm first."})
        
        test_vec = np.random.rand(384).astype(np.float32)
        outputs = []
        
        for i, clone in enumerate(swarm):
            try:
                result = clone.forward({'input': test_vec, 'text': test_input or 'test'})
                out = result.get('output', result.get('embedding', np.zeros(10)))
                if hasattr(out, 'tolist'):
                    out = out.tolist()
                outputs.append({"clone": i, "output_mean": float(np.mean(out)), "status": "ok"})
            except Exception as e:
                outputs.append({"clone": i, "error": str(e), "status": "error"})
        
        if outputs:
            means = [o.get('output_mean', 0) for o in outputs if o.get('status') == 'ok']
            consensus = float(np.mean(means)) if means else 0
            divergence = float(np.std(means)) if means else 0
        else:
            consensus = 0
            divergence = 0
        
        return json.dumps({
            "swarm_size": len(swarm),
            "outputs": outputs,
            "consensus_mean": consensus,
            "divergence": divergence
        }, indent=2)
    
    @logged_tool()
    def tree() -> str:
        """Show clone family tree.
        
        Returns:
            JSON with lineage tree
        """
        agent = get_agent()
        g = globals()
        
        # Build lineage from _NODE_DOCS
        lineage = []
        node_docs = g.get('_NODE_DOCS', [])
        if node_docs:
            for doc in node_docs:
                lineage.append({
                    "node_id": doc.get("node_id", "unknown"),
                    "generation_born": doc.get("generation_born", 0),
                    "fitness": doc.get("fitness", 0.0),
                    "parent_ids": doc.get("parent_ids", [])
                })
        
        return json.dumps({
            "root": g.get('_GENESIS_ROOT', 'unknown'),
            "current": g.get('_QUINE_HASH', 'unknown'),
            "generation": getattr(agent, 'generation', 0),
            "lineage": lineage,
            "children": []
        }, indent=2)
    
