    @logged_tool()
    def capture_model(model_id: str) -> str:
        """Capture a HuggingFace model's artifacts to FelixBag.
        
        Args:
            model_id: HuggingFace model ID
        
        Returns:
            JSON with capture status
        """
        try:
            from huggingface_hub import snapshot_download, model_info
            info = model_info(model_id)
            path = snapshot_download(model_id)
            
            captured = []
            from pathlib import Path
            for f in Path(path).glob('*'):
                if f.is_file() and f.stat().st_size < 10_000_000:  # < 10MB
                    key = f"model_{model_id.replace('/', '_')}_{f.name}"
                    content = f.read_text(encoding='utf-8') if f.suffix in ['.json', '.txt', '.md'] else f"[binary: {f.stat().st_size} bytes]"
                    if hasattr(_BAG, 'induct'):
                        _BAG.induct(key, content, item_type='model_artifact')
                    captured.append(key)
            
            return json.dumps({"status": "ok", "model": model_id, "captured": captured}, indent=2)
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def grab_slot(slot: int) -> str:
        """Grab a slot's model info to FelixBag for later restore.
        
        Args:
            slot: Slot index to grab
        
        Returns:
            JSON with grab status
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors') or slot >= len(brain.councilors):
            return json.dumps({"error": f"Invalid slot {slot}"})
        
        councilor = brain.councilors[slot]
        model_source = getattr(councilor, '_model_source', None)
        name = getattr(councilor, 'name', f'slot_{slot}')
        
        if not model_source:
            return json.dumps({"error": f"Slot {slot} has no model source to grab"})
        
        key = f"grabbed_slot_{slot}_{name}"
        if hasattr(_BAG, 'induct'):
            _BAG.induct(key, json.dumps({"source": model_source, "name": name, "slot": slot}), item_type='slot_backup')
        
        return json.dumps({"status": "ok", "key": key, "source": model_source})
    
    @logged_tool()
    def restore_slot(key: str, slot: int = None) -> str:
        """Restore a model from FelixBag to a slot.
        
        Args:
            key: FelixBag key for the grabbed slot
            slot: Target slot (optional, uses original if not specified)
        
        Returns:
            JSON with restore status
        """
        data = _BAG.get(key)
        if not data:
            return json.dumps({"error": f"Key '{key}' not found in bag"})
        
        try:
            info = json.loads(data) if isinstance(data, str) else data
            model_source = info.get('source')
            target_slot = slot if slot is not None else info.get('slot', 0)
            
            # Use plug_model to restore
            from transformers import AutoModel, AutoTokenizer
            model = AutoModel.from_pretrained(model_source, trust_remote_code=True)
            
            agent = get_agent()
            outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
            brain = getattr(outer_brain, '_brain', outer_brain)
            
            if hasattr(brain, 'councilors') and target_slot < len(brain.councilors):
                brain.councilors[target_slot].model = model
                brain.councilors[target_slot]._model_source = model_source
                return json.dumps({"status": "ok", "slot": target_slot, "source": model_source})
            
            return json.dumps({"error": "Could not restore to slot"})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def summon(query: str, k: int = 5) -> str:
        """Semantic search in FelixBag and retrieve best matches.
        
        Args:
            query: Search query
            k: Number of results
        
        Returns:
            JSON with matched items
        """
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        
        if hasattr(_BAG, 'search'):
            results = _BAG.search(query, top_k=k)
            return json.dumps({"query": query, "results": results}, indent=2)
        
        # Fallback: text matching
        items = _BAG.list()
        matches = []
        for key in items:
            if query.lower() in key.lower():
                val = _BAG.get(key)
                matches.append({"key": key, "preview": str(val)[:200] if val else None})
                if len(matches) >= k:
                    break
        
        return json.dumps({"query": query, "matches": matches})
    
    @logged_tool()
    def pocket(text: str, key: str = None) -> str:
        """Quick text storage in FelixBag.
        
        Args:
            text: Text to store
            key: Optional key (auto-generated if not provided)
        
        Returns:
            JSON with storage confirmation
        """
        import time
        key = key or f"pocket_{int(time.time())}"
        
        if hasattr(_BAG, 'induct'):
            _BAG.induct(key, text, item_type='pocket')
        elif hasattr(_BAG, 'put'):
            _BAG.put(key, text)
        else:
            _BAG._bag[key] = text
        
        return json.dumps({"status": "ok", "key": key, "length": len(text)})
    
    @logged_tool()
    def materialize(key: str, output_path: str = None) -> str:
        """Export a FelixBag item to the filesystem.
        
        Args:
            key: Key to export
            output_path: Optional output path
        
        Returns:
            JSON with export path
        """
        val = _BAG.get(key)
        if val is None:
            return json.dumps({"error": f"Key '{key}' not found"})
        
        path = output_path or f"materialized_{key.replace('/', '_')}.txt"
        try:
            with open(path, 'w', encoding='utf-8') as f:
                f.write(str(val))
            return json.dumps({"status": "ok", "path": path, "size": len(str(val))})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
