    @logged_tool()
    def set_consensus(method: str) -> str:
        """Set the council consensus method.
        
        Args:
            method: Consensus method ('majority', 'weighted', 'debate', 'adversarial', 'hierarchical', 'bayesian')
        
        Returns:
            JSON with new consensus setting
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
