    @logged_tool()
    def vast_connect(instance_id: str) -> str:
        """Connect to a Vast.ai instance for remote inference.
        
        Args:
            instance_id: Instance ID to connect to
        
        Returns:
            JSON with connection status
        """
        import subprocess
        try:
            result = subprocess.run(['vastai', 'show', 'instances', '--raw'],
                                   capture_output=True, text=True, timeout=60)
            if result.returncode != 0:
                return json.dumps({"error": result.stderr})
            
            instances = json.loads(result.stdout)
            target = None
            for inst in instances:
                if str(inst.get('id')) == str(instance_id):
                    target = inst
                    break
            
            if not target:
                return json.dumps({"error": f"Instance {instance_id} not found"})
            
            ssh_host = target.get('ssh_host', '')
            ssh_port = target.get('ssh_port', '')
            
            # Store connection info for later use
            agent = get_agent()
            agent._vast_connection = {
                "id": instance_id,
                "host": ssh_host,
                "port": ssh_port,
                "status": target.get('actual_status', 'unknown')
            }
            
            return json.dumps({
                "status": "ok",
                "instance_id": instance_id,
                "ssh": f"{ssh_host}:{ssh_port}" if ssh_host else "not available",
                "instance_status": target.get('actual_status')
            })
        except Exception as e:
            return json.dumps({"error": str(e)})
    
