    @logged_tool()
    def diagnose_file(file_path: str) -> str:
        """Run CASCADE diagnostics on a Python file.
        
        Uses SymbioticAdapter, CodeTracer, and BugDetector to analyze code
        for potential issues, anomalies, and patterns.
        
        Args:
            file_path: Path to Python file to analyze
        
        Returns:
            JSON with diagnostic findings
        """
        try:
            from cascade.diagnostics import diagnose, DiagnosticEngine
            from pathlib import Path
            
            engine = DiagnosticEngine()
            report = engine.analyze_file(Path(file_path))
            
            # Extract findings with defensive attribute access
            findings_list = []
            if hasattr(report, 'findings'):
                for f in report.findings:
                    # Convert location to string (may be WindowsPath)
                    loc = getattr(f, 'location', None)
                    if loc is not None and hasattr(loc, '__fspath__'):
                        loc = str(loc)
                    findings_list.append({
                        "type": getattr(f, 'finding_type', None) or getattr(f, 'finding_id', None) or getattr(f, 'type', 'unknown'),
                        "severity": getattr(f, 'severity', 'info'),
                        "message": getattr(f, 'message', str(f)),
                        "location": str(loc) if loc else None,
                        "suggestion": getattr(f, 'suggestion', None)
                    })
            
            return json.dumps({
                "file": file_path,
                "findings": findings_list,
                "summary": report.to_markdown()[:50000] if hasattr(report, 'to_markdown') else str(report)
            }, indent=2)
        except Exception as e:
            import traceback
            return json.dumps({"error": str(e), "traceback": traceback.format_exc()})
    
