    @logged_tool()
    def relay_send(command: str) -> str:
        """Send a command through the relay center.
        
        Args:
            command: Command to send to TUI
        
        Returns:
            JSON with send status
        """
        relay_file = Path(__file__).parent / '.relay_center.cmd'
        try:
            with open(relay_file, 'a', encoding='utf-8') as f:
                f.write(f"{command}\n")
            return json.dumps({"status": "ok", "command": command})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
