    @logged_tool()
    def cull_slot(slot: int, count: int = None) -> str:
        """Remove clones from a slot.
        
        Args:
            slot: Slot index to cull clones from
            count: Number of clones to remove (default: all)
        
        Returns:
            JSON with cull result
        """
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        
        if not hasattr(brain, 'councilors') or slot >= len(brain.councilors):
            return json.dumps({"error": f"Invalid slot {slot}"})
        
        c = brain.councilors[slot]
        clones = getattr(c, '_clones', [])
        if not clones:
            return json.dumps({"error": f"Slot {slot} has no clones to cull"})
        
        if count is None:
            culled = len(clones)
            c._clones = []
        else:
            culled = min(count, len(clones))
            c._clones = clones[culled:]
        
        return json.dumps({"slot": slot, "culled": culled, "remaining": len(getattr(c, '_clones', []))})
    
    @logged_tool()
    def load_manifest() -> str:
        """Load slot configuration from manifest file.
        
        Returns:
            JSON with manifest contents
        """
        try:
            p = Path(__file__).parent / '.slot_manifest.json'
            if p.exists():
                data = json.loads(p.read_text(encoding='utf-8'))
                return json.dumps({"manifest": data, "path": str(p)})
            return json.dumps({"error": "No manifest file found"})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def load_bag(file_path: str) -> str:
        """Load items from a bag file into FelixBag.
        
        Args:
            file_path: Path to bag JSON file
        
        Returns:
            JSON with load result
        """
        try:
            p = Path(file_path)
            if not p.exists():
                return json.dumps({"error": f"File not found: {file_path}"})
            
            data = json.loads(p.read_text(encoding='utf-8'))
            loaded = 0
            for k, v in data.items():
                if k not in _BAG._bag:
                    _BAG._bag[k] = v
                    loaded += 1
            
            return json.dumps({"loaded": loaded, "total_in_file": len(data), "path": file_path})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
    @logged_tool()
    def save_bag(file_path: str = "bag_export.json") -> str:
        """Save FelixBag contents to a file.
        
        Args:
            file_path: Output path for bag JSON
        
        Returns:
            JSON with save result
        """
        try:
            p = Path(file_path)
            p.write_text(json.dumps(_BAG._bag, indent=2, default=str), encoding='utf-8')
            return json.dumps({"saved": len(_BAG._bag), "path": file_path})
        except Exception as e:
            return json.dumps({"error": str(e)})
    
