    @logged_tool()
    def heartbeat() -> str:
        """Lightweight status check for async monitoring.
        
        Returns:
            JSON with alive status, uptime, and key metrics
        """
        import time
        agent = get_agent()
        uptime = time.time() - getattr(agent, '_start_time', time.time())
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)
        members = getattr(brain, 'councilors', getattr(brain, 'all_members', []))
        plugged = sum(1 for c in members if getattr(c, 'model', None) is not None)
        
        return json.dumps({
            "status": "alive",
            "uptime_seconds": int(uptime),
            "relay_listening": getattr(agent, '_relay_listening', False),
            "vast_enabled": getattr(agent, '_vast_enabled', False),
            "slots_plugged": plugged,
            "slots_total": len(members),
            "timestamp": time.time()
        })
    
    @logged_tool()
    def spawn_tui(detached: bool = True) -> str:
        """Spawn the embedded TUI as a subprocess for visualization.
        
        The TUI provides real-time visualization of:
        - Inference results and latency
        - Council deliberations and votes
        - Memory operations
        - Evolution metrics
        
        Args:
            detached: If True, run TUI in background. If False, block until TUI exits.
        
        Returns:
            JSON with status and process info
        """
        import subprocess
        import sys
        
        try:
            # Get the capsule's own path
            capsule_path = __file__
            
            # Build command to run TUI
            cmd = [sys.executable, capsule_path, "--tui"]
            
            if detached:
                # Run in background
                if sys.platform == "win32":
                    # CREATE_NEW_CONSOLE gives the TUI its own console window
                    # Do NOT redirect stdout/stderr - Textual needs them for rendering
                    process = subprocess.Popen(
                        cmd,
                        creationflags=subprocess.CREATE_NEW_CONSOLE
                    )
                else:
                    process = subprocess.Popen(
                        cmd,
                        stdout=subprocess.DEVNULL,
                        stderr=subprocess.DEVNULL,
                        start_new_session=True
                    )
                return json.dumps({
                    "status": "spawned",
                    "pid": process.pid,
                    "detached": True,
                    "command": " ".join(cmd)
                })
            else:
                # Run in foreground, wait for exit
                result = subprocess.run(cmd, capture_output=True, text=True)
                return json.dumps({
                    "status": "completed",
                    "return_code": result.returncode,
                    "stdout": result.stdout[:1000] if result.stdout else "",
                    "stderr": result.stderr[:500] if result.stderr else ""
                })
        except Exception as e:
            return json.dumps({"error": str(e)})

