    # CASCADE-LATTICE TOOLS - Composable Building Blocks
    # ═══════════════════════════════════════════════════════════════

    @logged_tool()
    def cascade_graph(operation: str, params: str = "{}") -> str:
        """CausationGraph operations for causal reasoning.

        Operations: create, add_event, add_link, get_causes, get_effects, recent, connections, stats

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        """
        import json, time
        try:
            from cascade.core.graph import CausationGraph
            from cascade.core.event import Event as CEvt, CausationLink as CLink
            p = json.loads(params) if isinstance(params, str) else params
            if not hasattr(cascade_graph, '_g'):
                cascade_graph._g = {}

            def _persist_graph(gid, g):
                try:
                    _gd = {"events": [e.to_dict() for e in g._events.values()],
                            "links": [l.to_dict() for l in g._links]}
                    _BAG.induct("cascade_graph:" + gid, json.dumps(_gd), item_type='state')
                except Exception:
                    pass

            def _restore_graph(gid):
                try:
                    _bv = _BAG.get("cascade_graph:" + gid)
                    if _bv:
                        _gd = json.loads(_bv)
                        g = CausationGraph()
                        for ed in _gd.get("events", []):
                            g.add_event(CEvt.from_dict(ed))
                        for ld in _gd.get("links", []):
                            g.add_link(CLink.from_dict(ld))
                        cascade_graph._g[gid] = g
                        return g
                except Exception:
                    pass
                return None

            gid = p.get('graph_id', 'default')
            if operation == 'create':
                cascade_graph._g[gid] = CausationGraph()
                return json.dumps({"status": "created", "graph_id": gid})
            g = cascade_graph._g.get(gid)
            if g is None:
                g = _restore_graph(gid)
            if g is None:
                g = CausationGraph()
                cascade_graph._g[gid] = g
            if operation == 'add_event':
                evt = CEvt(
                    timestamp=p.get('timestamp', time.time()),
                    component=p.get('component', 'mcp'),
                    event_type=p.get('event_type', 'observation'),
                    data=p.get('data', {})
                )
                g.add_event(evt)
                _persist_graph(gid, g)
                return json.dumps({"status": "added", "event_id": evt.event_id})
            elif operation == 'add_link':
                link = CLink(
                    from_event=p['from_event'],
                    to_event=p['to_event'],
                    causation_type=p.get('causation_type', 'direct'),
                    strength=p.get('strength', 1.0),
                    explanation=p.get('explanation', '')
                )
                g.add_link(link)
                _persist_graph(gid, g)
                return json.dumps({"status": "linked"})
            elif operation == 'get_causes':
                causes = g.get_causes(p['event_id'])
                return json.dumps({"causes": [e.to_dict() for e in causes]})
            elif operation == 'get_effects':
                effects = g.get_effects(p['event_id'])
                return json.dumps({"effects": [e.to_dict() for e in effects]})
            elif operation == 'recent':
                evts = g.get_recent_events(p.get('count', 50))
                return json.dumps({"events": [e.to_dict() for e in evts]})
            elif operation == 'connections':
                conns = g.get_component_connections()
                return json.dumps({"connections": {str(k): v for k, v in conns.items()}})
            elif operation == 'stats':
                return json.dumps({"graph_id": gid, "events": g._event_count, "links": g._link_count, "graphs": len(cascade_graph._g)})
            else:
                return json.dumps({"error": "Unknown op: " + operation, "ops": ["create", "add_event", "add_link", "get_causes", "get_effects", "recent", "connections", "stats"]})
        except Exception as e:
            return json.dumps({"error": str(e)})

    @logged_tool()
    def cascade_chain(operation: str, params: str = "{}") -> str:
        """ProvenanceChain, Identity, and Genesis operations.

        Operations: create_chain, add_record, finalize, verify, link_external, identity, genesis

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        """
        import json, time, hashlib
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if not hasattr(cascade_chain, '_chains'):
                cascade_chain._chains = {}

            def _get_chain(cid):
                """Look up chain in memory, fall back to FelixBag."""
                chain = cascade_chain._chains.get(cid)
                if chain:
                    return chain
                try:
                    _bag_val = _BAG.get("cascade_chain:" + cid)
                    if _bag_val:
                        from cascade.core.provenance import ProvenanceChain
                        chain = ProvenanceChain.from_dict(json.loads(_bag_val))
                        cascade_chain._chains[cid] = chain
                        return chain
                except Exception:
                    pass
                return None

            def _persist_chain(cid, chain):
                """Persist chain to FelixBag for cross-restart survival."""
                try:
                    _BAG.induct("cascade_chain:" + cid, chain.to_json(), item_type='state')
                except Exception:
                    pass

            if operation == 'create_chain':
                from cascade.core.provenance import ProvenanceChain
                sid = p.get('session_id', 'mcp_' + str(int(time.time())))
                chain = ProvenanceChain(
                    session_id=sid,
                    model_id=p.get('model_id', 'unknown'),
                    model_hash=p.get('model_hash', hashlib.sha256(p.get('model_id', 'unknown').encode()).hexdigest()[:16]),
                    input_hash=p.get('input_hash', hashlib.sha256(json.dumps(p).encode()).hexdigest()[:16])
                )
                cascade_chain._chains[sid] = chain
                _persist_chain(sid, chain)
                return json.dumps({"status": "created", "chain_id": sid})
            elif operation == 'add_record':
                from cascade.core.provenance import ProvenanceRecord
                cid = p.get('chain_id', '')
                chain = _get_chain(cid)
                if not chain:
                    return json.dumps({"error": "Chain not found: " + cid})
                rec = ProvenanceRecord(
                    layer_name=p.get('layer_name', 'layer_0'),
                    layer_idx=p.get('layer_idx', 0),
                    state_hash=p.get('state_hash', hashlib.sha256(json.dumps(p.get('data', {})).encode()).hexdigest()[:16]),
                    parent_hashes=p.get('parent_hashes', [])
                )
                chain.add_record(rec)
                _persist_chain(cid, chain)
                return json.dumps({"status": "recorded", "layer": rec.layer_name})
            elif operation == 'finalize':
                cid = p.get('chain_id', '')
                chain = _get_chain(cid)
                if not chain:
                    return json.dumps({"error": "Chain not found"})
                root = chain.finalize()
                _persist_chain(cid, chain)
                return json.dumps({"status": "finalized", "merkle_root": root})
            elif operation == 'verify':
                cid = p.get('chain_id', '')
                chain = _get_chain(cid)
                if not chain:
                    return json.dumps({"error": "Chain not found"})
                ok, msg = chain.verify()
                return json.dumps({"valid": ok, "message": msg})
            elif operation == 'link_external':
                cid = p.get('chain_id', '')
                chain = _get_chain(cid)
                if not chain:
                    return json.dumps({"error": "Chain not found"})
                chain.link_external(p.get('external_root', ''), p.get('source_id'))
                _persist_chain(cid, chain)
                return json.dumps({"status": "linked"})
            elif operation == 'identity':
                return json.dumps({
                    "capsule_id": _QUINE_HASH[:16],
                    "generation": _GENERATION,
                    "brain_type": _BRAIN_CONFIG.get('brain_type', 'unknown'),
                    "capsule_name": capsule_name,
                    "integrity": "verified" if verify_quine_integrity() else "unverified",
                })
            elif operation == 'genesis':
                from cascade.genesis import get_genesis_root, verify_lineage_to_genesis
                root = get_genesis_root()
                # verify_lineage_to_genesis requires (chain, known_chains) args
                # Without an active chain context, report genesis root and capsule lineage
                lineage_info = {
                    "genesis_root": str(root),
                    "capsule_hash": _QUINE_HASH[:16],
                    "generation": _GENERATION,
                    "genesis_linked": str(root) in _QUINE_HASH or _GENESIS_ROOT == str(root)[:16],
                }
                return json.dumps(lineage_info)
            else:
                return json.dumps({"error": "Unknown op: " + operation, "ops": ["create_chain", "add_record", "finalize", "verify", "link_external", "identity", "genesis"]})
        except Exception as e:
            return json.dumps({"error": str(e)})

    @logged_tool()
    def cascade_data(operation: str, params: str = "{}") -> str:
        """Dataset observation - PII scanning, schema inference, license analysis.

        Operations: pii_scan, schema, license_check, observe

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        """
        import json
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if operation == 'pii_scan':
                from cascade.data.pii import PIIScanner
                scanner = PIIScanner()
                findings = scanner.scan_text(p.get('text', ''))
                results = []
                for f in (findings if findings else []):
                    if hasattr(f, 'to_dict'):
                        results.append(f.to_dict())
                    elif hasattr(f, '__dict__'):
                        results.append(f.__dict__)
                    else:
                        results.append(str(f))
                return json.dumps({"pii_found": results, "count": len(results)})
            elif operation == 'schema':
                from cascade.data.schema import SchemaObserver
                observer = SchemaObserver()
                data = p.get('data', {})
                # Convert list-of-dicts to dict-of-lists (columnar) if needed
                if isinstance(data, list) and data and isinstance(data[0], dict):
                    columnar = {}
                    for row in data:
                        for k, v in row.items():
                            columnar.setdefault(k, []).append(v)
                    data = columnar
                elif not isinstance(data, dict):
                    data = {"value": [data] if not isinstance(data, list) else data}
                schema = observer.observe_dict(data)
                if hasattr(schema, 'to_dict'):
                    return json.dumps({"schema": schema.to_dict()}, default=str)
                return json.dumps({"schema": str(schema)})
            elif operation == 'license_check':
                from cascade.data.license import LicenseAnalyzer
                analyzer = LicenseAnalyzer()
                license_id = p.get('license', p.get('text', 'unknown'))
                source_licenses = [("input", license_id)]
                target = p.get('target', None)
                result = analyzer.check_compatibility(source_licenses, target_license=target)
                if hasattr(result, 'to_dict'):
                    return json.dumps(result.to_dict(), default=str)
                elif isinstance(result, dict):
                    return json.dumps(result, default=str)
                return json.dumps({"license": str(result)})
            elif operation == 'observe':
                from cascade.data.observer import DatasetObserver
                obs = DatasetObserver()
                entity = obs.observe_dataset(p.get('data', {}), name=p.get('name'))
                if hasattr(entity, 'to_dict'):
                    return json.dumps(entity.to_dict())
                return json.dumps({"entity": str(entity)})
            else:
                return json.dumps({"error": "Unknown op: " + operation, "ops": ["pii_scan", "schema", "license_check", "observe"]})
        except Exception as e:
            return json.dumps({"error": str(e)})

    @logged_tool()
    def cascade_system(operation: str, params: str = "{}") -> str:
        """Universal log/file ingestion and MoE analysis.

        Operations: ingest_text, ingest_file, analyze, classify

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        """
        import json
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if operation == 'ingest_text':
                from cascade.system.adapter import UniversalAdapter
                adapter = UniversalAdapter()
                events = list(adapter.parse_lines(p.get('text', '').splitlines()))
                results = []
                for evt in events:
                    if hasattr(evt, 'to_dict'):
                        results.append(evt.to_dict())
                    elif hasattr(evt, '__dict__'):
                        results.append(evt.__dict__)
                    else:
                        results.append(str(evt))
                return json.dumps({"events": results, "count": len(results)})
            elif operation == 'ingest_file':
                from cascade.system.universal_extractor import UniversalExtractor
                ext = UniversalExtractor()
                content = ext.extract_file(p.get('file_path', p.get('path', '')))
                if isinstance(content, dict):
                    return json.dumps(content)
                return json.dumps({"content": str(content)[:5000]})
            elif operation == 'analyze':
                from cascade.system.moe_analyzer import MoEAnalyzer
                from cascade.system.adapter import UniversalAdapter
                adapter = UniversalAdapter()
                events = list(adapter.parse_lines(p.get('text', '').splitlines()))
                analyzer = MoEAnalyzer()
                result = analyzer.analyze(events)
                if isinstance(result, dict):
                    return json.dumps(result, default=str)
                elif hasattr(result, 'to_dict'):
                    return json.dumps(result.to_dict(), default=str)
                return json.dumps({"analysis": str(result)})
            elif operation == 'classify':
                from cascade.system.adapter import UniversalAdapter
                adapter = UniversalAdapter()
                events = list(adapter.parse_lines(p.get('text', '').splitlines()))
                formats = set()
                for evt in events:
                    if hasattr(evt, 'event_type'):
                        formats.add(evt.event_type)
                return json.dumps({"detected_formats": list(formats), "event_count": len(events)})
            else:
                return json.dumps({"error": "Unknown op: " + operation, "ops": ["ingest_text", "ingest_file", "analyze", "classify"]})
        except Exception as e:
            return json.dumps({"error": str(e)})

    @logged_tool()
    def cascade_instrument(operation: str, params: str = "{}") -> str:
        """SDK auto-patching for LLM provider telemetry.

        Operations: init_sdk, patch

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        """
        import json
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if operation == 'init_sdk':
                from cascade.sdk import init as _sdk_init
                _sdk_init()
                return json.dumps({"status": "initialized"})
            elif operation == 'patch':
                provider = p.get('provider', 'openai')
                from cascade.sdk import _sdk
                _pfn = None
                if provider == 'openai':
                    from cascade.patches.openai_patch import patch_openai as _pfn
                elif provider == 'anthropic':
                    from cascade.patches.anthropic_patch import patch_anthropic as _pfn
                elif provider == 'huggingface':
                    from cascade.patches.huggingface_patch import patch_huggingface as _pfn
                elif provider == 'ollama':
                    from cascade.patches.ollama_patch import patch_ollama as _pfn
                elif provider == 'litellm':
                    from cascade.patches.litellm_patch import patch_litellm as _pfn
                if _pfn:
                    _pfn(_sdk)
                    return json.dumps({"status": "patched", "provider": provider})
                return json.dumps({"error": "Unknown provider: " + provider, "providers": ["openai", "anthropic", "huggingface", "ollama", "litellm"]})
            else:
                return json.dumps({"error": "Unknown op: " + operation, "ops": ["init_sdk", "patch"]})
        except Exception as e:
            return json.dumps({"error": str(e)})

    @logged_tool()
    def cascade_record(operation: str, params: str = "{}") -> str:
        """Tape recording and Kleene/Interpretive logging.

        Operations: tape_write, tape_read, tape_list, log_kleene, log_interpretive, session_stats

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        """
        import json, time
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if operation == 'tape_write':
                from cascade.viz.tape import write_tape_event, create_tape_path
                if not hasattr(cascade_record, '_tape_path'):
                    cascade_record._tape_path = create_tape_path()
                write_tape_event(cascade_record._tape_path, p.get('data', {}))
                return json.dumps({"status": "recorded", "tape": cascade_record._tape_path})
            elif operation == 'tape_read':
                from cascade.viz.tape import load_tape_file
                if not hasattr(cascade_record, '_tape_path'):
                    return json.dumps({"entries": []})
                entries = load_tape_file(cascade_record._tape_path)
                count = int(p.get('count', 50))
                return json.dumps({"entries": entries[-count:]})
            elif operation == 'tape_list':
                from cascade.viz.tape import list_tape_files
                tapes = list_tape_files()
                return json.dumps({"tapes": tapes})
            elif operation == 'log_kleene':
                from cascade.logging import KleeneLogger, LogLevel
                if not hasattr(cascade_record, '_kleene'):
                    cascade_record._kleene = KleeneLogger(p.get('component', 'mcp'))
                level = getattr(LogLevel, p.get('level', 'INFO'), LogLevel.INFO)
                cascade_record._kleene.log(level, p.get('operation', 'observe'), p.get('data', {}))
                return json.dumps({"status": "logged_kleene"})
            elif operation == 'log_interpretive':
                from cascade.logging import InterpretiveLogger, ImpactLevel
                if not hasattr(cascade_record, '_interp'):
                    cascade_record._interp = InterpretiveLogger(p.get('system', 'cascade'))
                impact = getattr(ImpactLevel, p.get('impact', 'MEDIUM'), ImpactLevel.MEDIUM)
                cascade_record._interp.log(impact, p.get('component', 'mcp'), p.get('event', 'observation'), context=p.get('context', ''), consequence=p.get('consequence', ''))
                return json.dumps({"status": "logged_interpretive"})
            elif operation == 'session_stats':
                from cascade.logging import get_log_manager
                mgr = get_log_manager()
                stats = mgr.get_session_stats()
                if not isinstance(stats, dict):
                    stats = {"raw": str(stats)}
                try:
                    _agent = get_agent()
                    _outer = _agent._brain if hasattr(_agent, '_brain') else getattr(_agent, 'brain', None)
                    _br = getattr(_outer, '_brain', _outer) if _outer is not None else None
                    if _br is not None and hasattr(_br, '_obs_buffer'):
                        stats['obs_buffer_size'] = len(_br._obs_buffer)
                except Exception:
                    pass
                return json.dumps({"stats": stats})
            else:
                return json.dumps({"error": "Unknown op: " + operation, "ops": ["tape_write", "tape_read", "tape_list", "log_kleene", "log_interpretive", "session_stats"]})
        except Exception as e:
            return json.dumps({"error": str(e)})

    @logged_tool()
    def cascade_proxy(operation: str, params: str = "{}") -> str:
        """LLM API proxy for intercepting and observing API calls.

        Operations: start, stop, status

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        """
        import json
        try:
            p = json.loads(params) if isinstance(params, str) else params
            from cascade.proxy import CascadeProxy
            if not hasattr(cascade_proxy, '_proxy'):
                cascade_proxy._proxy = None
            if operation == 'start':
                port = p.get('port', 8081)
                cascade_proxy._proxy = CascadeProxy(port=port)
                cascade_proxy._proxy.start()
                return json.dumps({"status": "started", "port": port})
            elif operation == 'stop':
                if cascade_proxy._proxy:
                    cascade_proxy._proxy.stop()
                    cascade_proxy._proxy = None
                return json.dumps({"status": "stopped"})
            elif operation == 'status':
                if cascade_proxy._proxy and hasattr(cascade_proxy._proxy, 'status'):
                    st = cascade_proxy._proxy.status()
                    if isinstance(st, dict):
                        return json.dumps(st)
                    return json.dumps({"status": str(st)})
                return json.dumps({"running": cascade_proxy._proxy is not None})
            else:
                return json.dumps({"error": "Unknown op: " + operation, "ops": ["start", "stop", "status"]})
        except Exception as e:
            return json.dumps({"error": str(e)})

    # REGISTER TOOLS WITH WORKFLOW ENGINE
    # @logged_tool() functions are local to run_mcp_server(),
    # so WorkflowExecutor's globals() can't find them.
    # Inject them into the executor's tool registry.
    # ═══════════════════════════════════════════════════════════════
    _wf_exec = get_workflow_executor()
    _wf_exec._tool_registry = {name: func for name, func in locals().items() if callable(func) and not name.startswith('_')}

    # Arcade/external bridge: return mcp instance with all tools registered
    if register_only:
        return mcp

    # ── FelixBag auto-persistence (normal mode) ──
    _bag_state_path = Path(__file__).parent / '.bag_state.json'
    if _bag_state_path.exists():
        try:
            _bag_data = json.loads(_bag_state_path.read_text(encoding='utf-8'))
            for _bk, _bv in _bag_data.items():
                if _bk not in _BAG._bag:
                    _BAG._bag[_bk] = _bv
        except Exception:
            pass

    import atexit as _atexit_mod
    def _auto_save_bag():
        try:
            _p = Path(__file__).parent / '.bag_state.json'
            _p.write_text(json.dumps(_BAG._bag, indent=2, default=str), encoding='utf-8')
        except Exception:
            pass
    _atexit_mod.register(_auto_save_bag)

    import threading as _thr_mod
    def _bag_autosave_loop():
        import time as _t
        while True:
            _t.sleep(300)
            _auto_save_bag()
    _thr_mod.Thread(target=_bag_autosave_loop, daemon=True).start()

    # Run the MCP server with appropriate transport
    if host:
        # HTTP transport for remote access (Kiro, external IDEs)
        # NOTE: host/port must be set on FastMCP constructor, not run()
        # Recreate with correct host/port settings
        mcp_http = FastMCP(f"{capsule_name}-quine", instructions=_build_mcp_instructions(), host=host, port=port)
        # Copy all registered tools/resources from original mcp
        mcp_http._tool_manager = mcp._tool_manager
        mcp_http._resource_manager = mcp._resource_manager
        mcp_http._prompt_manager = mcp._prompt_manager
        
        if not quiet:
            print(f"🔌 MCP Server starting on http://{host}:{port}")
            print(f"   SSE endpoint: http://{host}:{port}/sse")
            print(f"   For Kiro/external IDEs, use this URL")
        
        # Suppress uvicorn logging when quiet mode or in TUI
        if quiet:
            import logging
            logging.getLogger('uvicorn').setLevel(logging.CRITICAL)
            logging.getLogger('uvicorn.error').setLevel(logging.CRITICAL)
            logging.getLogger('uvicorn.access').setLevel(logging.CRITICAL)
        
        mcp_http.run(transport="sse")
    else:
        # stdio transport for local tools (VS Code, Claude Desktop)
        mcp.run(transport="stdio")


