        # ═══════════════════════════════════════════════════════════
        
        headless_commands = ('infer', 'demo', 'state', 'slots', 'plug', 'unplug',
                            'status', 'id', 'prov', 'forward', 'weights',
                            'pdf', 'artifacts', 'bag', 'induct', 'restore',
                            'invoke', 'embed', 'generate', 'classify', 'rerank',
                            'deliberate', 'imagine', 'chat', 'batch', 'pipe',
                            'compare', 'rerun')
        
        if cmd in headless_commands:
            # Quick agent load for headless mode
            agent = CapsuleAgent()
            capsule_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
            brain = capsule_brain._brain if hasattr(capsule_brain, '_brain') else capsule_brain
            brain_type = _BRAIN_CONFIG.get('brain_type', 'unknown')
            is_ouroboros = brain_type == 'ouroboros'
            is_council = brain_type == 'council'
            is_scarecrow = brain_type == 'scarecrow'
            is_embedding = brain_type == 'embedding'
            cmd_args = sys.argv[2:]
            
            if cmd in ('infer', 'forward'):
                # Brain-type aware input generation
                if is_ouroboros:
                    # Ouroboros: multi-modal input (text + optional embedding)
                    text = ' '.join(cmd_args) if cmd_args else 'Hello from Ouroboros'
                    obs = {'text': text, 'input': np.random.rand(384).astype(np.float32)}
                elif is_scarecrow or is_embedding:
                    input_dim = getattr(brain, 'input_dim', 384)
                    obs = {'input': np.random.rand(input_dim).astype(np.float32)}
                elif is_council:
                    obs = {'text': 'Hello world', 'input': np.random.rand(384).astype(np.float32)}
                else:
                    obs = {'frame': np.random.rand(84,84,3).astype(np.float32)}
                result = agent.forward(obs)
                # Ouroboros returns different keys
